-- Poems batch 474
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-25','饒州餘幹縣琵琶洲有故韓賓客宣城裴尚書修行…因以和吟','韋莊','唐','御定全唐诗','yuding','','[]','琵琶洲近鬥牛星，鸞鳳曾於此放情。已覺地靈因昴降，',40,'御定全唐詩/json/698.json','["琵琶洲近鬥牛星，鸞鳳曾於此放情。已覺地靈因昴降，", "戟戶盡移天上去，裏人空說舊簪纓。"]'),
('yuding-26','九江逢盧員外','韋莊','唐','御定全唐诗','yuding','','[]','前年風月宿琴堂，大媚仙山近帝鄉。別後幾沾新雨露，',40,'御定全唐詩/json/698.json','["前年風月宿琴堂，大媚仙山近帝鄉。別後幾沾新雨露，", "莫怪相逢倍惆悵，九江煙月似瀟湘。"]'),
('yuding-27','南昌晚眺','韋莊','唐','御定全唐诗','yuding','','[]','南昌城郭枕江煙，章水悠悠浪拍天。芳草綠遮仙尉宅，',40,'御定全唐詩/json/698.json','["南昌城郭枕江煙，章水悠悠浪拍天。芳草綠遮仙尉宅，", "怪得地多章句客，庾家樓在鬥牛邊。"]'),
('yuding-28','衢州江上別李秀才','韋莊','唐','御定全唐诗','yuding','','[]','千山紅樹萬山雲，把酒相看日又曛。',32,'御定全唐詩/json/698.json','["千山紅樹萬山雲，把酒相看日又曛。", "一曲離歌兩行淚，更知何地再逢君。"]'),
('yuding-29','湘中作','韋莊','唐','御定全唐诗','yuding','','[]','千重煙樹萬重波，因便何妨吊汨羅。楚地不知秦地亂，',40,'御定全唐詩/json/698.json','["千重煙樹萬重波，因便何妨吊汨羅。楚地不知秦地亂，", "否去泰來終可待，夜寒休唱飯牛歌。"]'),
('yuding-30','桐廬縣作','韋莊','唐','御定全唐诗','yuding','','[]','錢塘江盡到桐廬，水碧山青畫不如。白羽鳥飛嚴子瀨，',40,'御定全唐詩/json/698.json','["錢塘江盡到桐廬，水碧山青畫不如。白羽鳥飛嚴子瀨，", "此境只應詞客愛，投文空吊木玄虛。"]'),
('yuding-31','東陽贈別','韋莊','唐','御定全唐诗','yuding','','[]','繡袍公子出旌旗，送我搖鞭入翠微。大抵行人難訴酒，',40,'御定全唐詩/json/698.json','["繡袍公子出旌旗，送我搖鞭入翠微。大抵行人難訴酒，", "無限別情言不得，回看溪柳恨依依。"]'),
('yuding-32','寄湖州舍弟','韋莊','唐','御定全唐诗','yuding','','[]','半年江上愴離襟，把得新詩喜又吟。多病似逢秦氏藥，',40,'御定全唐詩/json/698.json','["半年江上愴離襟，把得新詩喜又吟。多病似逢秦氏藥，", "何況別來詞轉麗，不愁明代少知音。"]'),
('yuding-33','信州西三十裏山名仙人城下有月岩山其狀秀拔…賦是詩','韋莊','唐','御定全唐诗','yuding','','[]','驅車過閩越，路出饒陽西。仙山翠如畫，簇簇生虹蜺。',120,'御定全唐詩/json/698.json','["驅車過閩越，路出饒陽西。仙山翠如畫，簇簇生虹蜺。", "群峰若侍從，眾阜如嬰提。岩巒互吞吐，嶺岫相追攜。", "中有月輪滿，皎潔如圓珪。玉皇恣遊覽，到此神應迷。", "常娥曳霞帔，引我同攀躋。騰騰上天半，玉鏡懸飛梯。", "瑤池何悄悄，鸞鶴煙中棲。回頭望塵世，露下寒淒淒。"]'),
('yuding-34','婺州水館重陽日作','韋莊','唐','御定全唐诗','yuding','','[]','異國逢佳節，憑高獨若吟。一杯今日醉，萬里故園心。',48,'御定全唐詩/json/698.json','["異國逢佳節，憑高獨若吟。一杯今日醉，萬里故園心。", "水館紅蘭合，山城紫菊深。白衣雖不至，鷗鳥自相尋。"]'),
('yuding-35','避地越中作','韋莊','唐','御定全唐诗','yuding','','[]','避世移家遠，天涯歲已周。豈知今夜月，還是去年愁。',48,'御定全唐詩/json/698.json','["避世移家遠，天涯歲已周。豈知今夜月，還是去年愁。", "露果珠沈水，風螢燭上樓。傷心潘騎省，華髮不禁秋。"]'),
('yuding-36','撫州江口雨中作','韋莊','唐','御定全唐诗','yuding','','[]','江上閑沖細雨行，滿衣風灑綠荷聲。',32,'御定全唐詩/json/698.json','["江上閑沖細雨行，滿衣風灑綠荷聲。", "金騮掉尾橫鞭望，猶指廬陵半日程。"]'),
('yuding-37','信州溪岸夜吟作','韋莊','唐','御定全唐诗','yuding','','[]','夜倚臨溪店，懷鄉獨苦吟。月當山頂出，星倚水湄沈。',48,'御定全唐詩/json/698.json','["夜倚臨溪店，懷鄉獨苦吟。月當山頂出，星倚水湄沈。", "霧氣漁燈冷，鐘聲穀寺深。一城人悄悄，琪樹宿仙禽。"]'),
('yuding-38','訪潯陽友人不遇','韋莊','唐','御定全唐诗','yuding','','[]','不見安期悔上樓，寂寥人對鷺鷥愁。',32,'御定全唐詩/json/698.json','["不見安期悔上樓，寂寥人對鷺鷥愁。", "蘆花雨急江煙暝，何處潺潺獨棹舟。"]'),
('yuding-39','東林寺再遇僧益大德','韋莊','唐','御定全唐诗','yuding','','[]','見師初事懿皇朝，三殿歸來白馬驕。上講每教傾國聽，',40,'御定全唐詩/json/698.json','["見師初事懿皇朝，三殿歸來白馬驕。上講每教傾國聽，", "若向君門逢舊友，為傳音信到雲霄。"]'),
('yuding-40','西塞山下作','韋莊','唐','御定全唐诗','yuding','','[]','西塞山前水似藍，亂雲如絮滿澄潭。孤峰漸映湓城北，',40,'御定全唐詩/json/698.json','["西塞山前水似藍，亂雲如絮滿澄潭。孤峰漸映湓城北，", "他年卻棹扁舟去，終傍蘆花結一庵。"]'),
('yuding-41','齊安郡','韋莊','唐','御定全唐诗','yuding','','[]','彌棹齊安郡，孤城百戰殘。傍村林有虎，帶郭縣無官。',48,'御定全唐詩/json/698.json','["彌棹齊安郡，孤城百戰殘。傍村林有虎，帶郭縣無官。", "暮角梅花怨，清江桂影寒。黍離緣底事，撩我起長歎。"]'),
('yuding-42','夏口行寄婺州諸弟','韋莊','唐','御定全唐诗','yuding','','[]','回頭煙樹各天涯，婺女星邊遠寄家。盡眼楚波連夢澤，',40,'御定全唐詩/json/698.json','["回頭煙樹各天涯，婺女星邊遠寄家。盡眼楚波連夢澤，", "誰道我隨張博望，悠悠空外泛仙槎。"]'),
('yuding-43','南省伴直','韋莊','唐','御定全唐诗','yuding','','[]','文昌二十四仙曹，盡倚紅簷種露桃。一洞煙霞人跡少，',40,'御定全唐詩/json/698.json','["文昌二十四仙曹，盡倚紅簷種露桃。一洞煙霞人跡少，", "何事愛留詩客宿，滿庭風雨竹蕭騷。"]'),
('yuding-44','鄠杜舊居二首','韋莊','唐','御定全唐诗','yuding','','[]','卻到山陽事事非，穀雲溪鳥尚相依。阮咸貧去田園盡，',80,'御定全唐詩/json/698.json','["卻到山陽事事非，穀雲溪鳥尚相依。阮咸貧去田園盡，", "年年為獻東堂策，長是蘆花別釣磯。", "一徑尋村渡碧溪，稻花香澤水千畦。雲中寺遠磬難識，", "歸來滿把如澠酒，何用傷時歎鳳兮。"]'),
('yuding-45','寄江南諸弟','韋莊','唐','御定全唐诗','yuding','','[]','萬里逢歸雁，鄉書忍淚封。吾身不自保，爾道各何從。',48,'御定全唐詩/json/698.json','["萬里逢歸雁，鄉書忍淚封。吾身不自保，爾道各何從。", "性拙唯多蹇，家貧半為慵。只思溪影上，臥看玉華峰。"]'),
('yuding-46','投寄舊知','韋莊','唐','御定全唐诗','yuding','','[]','卻將憔悴入都門，自喜青霄足故人。萬里有家留百越，',40,'御定全唐詩/json/698.json','["卻將憔悴入都門，自喜青霄足故人。萬里有家留百越，", "多謝青雲好知己，莫教歸去重沾巾。"]'),
('yuding-47','癸醜年下第獻新先輩','韋莊','唐','御定全唐诗','yuding','','[]','五更殘月省牆邊，絳旆蜺旌卓曉煙。千炬火中鶯出穀，',48,'御定全唐詩/json/698.json','["五更殘月省牆邊，絳旆蜺旌卓曉煙。千炬火中鶯出穀，", "對酒暫時情豁爾，見花依舊涕潸然。未酬闞澤傭書債，"]'),
('yuding-48','題汧陽縣馬跑泉李學士別業','韋莊','唐','御定全唐诗','yuding','','[]','水滿寒塘菊滿籬，籬邊無限彩禽飛。西園夜雨紅櫻熟，',40,'御定全唐詩/json/698.json','["水滿寒塘菊滿籬，籬邊無限彩禽飛。西園夜雨紅櫻熟，", "九霄岐路忙於火，肯戀斜陽守釣磯。"]'),
('yuding-49','絳州過夏留獻鄭尚書','韋莊','唐','御定全唐诗','yuding','','[]','朝朝沈醉引金船，不覺西風滿樹蟬。光景暗消銀燭下，',40,'御定全唐詩/json/698.json','["朝朝沈醉引金船，不覺西風滿樹蟬。光景暗消銀燭下，", "明月客腸何處斷，綠槐風裏獨揚鞭。"]'),
('yuding-50','綏州作','韋莊','唐','御定全唐诗','yuding','','[]','雕陰無樹水難流，雉堞連雲古帝州。帶雨晚駝鳴遠戍，',40,'御定全唐詩/json/698.json','["雕陰無樹水難流，雉堞連雲古帝州。帶雨晚駝鳴遠戍，", "一曲單于暮烽起，扶蘇城上月如鉤。"]'),
('yuding-0','與東吳生相遇','韋莊','唐','御定全唐诗','yuding','','[]','十年身事各如萍，白首相逢淚滿纓。老去不知花有態，',40,'御定全唐詩/json/699.json','["十年身事各如萍，白首相逢淚滿纓。老去不知花有態，", "且對一尊開口笑，未衰應見泰階平。"]'),
('yuding-1','庭前桃','韋莊','唐','御定全唐诗','yuding','','[]','曾向桃源爛漫遊，也同漁父泛仙舟。皆言洞裏千株好，',40,'御定全唐詩/json/699.json','["曾向桃源爛漫遊，也同漁父泛仙舟。皆言洞裏千株好，", "五陵公子饒春恨，莫引香風上酒樓。"]'),
('yuding-2','丙辰年鄜州遇寒食城外醉吟五首','韋莊','唐','御定全唐诗','yuding','','[]','滿街楊柳綠絲煙，畫出清明二月天。',160,'御定全唐詩/json/699.json','["滿街楊柳綠絲煙，畫出清明二月天。", "好是隔簾花樹動，女郎撩亂送秋千。", "雕陰寒食足遊人，金鳳羅衣濕麝熏。", "腸斷入城芳草路，淡紅香白一群群。", "開元坡下日初斜，拜掃歸來走鈿車。", "可惜數株紅豔好，不知今夜落誰家。", "馬驕風疾玉鞭長，過去唯留一陣香。", "閑客不須燒破眼，好花皆屬富家郎。", "雨絲煙柳欲清明，金屋人閑暖鳳笙。", "永日迢迢無一事，隔街聞築氣球聲。"]'),
('yuding-3','宜君縣比卜居不遂，留題王秀才別墅二首','韋莊','唐','御定全唐诗','yuding','','[]','本期同此臥林丘，榾柮爐前擁布裘。',64,'御定全唐詩/json/699.json','["本期同此臥林丘，榾柮爐前擁布裘。", "何事卻騎羸馬去，白雲紅樹不相留。", "明月嚴霜撲皂貂，羨君高臥正逍遙。", "門前積雪深三尺，火滿紅爐酒滿瓢。"]'),
('yuding-4','鄜州留別張員外','韋莊','唐','御定全唐诗','yuding','','[]','江南相送君山下，塞北相逢朔漠中。三楚故人皆是夢，',40,'御定全唐詩/json/699.json','["江南相送君山下，塞北相逢朔漠中。三楚故人皆是夢，", "惆悵卻愁明日別，馬嘶山店雨濛濛。"]'),
('yuding-5','病中聞相府夜宴戲贈集賢盧學士','韋莊','唐','御定全唐诗','yuding','','[]','滿筵紅蠟照香鈿，一夜歌鐘欲沸天。花裏亂飛金錯落，',40,'御定全唐詩/json/699.json','["滿筵紅蠟照香鈿，一夜歌鐘欲沸天。花裏亂飛金錯落，", "無那兩三新進士，風流長得飲徒憐。"]'),
('yuding-6','出關','韋莊','唐','御定全唐诗','yuding','','[]','馬嘶煙岸柳陰斜，東去關山路轉賒。到處因循緣嗜酒，',40,'御定全唐詩/json/699.json','["馬嘶煙岸柳陰斜，東去關山路轉賒。到處因循緣嗜酒，", "正是灞陵春酬綠，仲宣何事獨辭家。"]'),
('yuding-7','過樊川舊居','韋莊','唐','御定全唐诗','yuding','','[]','卻到樊川訪舊遊，夕陽衰草杜陵秋。應劉去後苔生閣，',40,'御定全唐詩/json/699.json','["卻到樊川訪舊遊，夕陽衰草杜陵秋。應劉去後苔生閣，", "千桑萬海無人見，橫笛一聲空淚流。"]'),
('yuding-8','長安舊裏','韋莊','唐','御定全唐诗','yuding','','[]','滿目牆匡春草深，傷時傷事更傷心。',32,'御定全唐詩/json/699.json','["滿目牆匡春草深，傷時傷事更傷心。", "車輪馬跡今何在，十二玉樓無處尋。"]'),
('yuding-9','過渼陂懷舊','韋莊','唐','御定全唐诗','yuding','','[]','辛勤曾寄玉峰前，一別雲溪二十年。三徑荒涼迷竹樹，',40,'御定全唐詩/json/699.json','["辛勤曾寄玉峰前，一別雲溪二十年。三徑荒涼迷竹樹，", "多少亂離無處問，夕陽吟罷涕潸然。"]'),
('yuding-10','汧陽間','韋莊','唐','御定全唐诗','yuding','','[]','汧水悠悠去似絣，遠山如畫翠眉橫。僧尋野渡歸吳嶽，',40,'御定全唐詩/json/699.json','["汧水悠悠去似絣，遠山如畫翠眉橫。僧尋野渡歸吳嶽，", "牧童何處吹羌笛，一曲梅花出塞聲。"]'),
('yuding-11','焦崖閣','韋莊','唐','御定全唐诗','yuding','','[]','李白曾歌蜀道難，長聞白日上青天。',32,'御定全唐詩/json/699.json','["李白曾歌蜀道難，長聞白日上青天。", "今朝夜過焦崖閣，始信星河在馬前。"]'),
('yuding-12','雞公幘','韋莊','唐','御定全唐诗','yuding','','[]','石狀雖如幘，山形可類雞。向風疑欲鬥，帶雨似聞啼。',48,'御定全唐詩/json/699.json','["石狀雖如幘，山形可類雞。向風疑欲鬥，帶雨似聞啼。", "蔓織青籠合，松長翠羽低。不鳴非有意，為怕客奔齊。"]'),
('yuding-0','平陵老將','韋莊','唐','御定全唐诗','yuding','','[]','白羽金僕姑，腰懸雙轆轤。前年蔥嶺北，獨戰雲中胡。',48,'御定全唐詩/json/700.json','["白羽金僕姑，腰懸雙轆轤。前年蔥嶺北，獨戰雲中胡。", "匹馬塞垣老，一身如鳥孤。歸來辭第宅，卻占平陵居。"]'),
('yuding-1','即事','韋莊','唐','御定全唐诗','yuding','','[]','亂世時偏促，陰天日易昏。無言搔白首，憔悴倚東門。',24,'御定全唐詩/json/700.json','["亂世時偏促，陰天日易昏。無言搔白首，憔悴倚東門。"]'),
('yuding-2','姬人養蠶','韋莊','唐','御定全唐诗','yuding','','[]','昔年愛笑蠶家婦，今日辛勤自養蠶。',32,'御定全唐詩/json/700.json','["昔年愛笑蠶家婦，今日辛勤自養蠶。", "仍道不愁羅與綺，女郎初解織桑籃。"]'),
('yuding-3','長幹塘別徐茂才','韋莊','唐','御定全唐诗','yuding','','[]','亂離時節別離輕，別酒應須滿滿傾。',32,'御定全唐詩/json/700.json','["亂離時節別離輕，別酒應須滿滿傾。", "才喜相逢又相送，有情爭得似無情。"]'),
('yuding-4','勉兒子','韋莊','唐','御定全唐诗','yuding','','[]','養爾逢多難，常憂學已遲。辟疆為上相，何必待從師。',24,'御定全唐詩/json/700.json','["養爾逢多難，常憂學已遲。辟疆為上相，何必待從師。"]'),
('yuding-5','乞彩箋歌','韋莊','唐','御定全唐诗','yuding','','[]','浣花溪上如花客，綠闇紅藏人不識。留得溪頭瑟瑟波，',96,'御定全唐詩/json/700.json','["浣花溪上如花客，綠闇紅藏人不識。留得溪頭瑟瑟波，", "不使紅霓段段飛，一時驅上丹霞壁。蜀客才多染不供，", "我有歌詩一千首，磨礱山嶽羅星斗。開卷長疑雷電驚，", "人間無處買煙霞，須知得自神仙手。也知價重連城璧，"]'),
('yuding-6','白牡丹','韋莊','唐','御定全唐诗','yuding','','[]','閨中莫妒新妝婦，陌上須慚傅粉郎。',32,'御定全唐詩/json/700.json','["閨中莫妒新妝婦，陌上須慚傅粉郎。", "昨夜月明渾似水，入門唯覺一庭香。"]'),
('yuding-7','憫耕者','韋莊','唐','御定全唐诗','yuding','','[]','何代何王不戰爭，盡從離亂見清平。',32,'御定全唐詩/json/700.json','["何代何王不戰爭，盡從離亂見清平。", "如今暴骨多於土，猶點鄉兵作戍兵。"]'),
('yuding-8','壺關道中作','韋莊','唐','御定全唐诗','yuding','','[]','處處兵戈路不通，卻從山北去江東。',32,'御定全唐詩/json/700.json','["處處兵戈路不通，卻從山北去江東。", "黃昏欲到壺關寨，匹馬寒嘶野草中。"]'),
('yuding-9','題酒家','韋莊','唐','御定全唐诗','yuding','','[]','酒綠花紅客愛詩，落花春岸酒家旗。',32,'御定全唐詩/json/700.json','["酒綠花紅客愛詩，落花春岸酒家旗。", "尋思避世為逋客，不醉長醒也是癡。"]'),
('yuding-10','寄舍弟','韋莊','唐','御定全唐诗','yuding','','[]','每吟富貴他人合，不覺汍瀾又濕衣。',32,'御定全唐詩/json/700.json','["每吟富貴他人合，不覺汍瀾又濕衣。", "萬里日邊鄉樹遠，何年何路得同歸。"]'),
('yuding-11','僕者楊金','韋莊','唐','御定全唐诗','yuding','','[]','半年辛苦葺荒居，不獨單寒腹亦虛。',32,'御定全唐詩/json/700.json','["半年辛苦葺荒居，不獨單寒腹亦虛。", "努力且為田舍客，他年為爾覓金魚。"]'),
('yuding-12','春陌二首','韋莊','唐','御定全唐诗','yuding','','[]','滿街芳草卓香車，仙子門前白日斜。',64,'御定全唐詩/json/700.json','["滿街芳草卓香車，仙子門前白日斜。", "腸斷東風各回首，一枝春雪凍梅花。", "嫩煙輕染柳絲黃，句引花枝笑憑牆。", "馬上王孫莫回首，好風偏逐羽林郎。"]'),
('yuding-13','贈姬人','韋莊','唐','御定全唐诗','yuding','','[]','莫恨紅裙破，休嫌白屋低。請看京與洛，誰在舊香閨。',24,'御定全唐詩/json/700.json','["莫恨紅裙破，休嫌白屋低。請看京與洛，誰在舊香閨。"]'),
('yuding-14','中酒','韋莊','唐','御定全唐诗','yuding','','[]','南鄰酒熟愛相招，蘸甲傾來綠滿瓢。',32,'御定全唐詩/json/700.json','["南鄰酒熟愛相招，蘸甲傾來綠滿瓢。", "一醉不知三日事，任他童稚作漁樵。"]'),
('yuding-15','暴雨','韋莊','唐','御定全唐诗','yuding','','[]','江村入夏多雷雨，曉作狂霖晚又晴。',32,'御定全唐詩/json/700.json','["江村入夏多雷雨，曉作狂霖晚又晴。", "波浪不知深幾許，南湖今與北湖平。"]'),
('yuding-16','悼亡姬','韋莊','唐','御定全唐诗','yuding','','[]','鳳去鸞歸不可尋，十洲仙路彩雲深。若無少女花應老，',40,'御定全唐詩/json/700.json','["鳳去鸞歸不可尋，十洲仙路彩雲深。若無少女花應老，", "湘江水闊蒼梧遠，何處相思弄舜琴。"]'),
('yuding-17','獨吟','韋莊','唐','御定全唐诗','yuding','','[]','默默無言惻惻悲，閑吟獨傍菊花籬。只今已作經年別，',40,'御定全唐詩/json/700.json','["默默無言惻惻悲，閑吟獨傍菊花籬。只今已作經年別，", "夜來孤枕空腸斷，窗月斜輝夢覺時。"]'),
('yuding-18','悔恨','韋莊','唐','御定全唐诗','yuding','','[]','六七年來春又秋，也同歡笑也同愁。才聞及第心先喜，',40,'御定全唐詩/json/700.json','["六七年來春又秋，也同歡笑也同愁。才聞及第心先喜，", "如今悔恨將何益，腸斷千休與萬休。"]'),
('yuding-19','虛席','韋莊','唐','御定全唐诗','yuding','','[]','一閉香閨後，羅衣盡施僧。鼠偷筵上果，蛾撲帳前燈。',48,'御定全唐詩/json/700.json','["一閉香閨後，羅衣盡施僧。鼠偷筵上果，蛾撲帳前燈。", "土蝕釵無鳳，塵生鏡少菱。有時還影響，花葉曳香繒。"]'),
('yuding-20','舊居','韋莊','唐','御定全唐诗','yuding','','[]','芳草又芳草，故人楊子家。青雲容易散，白日等閒斜。',48,'御定全唐詩/json/700.json','["芳草又芳草，故人楊子家。青雲容易散，白日等閒斜。", "皓質留殘雪，香魂逐斷霞。不知何處笛，一夜叫梅花。"]'),
('yuding-21','晏起','韋莊','唐','御定全唐诗','yuding','','[]','爾來中酒起常遲，臥看南山改舊詩。',32,'御定全唐詩/json/700.json','["爾來中酒起常遲，臥看南山改舊詩。", "開戶日高春寂寂，數聲啼鳥上花枝。"]'),
('yuding-22','幽居春思','韋莊','唐','御定全唐诗','yuding','','[]','綠映紅藏江上村，一聲雞犬似山源。',32,'御定全唐詩/json/700.json','["綠映紅藏江上村，一聲雞犬似山源。", "閉門盡日無人到，翠羽春禽滿樹喧。"]'),
('yuding-23','思歸引','韋莊','唐','御定全唐诗','yuding','','[]','越鳥南翔雁北飛，兩鄉雲路各言歸。',32,'御定全唐詩/json/700.json','["越鳥南翔雁北飛，兩鄉雲路各言歸。", "如何我是飄飄者，獨向江頭戀釣磯。"]'),
('yuding-24','與小女','韋莊','唐','御定全唐诗','yuding','','[]','見人初解語嘔啞，不肯歸眠戀小車。',32,'御定全唐詩/json/700.json','["見人初解語嘔啞，不肯歸眠戀小車。", "一夜嬌啼緣底事，為嫌衣少縷金華。"]'),
('yuding-25','虎跡','韋莊','唐','御定全唐诗','yuding','','[]','白額頻頻夜到門，水邊蹤跡漸成群。',32,'御定全唐詩/json/700.json','["白額頻頻夜到門，水邊蹤跡漸成群。", "我今避世棲岩穴，岩穴如何又見君。"]'),
('yuding-26','買酒不得','韋莊','唐','御定全唐诗','yuding','','[]','停尊待爾怪來遲，手挈空瓶毷氉歸。',32,'御定全唐詩/json/700.json','["停尊待爾怪來遲，手挈空瓶毷氉歸。", "滿面春愁消不得，更看溪鷺寂寥飛。"]'),
('yuding-27','得故人書','韋莊','唐','御定全唐诗','yuding','','[]','正向溪頭自采蘇，青雲忽得故人書。',32,'御定全唐詩/json/700.json','["正向溪頭自采蘇，青雲忽得故人書。", "殷勤問我歸來否，雙闕而今畫不如。"]'),
('yuding-28','洪州送僧游福建','韋莊','唐','御定全唐诗','yuding','','[]','八月風波似鼓鼙，可堪波上各東西。',32,'御定全唐詩/json/700.json','["八月風波似鼓鼙，可堪波上各東西。", "殷勤早作歸來計，莫戀猿聲住建溪。"]'),
('yuding-29','聞回戈軍','韋莊','唐','御定全唐诗','yuding','','[]','上將鏖兵又欲旋，翠華巡幸已三年。',32,'御定全唐詩/json/700.json','["上將鏖兵又欲旋，翠華巡幸已三年。", "營中不用栽楊柳，願戴儒冠為控弦。"]'),
('yuding-30','南鄰公子','韋莊','唐','御定全唐诗','yuding','','[]','南鄰公子夜歸聲，數炬銀燈隔竹明。',32,'御定全唐詩/json/700.json','["南鄰公子夜歸聲，數炬銀燈隔竹明。", "醉憑馬鬃扶不起，更邀紅袖出門迎。"]'),
('yuding-31','憶小女銀娘','韋莊','唐','御定全唐诗','yuding','','[]','睦州江上水門西，蕩槳揚帆各解攜。',32,'御定全唐詩/json/700.json','["睦州江上水門西，蕩槳揚帆各解攜。", "今日天涯夜深坐，斷腸偏憶阿銀犁。"]'),
('yuding-32','女僕阿汪','韋莊','唐','御定全唐诗','yuding','','[]','念爾辛勤歲已深，亂離相失又相尋。',32,'御定全唐詩/json/700.json','["念爾辛勤歲已深，亂離相失又相尋。", "他年待我門如市，報爾千金與萬金。"]'),
('yuding-33','河清縣河亭','韋莊','唐','御定全唐诗','yuding','','[]','由來多感莫憑高，竟日衷腸似有刀。',32,'御定全唐詩/json/700.json','["由來多感莫憑高，竟日衷腸似有刀。", "人事任成陵與谷，大河東去自滔滔。"]'),
('yuding-34','鐘陵夜闌作','韋莊','唐','御定全唐诗','yuding','','[]','鐘陵風雪夜將深，坐對寒江獨苦吟。',32,'御定全唐詩/json/700.json','["鐘陵風雪夜將深，坐對寒江獨苦吟。", "流落天涯誰見問，少卿應識子卿心。"]'),
('yuding-35','悼楊氏妓琴弦','韋莊','唐','御定全唐诗','yuding','','[]','魂歸寥廓魄歸煙，只住人間十八年。',32,'御定全唐詩/json/700.json','["魂歸寥廓魄歸煙，只住人間十八年。", "昨日施僧裙帶上，斷腸猶系琵琶弦。"]'),
('yuding-36','殘花','韋莊','唐','御定全唐诗','yuding','','[]','江頭沈醉泥斜暉，卻向花前慟哭歸。',32,'御定全唐詩/json/700.json','["江頭沈醉泥斜暉，卻向花前慟哭歸。", "惆悵一年春又去，碧雲芳草兩依依。"]'),
('yuding-37','歲晏同左生作','韋莊','唐','御定全唐诗','yuding','','[]','歲暮鄉關遠，天涯手重攜。雪埋江樹短，雲壓夜城低。',48,'御定全唐詩/json/700.json','["歲暮鄉關遠，天涯手重攜。雪埋江樹短，雲壓夜城低。", "寶瑟湘靈怨，清砧杜魄啼。不須臨皎鏡，年長易淒淒。"]'),
('yuding-38','咸陽懷古','韋莊','唐','御定全唐诗','yuding','','[]','城邊人倚夕陽樓，城上雲凝萬古愁。山色不知秦苑廢，',40,'御定全唐詩/json/700.json','["城邊人倚夕陽樓，城上雲凝萬古愁。山色不知秦苑廢，", "莫怪楚吟偏斷骨，野煙蹤跡似東周。"]'),
('yuding-39','和同年韋學士華下途中見寄','韋莊','唐','御定全唐诗','yuding','','[]','綠楊城郭雨淒淒，過盡千輪與萬蹄。送我獨游三蜀路，',40,'御定全唐詩/json/700.json','["綠楊城郭雨淒淒，過盡千輪與萬蹄。送我獨游三蜀路，", "正是清和好時節，不堪離恨劍門西。"]'),
('yuding-40','春愁','韋莊','唐','御定全唐诗','yuding','','[]','自有春愁正斷魂，不堪芳草思王孫。',32,'御定全唐詩/json/700.json','["自有春愁正斷魂，不堪芳草思王孫。", "落花寂寂黃昏雨，深院無人獨倚門。"]'),
('yuding-41','傷灼灼','韋莊','唐','御定全唐诗','yuding','','[]','嘗聞灼灼麗於花，雲髻盤時未破瓜。桃臉曼長橫綠水，',40,'御定全唐詩/json/700.json','["嘗聞灼灼麗於花，雲髻盤時未破瓜。桃臉曼長橫綠水，", "流落錦江無處問，斷魂飛作碧天霞。"]'),
('yuding-42','漢州','韋莊','唐','御定全唐诗','yuding','','[]','比儂初到漢州城，郭邑樓臺觸目驚。松桂影中旌旆色，',40,'御定全唐詩/json/700.json','["比儂初到漢州城，郭邑樓臺觸目驚。松桂影中旌旆色，", "十日醉眠金雁驛，臨岐無恨臉波橫。"]'),
('yuding-43','長安清明','韋莊','唐','御定全唐诗','yuding','','[]','蚤是傷春夢雨天，可堪芳草更芊芊。內官初賜清明火，',40,'御定全唐詩/json/700.json','["蚤是傷春夢雨天，可堪芳草更芊芊。內官初賜清明火，", "遊人記得承平事，暗喜風光似昔年。"]'),
('yuding-44','秋霽晚景','韋莊','唐','御定全唐诗','yuding','','[]','秋霽禁城晚，六街煙雨殘。牆頭山色健，林外鳥聲歡。',48,'御定全唐詩/json/700.json','["秋霽禁城晚，六街煙雨殘。牆頭山色健，林外鳥聲歡。", "翹日樓臺麗，清風劍佩寒。玉人襟袖薄，斜憑翠闌幹。"]'),
('yuding-45','和人春暮書事寄崔秀才','韋莊','唐','御定全唐诗','yuding','','[]','半掩朱門白日長，晚風輕墮落梅妝。不知芳草情何限，',40,'御定全唐詩/json/700.json','["半掩朱門白日長，晚風輕墮落梅妝。不知芳草情何限，", "相逢只賴如澠酒，一曲狂歌入醉鄉。"]'),
('yuding-46','古離別','韋莊','唐','御定全唐诗','yuding','','[]','一生風月供惆悵，到處煙花恨別離。',32,'御定全唐詩/json/700.json','["一生風月供惆悵，到處煙花恨別離。", "止竟多情何處好，少年長抱少年悲。"]'),
('yuding-47','邊上逢薛秀才話舊','韋莊','唐','御定全唐诗','yuding','','[]','前年同醉武陵亭，絕倒閑譚坐到明。也有絳唇歌白雪，',40,'御定全唐詩/json/700.json','["前年同醉武陵亭，絕倒閑譚坐到明。也有絳唇歌白雪，", "今日皤然對芳草，不勝東望涕交橫。"]'),
('yuding-48','飲散呈主人','韋莊','唐','御定全唐诗','yuding','','[]','夢覺笙歌散，空堂寂寞秋。更聞城角弄，煙雨不勝愁。',24,'御定全唐詩/json/700.json','["夢覺笙歌散，空堂寂寞秋。更聞城角弄，煙雨不勝愁。"]'),
('yuding-49','使院黃葵花','韋莊','唐','御定全唐诗','yuding','','[]','薄妝新著淡黃衣，對捧金爐侍醮遲。向月似矜傾國貌，',40,'御定全唐詩/json/700.json','["薄妝新著淡黃衣，對捧金爐侍醮遲。向月似矜傾國貌，", "為報同人看來好，不禁秋露即離披。"]'),
('yuding-50','搖落','韋莊','唐','御定全唐诗','yuding','','[]','搖落秋天酒易醒，淒淒長似別離情。',32,'御定全唐詩/json/700.json','["搖落秋天酒易醒，淒淒長似別離情。", "黃昏倚柱不歸去，腸斷綠荷風雨聲。"]'),
('yuding-51','奉和觀察郎中春暮憶花言懷見寄四韻之什','韋莊','唐','御定全唐诗','yuding','','[]','天畔峨嵋簇簇青，楚雲何處隔重扃。落花帶雪埋芳草，',40,'御定全唐詩/json/700.json','["天畔峨嵋簇簇青，楚雲何處隔重扃。落花帶雪埋芳草，", "惟君信我多惆悵，只願陶陶不願醒。"]'),
('yuding-52','奉和左司郎中春物暗度感而成章','韋莊','唐','御定全唐诗','yuding','','[]','才喜新春已暮春，夕陽吟殺倚樓人。錦江風散霏霏雨，',40,'御定全唐詩/json/700.json','["才喜新春已暮春，夕陽吟殺倚樓人。錦江風散霏霏雨，", "有時自患多情病，莫是生前宋玉身。"]'),
('yuding-53','少年行','韋莊','唐','御定全唐诗','yuding','','[]','五陵豪客多，買酒黃金盞。醉下酒家樓，美人雙翠幰。',48,'御定全唐詩/json/700.json','["五陵豪客多，買酒黃金盞。醉下酒家樓，美人雙翠幰。", "揮劍邯鄲市，走馬梁王苑。樂事殊未央，年華已雲晚。"]'),
('yuding-54','令狐亭','韋莊','唐','御定全唐诗','yuding','','[]','若非天上神仙宅，須是人間將相家。',32,'御定全唐詩/json/700.json','["若非天上神仙宅，須是人間將相家。", "想得當時好煙月，管弦吹殺後庭花。"]'),
('yuding-55','閨月','韋莊','唐','御定全唐诗','yuding','','[]','明月照前除，煙華蕙蘭濕。清風行處來，白露寒蟬急。',48,'御定全唐詩/json/700.json','["明月照前除，煙華蕙蘭濕。清風行處來，白露寒蟬急。", "美人情易傷，暗上紅樓立。欲言無處言，但向姮娥泣。"]'),
('yuding-56','閨怨','韋莊','唐','御定全唐诗','yuding','','[]','戚戚彼何人，明眸利於月。啼妝曉不幹，素面凝香雪。',48,'御定全唐詩/json/700.json','["戚戚彼何人，明眸利於月。啼妝曉不幹，素面凝香雪。", "良人去淄右，鏡破金簪折。空藏蘭蕙心，不忍琴中說。"]'),
('yuding-57','上春詞','韋莊','唐','御定全唐诗','yuding','','[]','曈曨赫日東方來，禁城煙暖蒸青苔。金樓美人花屏開，',48,'御定全唐詩/json/700.json','["曈曨赫日東方來，禁城煙暖蒸青苔。金樓美人花屏開，", "五陵年少惜花落，酒濃歌極翻如哀。四時輪環終又始，"]'),
('yuding-58','搗練篇','韋莊','唐','御定全唐诗','yuding','','[]','月華吐豔明燭燭，青樓婦唱擣衣曲。白袷絲光織魚目，',40,'御定全唐詩/json/700.json','["月華吐豔明燭燭，青樓婦唱擣衣曲。白袷絲光織魚目，", "樓蘭欲寄在何鄉，憑人與系征鴻足。"]'),
('yuding-59','雜體聯錦','韋莊','唐','御定全唐诗','yuding','','[]','攜手重攜手，夾江金線柳。江上柳能長，行人戀尊酒。',204,'御定全唐詩/json/700.json','["攜手重攜手，夾江金線柳。江上柳能長，行人戀尊酒。", "尊酒意何深，為郎歌玉簪。玉簪聲斷續，鈿軸鳴雙轂。", "雙轂去何方，隔江春樹綠。樹綠酒旗高，淚痕沾繡袍。", "袍縫紫鵝濕，重持金錯刀。錯刀何燦爛，使我腸千斷。", "腸斷欲何言，簾動真珠繁。真珠綴秋露，秋露沾金盤。", "金盤湛瓊液，仙子無歸跡。無跡又無言，海煙空寂寂。", "寂寂古城道，馬嘶芳岸草。岸草接長堤，長堤人解攜。", "解攜忽已久，緬邈空回首。回首隔天河，恨唱蓮塘歌。", "蓮塘在何許，日暮西山雨。"]'),
('yuding-60','長安春','韋莊','唐','御定全唐诗','yuding','','[]','長安二月多香塵，六街車馬聲轔轔。家家樓上如花人，',48,'御定全唐詩/json/700.json','["長安二月多香塵，六街車馬聲轔轔。家家樓上如花人，", "長安春色本無主，古來盡屬紅樓女。如今無奈杏園人，"]'),
('yuding-61','撫盈歌','韋莊','唐','御定全唐诗','yuding','','[]','鳳縠兮鴛綃，霞疏兮綺寮。玉庭兮春晝，金屋兮秋宵。',85,'御定全唐詩/json/700.json','["鳳縠兮鴛綃，霞疏兮綺寮。玉庭兮春晝，金屋兮秋宵。", "愁瞳兮月皎，笑頰兮花嬌。羅輕兮濃麝，室暖兮香椒。", "鑾輿去兮蕭屑，七絲斷兮泬寥，主父臥兮漳水，", "翠華長逝兮莫追，晏相望門兮空悲。"]'),
('yuding-62','贈峨嵋山彈琴李處士','韋莊','唐','御定全唐诗','yuding','','[]','峨嵋山下能琴客，似醉似狂人不測。何須見我眼偏青，',144,'御定全唐詩/json/700.json','["峨嵋山下能琴客，似醉似狂人不測。何須見我眼偏青，", "壺中醉臥日月明，世上長遊天地窄。晉朝叔夜舊相知，", "名卿名相盡知音，遇酒遇琴無間隔。如今世亂獨翛然，", "霓旌絳旆忽相尋，為我尊前橫綠綺。一彈猛雨隨手來，", "吟蜂繞樹去不來，別鶴引雛飛又止。錦麟不動惟側頭，", "子期子野俱不見，烏啼鬼哭空傷悲。坐中詞客悄無語，"]'),
('yuding-63','江皋贈別','韋莊','唐','御定全唐诗','yuding','','[]','金管多情恨解攜，一聲歌罷客如泥。江亭系馬綠楊短，',24,'御定全唐詩/json/700.json','["金管多情恨解攜，一聲歌罷客如泥。江亭系馬綠楊短，"]'),
('yuding-64','南陽小將張彥硤口鎮稅人場射虎歌','韋莊','唐','御定全唐诗','yuding','','[]','海內昔年狎太平，橫目穰穰何崢嶸。天生天殺豈天怒，',88,'御定全唐詩/json/700.json','["海內昔年狎太平，橫目穰穰何崢嶸。天生天殺豈天怒，", "張彥雄特製殘暴，見之叱起如叱羊。鳴弦霹靂越幽阻，", "老饕已斃眾雛恐，童稚揶揄皆自勇。忠良效順勢亦然，", "試征張彥作將軍，幾個將軍願策勳？"]'),
('yuding-65','下邽感舊','韋莊','唐','御定全唐诗','yuding','','[]','昔為童稚不知愁，竹馬閑乘繞縣遊。曾為看花偷出郭，',40,'御定全唐詩/json/700.json','["昔為童稚不知愁，竹馬閑乘繞縣遊。曾為看花偷出郭，", "今日故人何處問，夕陽衰草盡荒丘。"]'),
('yuding-66','塗次逢李氏兄弟感舊','韋莊','唐','御定全唐诗','yuding','','[]','禦溝西面朱門宅，記得當時好弟兄。曉傍柳陰騎竹馬，',40,'御定全唐詩/json/700.json','["禦溝西面朱門宅，記得當時好弟兄。曉傍柳陰騎竹馬，", "今日相逢俱老大，憂家憂國盡公卿。"]'),
('yuding-67','龍潭','韋莊','唐','御定全唐诗','yuding','','[]','激石懸流雪滿灣，九龍潛處野雲閑。欲行甘雨四天下，',40,'御定全唐詩/json/700.json','["激石懸流雪滿灣，九龍潛處野雲閑。欲行甘雨四天下，", "垂髯儻遇穆王駕，閬苑周流應未還。"]'),
('yuding-68','江上別李秀才','韋莊','唐','御定全唐诗','yuding','','[]','前年相送灞陵春，今日天涯各避秦。',32,'御定全唐詩/json/700.json','["前年相送灞陵春，今日天涯各避秦。", "莫向尊前惜沈醉，與君俱是異鄉人。"]'),
('yuding-69','句','韋莊','唐','御定全唐诗','yuding','','[]','印將金鎖鎖，簾用玉鉤鉤。（《北夢瑣言》雲：',94,'御定全唐詩/json/700.json','["印將金鎖鎖，簾用玉鉤鉤。（《北夢瑣言》雲：", "杜荀鶴嘗吟一聯詩雲：舊衣灰絮絮，新酒竹篘篘。", "或話于莊，莊擬之云云。即大拜之祥也）", "不隨妖豔開，獨媚玄冥節。", "豈是為窮常見隔，只應嫌酒不相過。（贈貫休，"]'),
('yuding-0','擬塞外征行','王貞白','唐','御定全唐诗','yuding','','[]','寇騎滿雞田，都護欲臨邊。青泥方絕漠，懷劍始辭燕。',120,'御定全唐詩/json/701.json','["寇騎滿雞田，都護欲臨邊。青泥方絕漠，懷劍始辭燕。", "旌旗掛龍虎，壯士募鷹鸇。長城威十萬，高嶺奮三千。", "行行向馬邑，去去指祁連。鼓聲遙赤塞，兵氣遠沖天。", "對陣雲初上，臨城月始懸。風驚烽易滅，沙暗馬難前。", "恩重恒思報，勞心屢損年。微功一可立，身輕不自憐。"]'),
('yuding-1','蘆葦','王貞白','唐','御定全唐诗','yuding','','[]','高士想江湖，湖閒庭植蘆。清風時有至，綠竹興何殊。',120,'御定全唐詩/json/701.json','["高士想江湖，湖閒庭植蘆。清風時有至，綠竹興何殊。", "嫩喜日光薄，疏憂雨點粗。驚蛙跳得過，鬥雀嫋如無。", "未織巴籬護，幾抬邛竹扶。惹煙輕弱柳，蘸水漱清蒲。", "溉灌情偏重，琴樽賞不孤。穿花思釣叟，吹葉少羌雛。", "寒色暮天映，秋聲遠籟俱。朗吟應有趣，瀟灑十餘株。"]'),
('yuding-2','田舍曲','王貞白','唐','御定全唐诗','yuding','','[]','古今利名路，只在儂門前。至老不離家，一生常晏眠。',72,'御定全唐詩/json/701.json','["古今利名路，只在儂門前。至老不離家，一生常晏眠。", "牛羊晚自歸，兒童戲野田。豈思封侯貴，唯只待豐年。", "征賦豈辭苦，但願時官賢。時官苟貪濁，田舍生憂煎。"]'),
('yuding-3','妾薄命','王貞白','唐','御定全唐诗','yuding','','[]','薄命頭欲白，頻年嫁不成。秦娥未十五，昨夜事公卿。',48,'御定全唐詩/json/701.json','["薄命頭欲白，頻年嫁不成。秦娥未十五，昨夜事公卿。", "豈有機杼力，空傳歌舞名。妾專修婦德，媒氏卻相輕。"]'),
('yuding-4','湘妃怨','王貞白','唐','御定全唐诗','yuding','','[]','舜欲省蠻陬，南巡非逸遊。九江沉白日，二女泣滄洲。',48,'御定全唐詩/json/701.json','["舜欲省蠻陬，南巡非逸遊。九江沉白日，二女泣滄洲。", "目極楚雲斷，恨深湘水流。至今聞鼓瑟，咽絕不勝愁。"]'),
('yuding-5','長門怨二首','王貞白','唐','御定全唐诗','yuding','','[]','寂寞故宮春，殘燈曉尚存。從來非妾過，偶爾失君恩。',96,'御定全唐詩/json/701.json','["寂寞故宮春，殘燈曉尚存。從來非妾過，偶爾失君恩。", "花落傷容鬢，鶯啼驚夢魂。翠華如可待，應免老長門。", "葉落長門靜，苔生永巷幽。相思對明月，獨坐向空樓。", "鑾駕迷終轉，蛾眉老自愁。昭陽歌舞伴，此夕未知秋。"]'),
('yuding-6','有所思','王貞白','唐','御定全唐诗','yuding','','[]','芙蓉出水時，偶爾便分離。自此無因見，長教掛所思。',48,'御定全唐詩/json/701.json','["芙蓉出水時，偶爾便分離。自此無因見，長教掛所思。", "殘春不入夢，芳信欲傳誰。寂寞秋堂下，空吟小謝詩。"]'),
('yuding-7','短歌','王貞白','唐','御定全唐诗','yuding','','[]','物候來相續，新蟬送晚鶯。百年休倚賴，一夢甚分明。',48,'御定全唐詩/json/701.json','["物候來相續，新蟬送晚鶯。百年休倚賴，一夢甚分明。", "金鼎神仙隱，銅壺晝夜傾。不如早立德，萬古有其名。"]'),
('yuding-8','禦溝水','王貞白','唐','御定全唐诗','yuding','','[]','一帶禦溝水，綠槐相蔭清。此中涵帝澤，無處濯塵纓。',48,'御定全唐詩/json/701.json','["一帶禦溝水，綠槐相蔭清。此中涵帝澤，無處濯塵纓。", "鳥道來雖險，龍池到自平。朝宗本心切，願向急流傾。"]'),
('yuding-9','少年行二首','王貞白','唐','御定全唐诗','yuding','','[]','遊宴不知厭，杜陵狂少年。花時輕暖酒，春服薄裝綿。',96,'御定全唐詩/json/701.json','["遊宴不知厭，杜陵狂少年。花時輕暖酒，春服薄裝綿。", "戲馬上林苑，鬥雞寒食天。魯儒甘被笑，對策鬢皤然。", "弱冠投邊急，驅兵夜渡河。追奔鐵馬走，殺虜寶刀訛。", "威靜黑山路，氣含清海波。常聞為突騎，天子賜長戈。"]'),
('yuding-10','塞上曲','王貞白','唐','御定全唐诗','yuding','','[]','歲歲但防虜，西征早晚休。匈奴不系頸，漢將但封侯。',48,'御定全唐詩/json/701.json','["歲歲但防虜，西征早晚休。匈奴不系頸，漢將但封侯。", "夕照低烽火，寒笳咽戍樓。燕然山上字，男子見須羞。"]'),
('yuding-11','長安道','王貞白','唐','御定全唐诗','yuding','','[]','曉鼓人已行，暮鼓人未息。梯航萬國來，爭先貢金帛。',48,'御定全唐詩/json/701.json','["曉鼓人已行，暮鼓人未息。梯航萬國來，爭先貢金帛。", "不問賢與愚，但論官與職。如何貧書生，只獻安邊策。"]'),
('yuding-12','洛陽道','王貞白','唐','御定全唐诗','yuding','','[]','喧喧洛陽路，奔走爭先步。唯恐著鞭遲，誰能更回顧。',48,'御定全唐詩/json/701.json','["喧喧洛陽路，奔走爭先步。唯恐著鞭遲，誰能更回顧。", "覆車雖在前，潤屋何曾懼。賢哉只二疏，東門掛冠去。"]'),
('yuding-13','度關山','王貞白','唐','御定全唐诗','yuding','','[]','只領千餘騎，長驅磧邑間。雲州多警急，雪夜度關山。',48,'御定全唐詩/json/701.json','["只領千餘騎，長驅磧邑間。雲州多警急，雪夜度關山。", "石響鈴聲遠，天寒弓力慳。秦樓休悵望，不日凱歌還。"]'),
('yuding-14','出自薊北門行','王貞白','唐','御定全唐诗','yuding','','[]','薊北連極塞，塞色晝冥冥。戰地骸骨滿，長時風雨腥。',48,'御定全唐詩/json/701.json','["薊北連極塞，塞色晝冥冥。戰地骸骨滿，長時風雨腥。", "沙河留不定，春草凍難青。萬戶封侯者，何謀靜虜庭。"]'),
('yuding-15','從軍行','王貞白','唐','御定全唐诗','yuding','','[]','從軍朔方久，未省用干戈。只以恩信及，自然戎虜和。',48,'御定全唐詩/json/701.json','["從軍朔方久，未省用干戈。只以恩信及，自然戎虜和。", "邊聲動白草，燒色入枯河。每度因看獵，令人勇氣多。"]'),
('yuding-16','古悔從軍行','王貞白','唐','御定全唐诗','yuding','','[]','憶昔仗孤劍，十年從武威。論兵親玉帳，逐虜過金微。',48,'御定全唐詩/json/701.json','["憶昔仗孤劍，十年從武威。論兵親玉帳，逐虜過金微。", "隴水秋先凍，關雲寒不飛。辛勤功業在，麟閣志猶違。"]'),
('yuding-17','胡笳曲','王貞白','唐','御定全唐诗','yuding','','[]','隴底悲笳引，隴頭鳴北風。一輪霜月落，萬里塞天空。',48,'御定全唐詩/json/701.json','["隴底悲笳引，隴頭鳴北風。一輪霜月落，萬里塞天空。", "戍卒淚應盡，胡兒哭未終。爭教班定遠，不念玉關中。"]'),
('yuding-18','入塞','王貞白','唐','御定全唐诗','yuding','','[]','玉殿論兵事，君王詔出征。新除羽林將，曾破月支兵。',48,'御定全唐詩/json/701.json','["玉殿論兵事，君王詔出征。新除羽林將，曾破月支兵。", "慣曆塞垣險，能分部落情。從今一戰勝，不使虜塵生。"]'),
('yuding-19','游仙','王貞白','唐','御定全唐诗','yuding','','[]','我家三島上，洞戶眺波濤。醉背雲屏臥，誰知海日高。',48,'御定全唐詩/json/701.json','["我家三島上，洞戶眺波濤。醉背雲屏臥，誰知海日高。", "露香紅玉樹，風綻碧蟠桃。悔與仙子別，思歸夢釣鼇。"]'),
('yuding-20','歌','王貞白','唐','御定全唐诗','yuding','','[]','誰唱關西曲，寂寞夜景深。一聲長在耳，萬恨重經心。',48,'御定全唐詩/json/701.json','["誰唱關西曲，寂寞夜景深。一聲長在耳，萬恨重經心。", "調古清風起，曲終涼月沉。卻應筵上客，未必是知音。"]'),
('yuding-21','經故洛城','王貞白','唐','御定全唐诗','yuding','','[]','卜世何久遠，由來仰聖明。山河徒自壯，周召不長生。',48,'御定全唐詩/json/701.json','["卜世何久遠，由來仰聖明。山河徒自壯，周召不長生。", "幾主任奸諂，諸侯各戰爭。但餘崩壘在，今古共傷情。"]'),
('yuding-22','金陵','王貞白','唐','御定全唐诗','yuding','','[]','六代江山在，繁華古帝都。亂來城不守，戰後地多蕪。',48,'御定全唐詩/json/701.json','["六代江山在，繁華古帝都。亂來城不守，戰後地多蕪。", "寒日隨潮落，歸帆與鳥孤。興亡多少事，回首一長籲。"]'),
('yuding-23','金陵懷古','王貞白','唐','御定全唐诗','yuding','','[]','恃險不種德，興亡歎數窮。石城幾換主，天塹謾連空。',48,'御定全唐詩/json/701.json','["恃險不種德，興亡歎數窮。石城幾換主，天塹謾連空。", "禦路疊民塚，台基聚牧童。折碑猶有字，多記晉英雄。"]'),
('yuding-24','商山','王貞白','唐','御定全唐诗','yuding','','[]','商山名利路，夜亦有人行。四皓臥雲處，千秋疊蘚生。',48,'御定全唐詩/json/701.json','["商山名利路，夜亦有人行。四皓臥雲處，千秋疊蘚生。", "晝燒籠澗黑，殘雪隔林明。我待酬恩了，來聽水石聲。"]'),
('yuding-25','廬山','王貞白','唐','御定全唐诗','yuding','','[]','岳立鎮南楚，雄名天下聞。五峰高閡日，九疊翠連雲。',48,'御定全唐詩/json/701.json','["岳立鎮南楚，雄名天下聞。五峰高閡日，九疊翠連雲。", "夏穀雪猶在，陰岩晝不分。唯應嵩與華，清峻得為群。"]'),
('yuding-26','終南山','王貞白','唐','御定全唐诗','yuding','','[]','終朝異五嶽，列翠滿長安。地去搜揚近，人謀隱遁難。',48,'御定全唐詩/json/701.json','["終朝異五嶽，列翠滿長安。地去搜揚近，人謀隱遁難。", "水穿諸苑過，雪照一城寒。為問紅塵裏，誰同駐馬看。"]'),
('yuding-27','寄鄭谷','王貞白','唐','御定全唐诗','yuding','','[]','五百首新詩，緘封寄去時。只憑夫子鑒，不要俗人知。',48,'御定全唐詩/json/701.json','["五百首新詩，緘封寄去時。只憑夫子鑒，不要俗人知。", "火鼠重收布，冰蠶乍吐絲。直須天上手，裁作領巾披。"]'),
('yuding-28','題嚴陵釣台','王貞白','唐','御定全唐诗','yuding','','[]','山色四時碧，溪聲七裏清。嚴陵愛此景，下視漢公卿。',48,'御定全唐詩/json/701.json','["山色四時碧，溪聲七裏清。嚴陵愛此景，下視漢公卿。", "垂釣月初上，放歌風正輕。應憐渭濱叟，匡國正論兵。"]'),
('yuding-29','曉泊漢陽渡','王貞白','唐','御定全唐诗','yuding','','[]','落月臨古渡，武昌城未開。殘燈明市井，曉色辨樓臺。',48,'御定全唐詩/json/701.json','["落月臨古渡，武昌城未開。殘燈明市井，曉色辨樓臺。", "雲自蒼梧去，水從嶓塚來。芳洲號鸚鵡，用記禰生才。"]'),
('yuding-30','隨計','王貞白','唐','御定全唐诗','yuding','','[]','徒步隨計吏，辛勤鬢易凋。歸期無定日，鄉思羨回潮。',48,'御定全唐詩/json/701.json','["徒步隨計吏，辛勤鬢易凋。歸期無定日，鄉思羨回潮。", "冒雨投前驛，侵星過斷橋。何堪穆陵路，霜葉更瀟瀟。"]'),
('yuding-31','白牡丹','王貞白','唐','御定全唐诗','yuding','','[]','穀雨洗纖素，裁為白牡丹。異香開玉合，輕粉泥銀盤。',48,'御定全唐詩/json/701.json','["穀雨洗纖素，裁為白牡丹。異香開玉合，輕粉泥銀盤。", "曉貯露華濕，宵傾月魄寒。家人淡妝罷，無語倚朱欄。"]'),
('yuding-32','述松','王貞白','唐','御定全唐诗','yuding','','[]','遠穀呈材幹，何由入棟樑。歲寒虛勝竹，功績不如桑。',48,'御定全唐詩/json/701.json','["遠穀呈材幹，何由入棟樑。歲寒虛勝竹，功績不如桑。", "秋露落松子，春深裛嫩黃。雖蒙匠者顧，樵采日難防。"]'),
('yuding-33','宮池產瑞蓮','王貞白','唐','御定全唐诗','yuding','','[]','雨露及萬物，嘉祥有瑞蓮。香飄雞樹近，榮占鳳池先。',48,'御定全唐詩/json/701.json','["雨露及萬物，嘉祥有瑞蓮。香飄雞樹近，榮占鳳池先。", "聖日臨雙麗，恩波照並妍。願同指佞草，生向帝堯前。"]'),
('yuding-34','送友人南歸','王貞白','唐','御定全唐诗','yuding','','[]','南國菖蒲老，知君憶釣船。離京近殘暑，歸路有新蟬。',48,'御定全唐詩/json/701.json','["南國菖蒲老，知君憶釣船。離京近殘暑，歸路有新蟬。", "峴首白雲起，洞庭秋月懸。若教吟興足，西笑是何年。"]'),
('yuding-35','送馬明府歸山','王貞白','唐','御定全唐诗','yuding','','[]','辭秩入匡廬，重修靖節居。免遭黑綬束，不與白雲疏。',48,'御定全唐詩/json/701.json','["辭秩入匡廬，重修靖節居。免遭黑綬束，不與白雲疏。", "送吏各獻酒，群兒自擔書。到時看瀑布，為我謝清虛。"]'),
('yuding-36','送韓從事歸本道','王貞白','唐','御定全唐诗','yuding','','[]','獻捷靈州倅，歸時寵拜新。論邊多稱旨，許國誓亡身。',48,'御定全唐詩/json/701.json','["獻捷靈州倅，歸時寵拜新。論邊多稱旨，許國誓亡身。", "馬渴黃河凍，雁回青塚春。到蕃唯促戰，應不肯和親。"]'),
('yuding-37','秋日旅懷寄右省鄭拾遺','王貞白','唐','御定全唐诗','yuding','','[]','永夕愁不寐，草蟲喧客庭。半窗分曉月，當枕落殘星。',48,'御定全唐詩/json/701.json','["永夕愁不寐，草蟲喧客庭。半窗分曉月，當枕落殘星。", "鬢髮游梁白，家山近越青。知音在諫省，苦調有誰聽。"]'),
('yuding-38','贈劉凝評事','王貞白','唐','御定全唐诗','yuding','','[]','棘寺官初罷，梁園靜掩扉。春深顏子巷，花映老萊衣。',48,'御定全唐詩/json/701.json','["棘寺官初罷，梁園靜掩扉。春深顏子巷，花映老萊衣。", "談史曾無滯，攻書已造微。即膺新寵命，稱慶向庭闈。"]'),
('yuding-39','憶張處士','王貞白','唐','御定全唐诗','yuding','','[]','天臺張處士，詩句造玄微。古樂知音少，名言與俗違。',48,'御定全唐詩/json/701.json','["天臺張處士，詩句造玄微。古樂知音少，名言與俗違。", "山風入松徑，海月上岩扉。畢世唯高臥，無人說是非。"]'),
('yuding-40','雲居長老','王貞白','唐','御定全唐诗','yuding','','[]','巘路躡雲上，來參出世僧。松高半岩雪，竹覆一溪冰。',48,'御定全唐詩/json/701.json','["巘路躡雲上，來參出世僧。松高半岩雪，竹覆一溪冰。", "不說有為法，非傳無盡燈。了然方寸內，應只見南能。"]'),
('yuding-41','洗竹','王貞白','唐','御定全唐诗','yuding','','[]','道院竹繁教略洗，鳴琴酌酒看扶疏。不圖結實來雙鳳，',40,'御定全唐詩/json/701.json','["道院竹繁教略洗，鳴琴酌酒看扶疏。不圖結實來雙鳳，", "有時記得三天事，自向琅玕節下書。"]'),
('yuding-42','庾樓曉望','王貞白','唐','御定全唐诗','yuding','','[]','獨憑朱檻亦淩晨，山色初明水色新。竹霧曉籠銜嶺月，',40,'御定全唐詩/json/701.json','["獨憑朱檻亦淩晨，山色初明水色新。竹霧曉籠銜嶺月，", "三百年來庾樓上，曾經多少望鄉人。"]'),
('yuding-43','送芮尊師','王貞白','唐','御定全唐诗','yuding','','[]','石上菖蒲節節靈，先生服食得長生。早知避世憂身老，',40,'御定全唐詩/json/701.json','["石上菖蒲節節靈，先生服食得長生。早知避世憂身老，", "他年控鯉升天去，廬嶽逋民願從行。"]'),
('yuding-44','折楊柳三首','王貞白','唐','御定全唐诗','yuding','','[]','枝枝交影鎖長門，嫩色曾沾雨露恩。',96,'御定全唐詩/json/701.json','["枝枝交影鎖長門，嫩色曾沾雨露恩。", "鳳輦不來春欲盡，空留鶯語到黃昏。", "水殿年年占早芳，柔條風裏禦爐香。", "如今萬乘多巡狩，輦路無陰綠草長。", "嫩葉初齊不耐寒，風和時拂玉欄幹。", "征人去日曾攀折，泣雨傷春翠黛殘。"]'),
('yuding-45','遠聞本郡行春到舊山二首','王貞白','唐','御定全唐诗','yuding','','[]','一身從宦留京邑，五馬遙聞到舊山。',64,'御定全唐詩/json/701.json','["一身從宦留京邑，五馬遙聞到舊山。", "已領煙霞光野徑，深慚老幼候柴關。", "清風借響松筠外，畫隼停暉水石間。", "定掩溪名在圖傳，共知軒蓋此登攀。"]'),
('yuding-46','宿新安村步','王貞白','唐','御定全唐诗','yuding','','[]','淅淅寒流漲淺沙，月明空渚遍蘆花。',32,'御定全唐詩/json/701.json','["淅淅寒流漲淺沙，月明空渚遍蘆花。", "離人偶宿孤村下，永夜聞砧一兩家。"]'),
('yuding-47','仙岩二首','王貞白','唐','御定全唐诗','yuding','','[]','白煙晝起丹灶，紅葉秋書篆文。',56,'御定全唐詩/json/701.json','["白煙晝起丹灶，紅葉秋書篆文。", "二十四岩天上，一雞啼破晴雲。", "風呼山鬼服役，月照衡薇結花。", "江暖客尋瑤草，洞深人咽丹霞。"]'),
('yuding-48','雨後從陶郎中登庾樓','王貞白','唐','御定全唐诗','yuding','','[]','庾樓逢霽色，夏日欲西曛。虹截半江雨，風驅大澤雲。',48,'御定全唐詩/json/701.json','["庾樓逢霽色，夏日欲西曛。虹截半江雨，風驅大澤雲。", "島邊漁艇聚，天畔鳥行分。此景堪誰畫，文翁請綴文。"]'),
('yuding-49','九日長安作','王貞白','唐','御定全唐诗','yuding','','[]','無酒泛金菊，登高但憶秋。歸心隨旅雁，萬里在滄洲。',48,'御定全唐詩/json/701.json','["無酒泛金菊，登高但憶秋。歸心隨旅雁，萬里在滄洲。", "殘照明天闕，孤砧隔禦溝。誰能思落帽，兩鬢已添愁。"]'),
('yuding-50','曉發蕭關','王貞白','唐','御定全唐诗','yuding','','[]','早發長風裏，邊城曙色間。數鴻寒背磧，片月落臨關。',48,'御定全唐詩/json/701.json','["早發長風裏，邊城曙色間。數鴻寒背磧，片月落臨關。", "隴上明星沒，沙中夜探還。歸程不可問，幾日到家山。"]'),
('yuding-51','釣台','王貞白','唐','御定全唐诗','yuding','','[]','異代有巢許，方知嚴子情。舊交雖建國，高臥不求榮。',48,'御定全唐詩/json/701.json','["異代有巢許，方知嚴子情。舊交雖建國，高臥不求榮。", "溪鳥寒來浴，汀蘭暖重生。何顏吟過此，辛苦得浮名。"]'),
('yuding-52','寄天臺葉尊師','王貞白','唐','御定全唐诗','yuding','','[]','師住天臺久，長聞過石橋。晴峰見滄海，深洞徹丹霄。',48,'御定全唐詩/json/701.json','["師住天臺久，長聞過石橋。晴峰見滄海，深洞徹丹霄。", "采藥霞衣濕，煎芝古鼎焦。念予無俗骨，頻與鶴書招。"]'),
('yuding-53','禦試後進詩','王貞白','唐','御定全唐诗','yuding','','[]','三時賜食天廚近，再宿偷吟禁漏清。',32,'御定全唐詩/json/701.json','["三時賜食天廚近，再宿偷吟禁漏清。", "二十五家齊拔宅，人間已寫上升名。"]'),
('yuding-54','春日詠梅花','王貞白','唐','御定全唐诗','yuding','','[]','靚妝才罷粉痕新，迨曉風回散玉塵。',32,'御定全唐詩/json/701.json','["靚妝才罷粉痕新，迨曉風回散玉塵。", "若遣有情應悵望，已兼殘雪又兼春。"]'),
('yuding-55','句','王貞白','唐','御定全唐诗','yuding','','[]','太陽雖不照，梁棟每重陰。',88,'御定全唐詩/json/701.json','["太陽雖不照，梁棟每重陰。", "白髮未逢媒，對景且裴回。", "別酒莫辭今夜醉，故人知我幾時來。", "改貫永留鄉黨額，減租重感郡侯恩。（洪景盧《野處集》", "載赴選別太守句，貞白自注：蒙本州改坊名為進賢，"]'),
('yuding-0','登單于台','張蠙','唐','御定全唐诗','yuding','','[]','邊兵春盡回，獨上單于台。白日地中出，黃河天外來。',48,'御定全唐詩/json/702.json','["邊兵春盡回，獨上單于台。白日地中出，黃河天外來。", "沙翻痕似浪，風急響疑雷。欲向陰關度，陰關曉不開。"]'),
('yuding-1','寄友人','張蠙','唐','御定全唐诗','yuding','','[]','戀道欲何如，東西遠索居。長疑即見面，翻致久無書。',48,'御定全唐詩/json/702.json','["戀道欲何如，東西遠索居。長疑即見面，翻致久無書。", "甸麥深藏雉，淮苔淺露魚。相思不我會，明月幾盈虛。"]'),
('yuding-2','和崔監丞春遊鄭僕射東園','張蠙','唐','御定全唐诗','yuding','','[]','春興隨花盡，東園自養閑。不離三畝地，似入萬重山。',48,'御定全唐詩/json/702.json','["春興隨花盡，東園自養閑。不離三畝地，似入萬重山。", "白鳥穿蘿去，清泉抵石還。豈同秦代客，無位隱商山。"]'),
('yuding-3','過蕭關','張蠙','唐','御定全唐诗','yuding','','[]','出得蕭關北，儒衣不稱身。隴狐來試客，沙鶻下欺人。',48,'御定全唐詩/json/702.json','["出得蕭關北，儒衣不稱身。隴狐來試客，沙鶻下欺人。", "曉戍殘烽火，晴原起獵塵。邊戎莫相忌，非是霍家親。"]'),
('yuding-4','盆池','張蠙','唐','御定全唐诗','yuding','','[]','圓內陶化功，外絕眾流通。選處離松影，穿時減藥叢。',48,'御定全唐詩/json/702.json','["圓內陶化功，外絕眾流通。選處離松影，穿時減藥叢。", "別疑天在地，長對月當空。每使登門客，煙波入夢中。"]'),
('yuding-5','野泉','張蠙','唐','御定全唐诗','yuding','','[]','遠出白雲中，長年聽不同。清聲縈亂石，寒色入長空。',48,'御定全唐詩/json/702.json','["遠出白雲中，長年聽不同。清聲縈亂石，寒色入長空。", "掛壁聊成雨，穿林別起風。溫泉非爾數，源發在深空。"]'),
('yuding-6','送成州牧','張蠙','唐','御定全唐诗','yuding','','[]','清時為塞郡，自古有儒流。素望知難愜，新恩且用酬。',48,'御定全唐詩/json/702.json','["清時為塞郡，自古有儒流。素望知難愜，新恩且用酬。", "犬牙連蜀國，兵額貫秦州。只作三年別，誰能聽邑留。"]'),
('yuding-7','薊北書事','張蠙','唐','御定全唐诗','yuding','','[]','度磧如經海，茫然但見空。戍樓承落日，沙塞礙驚蓬。',48,'御定全唐詩/json/702.json','["度磧如經海，茫然但見空。戍樓承落日，沙塞礙驚蓬。", "暑過燕僧出，時平虜客通。逢人皆上將，誰有定邊功。"]'),
('yuding-8','送徐州薛尚書','張蠙','唐','御定全唐诗','yuding','','[]','上將出儒中，論詩擬立功。州從禹後別，軍自漢來雄。',48,'御定全唐詩/json/702.json','["上將出儒中，論詩擬立功。州從禹後別，軍自漢來雄。", "遠驛銷寒日，嚴城肅暮空。龍顏有遺廟，猶得奠英風。"]'),
('yuding-9','貽曹郎中','張蠙','唐','御定全唐诗','yuding','','[]','所作高前古，封章自曲台。細看明主意，終用出人才。',48,'御定全唐詩/json/702.json','["所作高前古，封章自曲台。細看明主意，終用出人才。", "省印尋僧鎖，書樓領鶴開。南山有舊友，時向白雲來。"]'),
('yuding-10','送縉雲尉','張蠙','唐','御定全唐诗','yuding','','[]','釋褐從仙尉，之官興若何。去程唯水石，公署在雲蘿。',48,'御定全唐詩/json/702.json','["釋褐從仙尉，之官興若何。去程唯水石，公署在雲蘿。", "野飯樓中迥，晴峰案上多。三年罷趨府，應更戰高科。"]'),
('yuding-11','送董卿赴台州','張蠙','唐','御定全唐诗','yuding','','[]','九陌除書出，尋僧問海城。家從中路挈，吏隔數州迎。',48,'御定全唐詩/json/702.json','["九陌除書出，尋僧問海城。家從中路挈，吏隔數州迎。", "夜蚌侵燈影，春禽雜櫓聲。開圖見異跡，思上石橋行。"]'),
('yuding-12','送友人赴涇州幕','張蠙','唐','御定全唐诗','yuding','','[]','杏園沈飲散，榮別就佳招。日月相期盡，山川獨去遙。',48,'御定全唐詩/json/702.json','["杏園沈飲散，榮別就佳招。日月相期盡，山川獨去遙。", "府樓明蜀雪，關磧轉胡雕。縱有煙塵動，應隨上策銷。"]'),
('yuding-13','逢漳州崔使君北歸','張蠙','唐','御定全唐诗','yuding','','[]','在郡多殊稱，無人不望回。離城攜客去，度嶺擔猿來。',48,'御定全唐詩/json/702.json','["在郡多殊稱，無人不望回。離城攜客去，度嶺擔猿來。", "障寫經冬蕊，瓶緘落暑梅。長安有歸宅，歸見鎖青苔。"]'),
('yuding-14','雲朔逢山友','張蠙','唐','御定全唐诗','yuding','','[]','會面卻生疑，居然似夢歸。塞深行客少，家遠識人稀。',48,'御定全唐詩/json/702.json','["會面卻生疑，居然似夢歸。塞深行客少，家遠識人稀。", "戰馬分旗牧，驚禽曳箭飛。將軍雖異禮，難便脫麻衣。"]'),
('yuding-15','別後寄友生','張蠙','唐','御定全唐诗','yuding','','[]','上馬如飛鳥，飄然隔去塵。共看今夜月，獨作異鄉人。',48,'御定全唐詩/json/702.json','["上馬如飛鳥，飄然隔去塵。共看今夜月，獨作異鄉人。", "就養江南熟，移居井賦新。襄陽曾卜隱，應與孟家鄰。"]'),
('yuding-16','邊游別友人','張蠙','唐','御定全唐诗','yuding','','[]','欲別不止淚，當杯難強歌。家貧隨日長，身病涉寒多。',48,'御定全唐詩/json/702.json','["欲別不止淚，當杯難強歌。家貧隨日長，身病涉寒多。", "雨雪迷燕路，田園隔楚波。良時未自致，歸去欲如何。"]'),
('yuding-17','邊庭送別','張蠙','唐','御定全唐诗','yuding','','[]','一生雖達理，遠別亦相悲。白髮無修處，青松有老時。',48,'御定全唐詩/json/702.json','["一生雖達理，遠別亦相悲。白髮無修處，青松有老時。", "暮煙傳戍起，寒日隔沙垂。若是長安去，何難定後期。"]'),
('yuding-18','將之京師留別親友','張蠙','唐','御定全唐诗','yuding','','[]','達命何勞問，西遊且自期。至公如有日，知我豈無時。',48,'御定全唐詩/json/702.json','["達命何勞問，西遊且自期。至公如有日，知我豈無時。", "野迥蟬相答，堤長柳對垂。酣歌一舉袂，明發不堪思。"]'),
('yuding-19','贈別山友','張蠙','唐','御定全唐诗','yuding','','[]','從容無限意，不獨為離群。年長驚黃葉，時清厭白雲。',48,'御定全唐詩/json/702.json','["從容無限意，不獨為離群。年長驚黃葉，時清厭白雲。", "舊山回馬見，寒瀑別家聞。相與存吾道，窮通各自分。"]'),
('yuding-20','途次績溪先寄陳明府','張蠙','唐','御定全唐诗','yuding','','[]','入境風煙好，幽人不易傳。新居多是客，舊隱半成仙。',48,'御定全唐詩/json/702.json','["入境風煙好，幽人不易傳。新居多是客，舊隱半成仙。", "山斷雲沖騎，溪長柳拂船。何當許過縣，聞有篋中篇。"]'),
('yuding-21','送友人歸武陵','張蠙','唐','御定全唐诗','yuding','','[]','聞近桃源住，無村不是花。戍旗招海客，廟鼓集江鴉。',48,'御定全唐詩/json/702.json','["聞近桃源住，無村不是花。戍旗招海客，廟鼓集江鴉。", "別島垂橙實，閒田長荻芽。游秦未得意，看即更離家。"]'),
('yuding-22','亂中寄友人','張蠙','唐','御定全唐诗','yuding','','[]','別來難覓信，何處避艱危。鬢黑無多日，塵清是幾時。',48,'御定全唐詩/json/702.json','["別來難覓信，何處避艱危。鬢黑無多日，塵清是幾時。", "人情將厭武，王澤即興詩。若便懷深隱，還應聖主知。"]'),
('yuding-23','哭建州李員外','張蠙','唐','御定全唐诗','yuding','','[]','詩名不易出，名出又何為。捷到重科早，官終一郡卑。',48,'御定全唐詩/json/702.json','["詩名不易出，名出又何為。捷到重科早，官終一郡卑。", "素風無後嗣，遺跡有生祠。自罷羊公市，溪猿哭舊時。"]'),
('yuding-24','吊孟浩然','張蠙','唐','御定全唐诗','yuding','','[]','每每樵家說，孤墳亦夜吟。若重生此世，應更苦前心。',48,'御定全唐詩/json/702.json','["每每樵家說，孤墳亦夜吟。若重生此世，應更苦前心。", "名與襄陽遠，詩同漢水深。親栽鹿門樹，猶蓋石床陰。"]'),
('yuding-25','送友人及第歸','張蠙','唐','御定全唐诗','yuding','','[]','家林滄海東，未曉日先紅。作貢諸蕃別，登科幾國同。',48,'御定全唐詩/json/702.json','["家林滄海東，未曉日先紅。作貢諸蕃別，登科幾國同。", "遠聲魚呷浪，層氣蜃迎風。鄉俗稀攀桂，爭來問月宮。"]'),
('yuding-26','次韻和友人冬月書齋','張蠙','唐','御定全唐诗','yuding','','[]','四季多花木，窮冬亦不凋。薄冰行處斷，殘火睡來消。',48,'御定全唐詩/json/702.json','["四季多花木，窮冬亦不凋。薄冰行處斷，殘火睡來消。", "象版簽書帙，蠻藤絡酒瓢。公卿有知己，時得一相招。"]'),
('yuding-27','過山家','張蠙','唐','御定全唐诗','yuding','','[]','避暑得探幽，忘言遂久留。雲深窗失曙，松合徑先秋。',48,'御定全唐詩/json/702.json','["避暑得探幽，忘言遂久留。雲深窗失曙，松合徑先秋。", "響谷傳人語，鳴泉洗客愁。家山不在此，至此可歸休。"]'),
('yuding-28','宿山驛','張蠙','唐','御定全唐诗','yuding','','[]','驛在千峰裏，寒宵獨此身。古墳時見火，荒壁悄無鄰。',48,'御定全唐詩/json/702.json','["驛在千峰裏，寒宵獨此身。古墳時見火，荒壁悄無鄰。", "月白翻驚鳥，雲閑欲就人。只應明日鬢，更與老相親。"]'),
('yuding-29','宿開照寺光澤上人院','張蠙','唐','御定全唐诗','yuding','','[]','靜室譚玄旨，清宵獨細聽。真身非有像，至理本無經。',48,'御定全唐詩/json/702.json','["靜室譚玄旨，清宵獨細聽。真身非有像，至理本無經。", "鐘定遙聞水，樓高別見星。不教人觸穢，偏說此山靈。"]'),
('yuding-30','宿山寺','張蠙','唐','御定全唐诗','yuding','','[]','中峰半夜起，忽覺有青冥。此界自生雨，上方猶有星。',48,'御定全唐詩/json/702.json','["中峰半夜起，忽覺有青冥。此界自生雨，上方猶有星。", "樓高鐘尚遠，殿古像多靈。好是潺湲水，房房伴誦經。"]'),
('yuding-31','題紫閣院','張蠙','唐','御定全唐诗','yuding','','[]','上方人海外，苔徑上千層。洞壑有靈藥，房廊無老僧。',48,'御定全唐詩/json/702.json','["上方人海外，苔徑上千層。洞壑有靈藥，房廊無老僧。", "古岩雕素像，喬木掛寒燈。每到思修隱，將回苦不能。"]'),
('yuding-32','白菊','張蠙','唐','御定全唐诗','yuding','','[]','秋天木葉幹，猶有白花殘。舉世稀栽得，豪家卻畫看。',48,'御定全唐詩/json/702.json','["秋天木葉幹，猶有白花殘。舉世稀栽得，豪家卻畫看。", "片苔相應綠，諸卉獨宜寒。幾度攜佳客，登高欲折難。"]'),
('yuding-33','叢葦','張蠙','唐','御定全唐诗','yuding','','[]','叢叢寒水邊，曾折打魚船。忽與亭台近，翻嫌島嶼偏。',48,'御定全唐詩/json/702.json','["叢叢寒水邊，曾折打魚船。忽與亭台近，翻嫌島嶼偏。", "花明無月夜，聲急正秋天。遙憶巴陵渡，殘陽一望煙。"]'),
('yuding-34','鄭轂補闕山松','張蠙','唐','御定全唐诗','yuding','','[]','心將積雪欺，根與白雲離。遠寄僧猶憶，高看鶴未知。',48,'御定全唐詩/json/702.json','["心將積雪欺，根與白雲離。遠寄僧猶憶，高看鶴未知。", "影交新長葉，皴匝舊生枝。多少同時種，深山不得移。"]'),
('yuding-35','新竹','張蠙','唐','御定全唐诗','yuding','','[]','新鞭暗入庭，初長兩三莖。不是他山少，無如此地生。',48,'御定全唐詩/json/702.json','["新鞭暗入庭，初長兩三莖。不是他山少，無如此地生。", "垂梢叢上出，柔葉籜間成。何用高唐峽，風枝掃月明。"]'),
('yuding-36','和友人送趙能卿東歸','張蠙','唐','御定全唐诗','yuding','','[]','一第時難得，歸期日已過。相看玄鬢少，共憶白雲多。',48,'御定全唐詩/json/702.json','["一第時難得，歸期日已過。相看玄鬢少，共憶白雲多。", "楚闊天垂草，吳空月上波。無人不有遇，之子獨狂歌。"]'),
('yuding-37','送人歸南中','張蠙','唐','御定全唐诗','yuding','','[]','有家誰不別，經亂獨難尋。遠路波濤惡，窮荒雨霧深。',48,'御定全唐詩/json/702.json','["有家誰不別，經亂獨難尋。遠路波濤惡，窮荒雨霧深。", "燒驚山象出，雷觸海鼇沉。為問南遷客，何人在瘴林。"]'),
('yuding-38','塞下曲','張蠙','唐','御定全唐诗','yuding','','[]','邊事多更變，天心亦為憂。胡兵來作寇，漢將也封侯。',48,'御定全唐詩/json/702.json','["邊事多更變，天心亦為憂。胡兵來作寇，漢將也封侯。", "夜燒沖星赤，寒塵翳日愁。無門展微略，空上望西樓。"]'),
('yuding-39','邊將二首','張蠙','唐','御定全唐诗','yuding','','[]','曆戰燕然北，功高劍有威。聞名外國懼，輕命故人稀。',96,'御定全唐詩/json/702.json','["曆戰燕然北，功高劍有威。聞名外國懼，輕命故人稀。", "角怨星芒動，塵愁日色微。從為漢都護，未得脫征衣。", "按劍立城樓，西看極海頭。承家為上將，開地得邊州。", "磧迥兵難伏，天寒馬易收。胡風一度獵，吹裂錦貂裘。"]'),
('yuding-40','朔方書事','張蠙','唐','御定全唐诗','yuding','','[]','秋盡角聲苦，逢人唯荷戈。城池向隴少，岐路出關多。',48,'御定全唐詩/json/702.json','["秋盡角聲苦，逢人唯荷戈。城池向隴少，岐路出關多。", "雁遠行垂地，烽高影入河。仍聞黑山寇，又覓漢家和。"]'),
('yuding-41','經荒驛','張蠙','唐','御定全唐诗','yuding','','[]','古驛成幽境，雲蘿隔四鄰。夜燈移宿鳥，秋雨禁行人。',48,'御定全唐詩/json/702.json','["古驛成幽境，雲蘿隔四鄰。夜燈移宿鳥，秋雨禁行人。", "廢巷荊叢合，荒庭虎跡新。昔年經此地，終日是紅塵。"]'),
('yuding-42','贈棲白大師','張蠙','唐','御定全唐诗','yuding','','[]','剃發得時名，僧應別應星。偶題皆有詔，閑論便成經。',48,'御定全唐詩/json/702.json','["剃發得時名，僧應別應星。偶題皆有詔，閑論便成經。", "掃葉寒燒鼎，融冰曉注瓶。長因內齋出，多客叩禪扃。"]'),
('yuding-43','贈聞一上人','張蠙','唐','御定全唐诗','yuding','','[]','見面雖年少，聞名似白頭。玄談窮釋旨，清思掩詩流。',48,'御定全唐詩/json/702.json','["見面雖年少，聞名似白頭。玄談窮釋旨，清思掩詩流。", "果落痕生砌，松高影上樓。壇場在三殿，應召入焚修。"]'),
('yuding-44','贈可倫上人','張蠙','唐','御定全唐诗','yuding','','[]','師教本於空，流來不自東。修從多劫後，行出眾人中。',48,'御定全唐詩/json/702.json','["師教本於空，流來不自東。修從多劫後，行出眾人中。", "衲冷湖山雨，幡輕海甸風。游吳累夏講，還與虎溪同。"]'),
('yuding-45','寄法幹寺令諲太師','張蠙','唐','御定全唐诗','yuding','','[]','師居中禁寺，外請已無緣。望幸唯修偈，承恩不亂禪。',48,'御定全唐詩/json/702.json','["師居中禁寺，外請已無緣。望幸唯修偈，承恩不亂禪。", "院多喧種藥，池有化生蓮。何日龍宮裏，相尋借法船。"]'),
('yuding-46','寄太白禪師','張蠙','唐','御定全唐诗','yuding','','[]','何年萬仞頂，獨有坐禪僧。客上應無路，人傳或見燈。',48,'御定全唐詩/json/702.json','["何年萬仞頂，獨有坐禪僧。客上應無路，人傳或見燈。", "齋廚唯有橡，講石任生藤。遙想東林社，如師誰複能。"]'),
('yuding-47','遇道者','張蠙','唐','御定全唐诗','yuding','','[]','數裏白雲裏，身輕無履蹤。故尋多不見，偶到即相逢。',48,'御定全唐詩/json/702.json','["數裏白雲裏，身輕無履蹤。故尋多不見，偶到即相逢。", "古井生雲水，高壇出異松。聊看杏花酌，便似換顏容。"]'),
('yuding-48','贈道者','張蠙','唐','御定全唐诗','yuding','','[]','得道疑人識，都城獨閉關。頭從白後黑，心向鬧中閑。',48,'御定全唐詩/json/702.json','["得道疑人識，都城獨閉關。頭從白後黑，心向鬧中閑。", "饑渴唯調氣，兒孫亦駐顏。始知仙者隱，殊不在深山。"]'),
('yuding-49','雨','張蠙','唐','御定全唐诗','yuding','','[]','半夜西亭雨，離人獨啟關。桑麻荒舊國，雷電照前山。',48,'御定全唐詩/json/702.json','["半夜西亭雨，離人獨啟關。桑麻荒舊國，雷電照前山。", "細滴高槐底，繁聲疊漏間。唯應孤鏡裏，明月長愁顏。"]'),
('yuding-50','長安春望','張蠙','唐','御定全唐诗','yuding','','[]','明時不敢臥煙霞，又見秦城換物華。殘雪未銷雙鳳闕，',40,'御定全唐詩/json/702.json','["明時不敢臥煙霞，又見秦城換物華。殘雪未銷雙鳳闕，", "故國別來桑柘盡，十年兵踐海西艖。"]'),
('yuding-51','過黃牛峽','張蠙','唐','御定全唐诗','yuding','','[]','黃牛來勢瀉巴川，疊日孤舟逐峽前。雷電夜驚猿落樹，',40,'御定全唐詩/json/702.json','["黃牛來勢瀉巴川，疊日孤舟逐峽前。雷電夜驚猿落樹，", "多少人經過此去，一生魂夢怕潺湲。"]'),
('yuding-52','逢道者','張蠙','唐','御定全唐诗','yuding','','[]','縱意出山無遠近，還如孤鶴在空虛。昔年親種樹皆老，',40,'御定全唐詩/json/702.json','["縱意出山無遠近，還如孤鶴在空虛。昔年親種樹皆老，", "只尋隱跡歸何處，方說煙霞不定居。"]'),
('yuding-53','邊情','張蠙','唐','御定全唐诗','yuding','','[]','窮荒始得靜天驕，又說天兵擬渡遼。聖主尚嫌蕃界近，',40,'御定全唐詩/json/702.json','["窮荒始得靜天驕，又說天兵擬渡遼。聖主尚嫌蕃界近，", "惆悵臨戎皆效國，豈無人似霍嫖姚。"]'),
('yuding-54','贈李司徒','張蠙','唐','御定全唐诗','yuding','','[]','承家拓定隴關西，勳貴名應上將齊。金庫夜開龍甲冷，',40,'御定全唐詩/json/702.json','["承家拓定隴關西，勳貴名應上將齊。金庫夜開龍甲冷，", "長怪魯儒頭枉白，不親弓劍覓丹梯。"]'),
('yuding-55','送盧尚書赴靈武','張蠙','唐','御定全唐诗','yuding','','[]','西北正傳烽候急，靈州共喜信臣居。從軍儘是清才去，',40,'御定全唐詩/json/702.json','["西北正傳烽候急，靈州共喜信臣居。從軍儘是清才去，", "山川不異江湖景，賓館常聞食有魚。"]'),
('yuding-56','投翰林張侍郎','張蠙','唐','御定全唐诗','yuding','','[]','舉家貧拾海邊樵，來認仙宗在碧霄。丹穴雖無凡羽翼，',40,'御定全唐詩/json/702.json','["舉家貧拾海邊樵，來認仙宗在碧霄。丹穴雖無凡羽翼，", "願與吾君作霖雨，且應平地活枯苗。"]'),
('yuding-57','投翰林蕭侍郎','張蠙','唐','御定全唐诗','yuding','','[]','九仞牆邊絕路岐，野才非合自求知。靈湫豈要魚棲浪，',40,'御定全唐詩/json/702.json','["九仞牆邊絕路岐，野才非合自求知。靈湫豈要魚棲浪，", "從來為學投文鏡，文鏡如今更有誰。"]'),
('yuding-58','宴駙馬宅','張蠙','唐','御定全唐诗','yuding','','[]','牙香禁樂鎮相攜，日日君恩降紫泥。紅藥院深人半醉，',40,'御定全唐詩/json/702.json','["牙香禁樂鎮相攜，日日君恩降紫泥。紅藥院深人半醉，", "別向庭蕪寘吟石，不教宮妓踏成蹊。"]'),
('yuding-59','邊將','張蠙','唐','御定全唐诗','yuding','','[]','上馬乘秋欲建勳，飛弧夜闕出師頻。若無紫塞煙塵事，',40,'御定全唐詩/json/702.json','["上馬乘秋欲建勳，飛弧夜闕出師頻。若無紫塞煙塵事，", "由來邊卒皆如此，只是君門合殺身。"]'),
('yuding-60','贈水軍都將','張蠙','唐','御定全唐诗','yuding','','[]','平生為有安邦術，便別秋曹最上階。戰艦卻容儒客臥，',40,'御定全唐詩/json/702.json','["平生為有安邦術，便別秋曹最上階。戰艦卻容儒客臥，", "直待門前見幢節，始應高愜聖君懷。"]'),
('yuding-61','贈九江太守','張蠙','唐','御定全唐诗','yuding','','[]','江頭暫駐木蘭船，漁父來誇太守賢。二邑旋添新戶口，',40,'御定全唐詩/json/702.json','["江頭暫駐木蘭船，漁父來誇太守賢。二邑旋添新戶口，", "昨日西亭從遊騎，信旗風裏說詩篇。"]'),
('yuding-62','贈信安太守','張蠙','唐','御定全唐诗','yuding','','[]','三衢正對福星時，喜得君侯妙撫綏。甲士散教耕壟畝，',40,'御定全唐詩/json/702.json','["三衢正對福星時，喜得君侯妙撫綏。甲士散教耕壟畝，", "昨日中官說天意，即飛丹詔立新碑。"]'),
('yuding-63','贈江都鄭明府','張蠙','唐','御定全唐诗','yuding','','[]','他人豈是稱才術，才術須觀力有餘。兵亂幾年臨劇邑，',40,'御定全唐詩/json/702.json','["他人豈是稱才術，才術須觀力有餘。兵亂幾年臨劇邑，", "更欲棲蹤近彭澤，香爐峰下結茅廬。"]'),
('yuding-64','贈南昌宰','張蠙','唐','御定全唐诗','yuding','','[]','假邑邀真邑命分，明庭元有至公存。每鋤奸弊同荊棘，',40,'御定全唐詩/json/702.json','["假邑邀真邑命分，明庭元有至公存。每鋤奸弊同荊棘，", "新銜便合兼朱紱，應待蒼生更舉論。"]'),
('yuding-65','贈丘衙推','張蠙','唐','御定全唐诗','yuding','','[]','仙都高處掩柴扉，人世聞名見者稀。詩逸不拘凡對屬，',40,'御定全唐詩/json/702.json','["仙都高處掩柴扉，人世聞名見者稀。詩逸不拘凡對屬，", "任醉賓筵莫深隱，綺羅絲竹勝漁磯。"]'),
('yuding-66','獻所知','張蠙','唐','御定全唐诗','yuding','','[]','跡熟荀家見弟兄，九霄同與指前程。吹噓漸覺馨香出，',40,'御定全唐詩/json/702.json','["跡熟荀家見弟兄，九霄同與指前程。吹噓漸覺馨香出，", "登龍不敢懷他願，只望為霖致太平。"]'),
('yuding-67','投所知','張蠙','唐','御定全唐诗','yuding','','[]','十五年看帝裏春，一枝頭白未酬身。自聞離亂開公道，',40,'御定全唐詩/json/702.json','["十五年看帝裏春，一枝頭白未酬身。自聞離亂開公道，", "省郎門似龍門峻，應借風雷變涸鱗。"]'),
('yuding-68','南康夜宴東溪留別郡守陸郎中','張蠙','唐','御定全唐诗','yuding','','[]','飄然野客才無取，多謝君侯獨見知。竹葉樽前教駐樂，',40,'御定全唐詩/json/702.json','["飄然野客才無取，多謝君侯獨見知。竹葉樽前教駐樂，", "明發別愁何處去，片帆天際酒醒時。"]'),
('yuding-69','言懷','張蠙','唐','御定全唐诗','yuding','','[]','十載聲沈覺自非，賤身元合衣荷衣。豈能得路陪先達，',40,'御定全唐詩/json/702.json','["十載聲沈覺自非，賤身元合衣荷衣。豈能得路陪先達，", "平生只學穿楊箭，更向何門是見機。"]'),
('yuding-70','喜友人日南回','張蠙','唐','御定全唐诗','yuding','','[]','南游曾去海南涯，此去遊人不易歸。白日霧昏張夜燭，',40,'御定全唐詩/json/702.json','["南游曾去海南涯，此去遊人不易歸。白日霧昏張夜燭，", "重入帝城何寂寞，共回遷客半輕肥。"]'),
('yuding-71','下第述懷','張蠙','唐','御定全唐诗','yuding','','[]','十載長安跡未安，杏花還是看人看。名從近事方知險，',40,'御定全唐詩/json/702.json','["十載長安跡未安，杏花還是看人看。名從近事方知險，", "如何直道為身累，坐月眠霜思枉幹。"]'),
('yuding-72','華陽道者','張蠙','唐','御定全唐诗','yuding','','[]','華陽洞裏持真經，心嫌來客風塵腥。惟餐白石過白日，',40,'御定全唐詩/json/702.json','["華陽洞裏持真經，心嫌來客風塵腥。惟餐白石過白日，", "長生不必論貴賤，卻是幽人骨主靈。"]'),
('yuding-73','夏日題老將林亭','張蠙','唐','御定全唐诗','yuding','','[]','百戰功成翻愛靜，侯門漸欲似仙家。牆頭雨細垂纖草，',40,'御定全唐詩/json/702.json','["百戰功成翻愛靜，侯門漸欲似仙家。牆頭雨細垂纖草，", "幾人圖在淩煙閣，曾不交鋒向塞沙。"]'),
('yuding-74','觀江南牡丹','張蠙','唐','御定全唐诗','yuding','','[]','北地花開南地風，寄根還與客心同。群芳盡怯千般態，',40,'御定全唐詩/json/702.json','["北地花開南地風，寄根還與客心同。群芳盡怯千般態，", "近年明主思王道，不許新栽滿六宮。"]'),
('yuding-75','錢塘夜宴留別郡守','張蠙','唐','御定全唐诗','yuding','','[]','四方騷動一州安，夜列樽罍伴客歡。觱栗調高山閣迥，',40,'御定全唐詩/json/702.json','["四方騷動一州安，夜列樽罍伴客歡。觱栗調高山閣迥，", "沈醉不愁歸棹遠，晚風吹上子陵灘。"]'),
('yuding-76','送薛郎中赴江州','張蠙','唐','御定全唐诗','yuding','','[]','幾州聞出刺，謠美有江民。正面傳天旨，懸心禱嶽神。',96,'御定全唐詩/json/702.json','["幾州聞出刺，謠美有江民。正面傳天旨，懸心禱嶽神。", "尺書先假路，紅旆旋燒塵。郡顯山川別，衙開將吏新。", "散招僧坐暑，閑載客行春。聽事棋忘著，探題酒亂巡。", "好編高隱傳，多貌上升真。近日居清近，求人在此人。"]'),
('yuding-77','送南海僧游蜀','張蠙','唐','御定全唐诗','yuding','','[]','真修絕故鄉，一衲度暄涼。此世能先覺，他生豈再忘。',72,'御定全唐詩/json/702.json','["真修絕故鄉，一衲度暄涼。此世能先覺，他生豈再忘。", "定中船過海，臘後路沿湘。野迥鴉隨笠，山深虎背囊。", "瀑流垂石室，蘿蔓蓋銅梁。卻後何年會，西方有上房。"]'),
('yuding-78','和友人許裳題宣平裏古藤','張蠙','唐','御定全唐诗','yuding','','[]','欲結千年茂，生來便近松。迸根通井潤，交葉覆庭穠。',120,'御定全唐詩/json/702.json','["欲結千年茂，生來便近松。迸根通井潤，交葉覆庭穠。", "歷代頻更主，盤空漸變龍。晝風圓影亂，宵雨細聲重。", "蓋密勝丹桂，層危類遠峰。嫩條懸野鼠，枯節叫秋蛩。", "翠老霜難蝕，皴多蘚乍封。幾家遙共玩，何寺不堪容。", "客對忘離榻，僧看誤過鐘。頃因陪預作，終夕繞枝筇。"]'),
('yuding-79','十五夜與友人對月','張蠙','唐','御定全唐诗','yuding','','[]','每到月圓思共醉，不宜同醉不成歡。',32,'御定全唐詩/json/702.json','["每到月圓思共醉，不宜同醉不成歡。", "一千二百如輪夜，浮世誰能得盡看。"]'),
('yuding-80','青塚','張蠙','唐','御定全唐诗','yuding','','[]','傾國可能勝效國，無勞冥寞更思回。',32,'御定全唐詩/json/702.json','["傾國可能勝效國，無勞冥寞更思回。", "太真雖是承恩死，只作飛塵向馬嵬。"]'),
('yuding-81','古戰場','張蠙','唐','御定全唐诗','yuding','','[]','荒骨潛銷壘已平，漢家曾說此交兵。',32,'御定全唐詩/json/702.json','["荒骨潛銷壘已平，漢家曾說此交兵。", "如何萬古冤魂在，風雨時聞有戰聲。"]'),
('yuding-82','贈段逸人','張蠙','唐','御定全唐诗','yuding','','[]','長筇自擔藥兼琴，話著名山即擬尋。',32,'御定全唐詩/json/702.json','["長筇自擔藥兼琴，話著名山即擬尋。", "從聽世人權似火，不能燒得臥雲心。"]'),
('yuding-83','贈鄭司業','張蠙','唐','御定全唐诗','yuding','','[]','晚學更求來世達，正懷非與百邪侵。',32,'御定全唐詩/json/702.json','["晚學更求來世達，正懷非與百邪侵。", "古人名在今人口，不合於名不苦心。"]'),
('yuding-84','上所知','張蠙','唐','御定全唐诗','yuding','','[]','初向眾中留姓氏，敢期言下致時名。',32,'御定全唐詩/json/702.json','["初向眾中留姓氏，敢期言下致時名。", "而今馬亦知人意，每到門前不肯行。"]'),
('yuding-85','別鄭仁表','張蠙','唐','御定全唐诗','yuding','','[]','春雷醉別鏡湖邊，官顯才狂正少年。',32,'御定全唐詩/json/702.json','["春雷醉別鏡湖邊，官顯才狂正少年。", "紅燭滿汀歌舞散，美人迎上木蘭船。"]'),
('yuding-86','言懷','張蠙','唐','御定全唐诗','yuding','','[]','不將高蓋竟煙塵，自向蓬茅認此身。',32,'御定全唐詩/json/702.json','["不將高蓋竟煙塵，自向蓬茅認此身。", "唐祖本來成大業，豈非姚宋是平人。"]'),
('yuding-87','敘懷','張蠙','唐','御定全唐诗','yuding','','[]','月裏路從何處上，江邊身合幾時歸。',32,'御定全唐詩/json/702.json','["月裏路從何處上，江邊身合幾時歸。", "十年九陌寒風夜，夢掃蘆花絮客衣。"]'),
('yuding-88','抒懷','張蠙','唐','御定全唐诗','yuding','','[]','幾出東堂謝不才，便甘閑望故山回。',32,'御定全唐詩/json/702.json','["幾出東堂謝不才，便甘閑望故山回。", "翻思未是離家久，更有人從外國來。"]'),
('yuding-89','自諷','張蠙','唐','御定全唐诗','yuding','','[]','鹿鳴筵上強稱賢，一送離家十四年。',32,'御定全唐詩/json/702.json','["鹿鳴筵上強稱賢，一送離家十四年。", "同隱海山燒藥伴，不求丹桂卻登仙。"]'),
('yuding-90','傷賈島','張蠙','唐','御定全唐诗','yuding','','[]','生為明代苦吟身，死作長江一逐臣。',32,'御定全唐詩/json/702.json','["生為明代苦吟身，死作長江一逐臣。", "可是當時少知已，不知知己是何人。"]'),
('yuding-91','再游西山贈許尊師','張蠙','唐','御定全唐诗','yuding','','[]','別後已聞師得道，不期猶在此山頭。',32,'御定全唐詩/json/702.json','["別後已聞師得道，不期猶在此山頭。", "昔時霜鬢今如漆，疑是年光卻倒流。"]'),
('yuding-92','宮詞','張蠙','唐','御定全唐诗','yuding','','[]','日透珠簾見冕旒，六宮爭逐百花球。',32,'御定全唐詩/json/702.json','["日透珠簾見冕旒，六宮爭逐百花球。", "回看不覺君王去，已聽笙歌在遠樓。"]'),
('yuding-93','經範蠡舊居','張蠙','唐','御定全唐诗','yuding','','[]','一變姓名離百越，越城猶在範家無。',32,'御定全唐詩/json/702.json','["一變姓名離百越，越城猶在範家無。", "他人不見扁舟意，卻笑輕生泛五湖。"]'),
('yuding-94','題嘉陵驛','張蠙','唐','御定全唐诗','yuding','','[]','嘉陵路惡石和泥，行到長亭日已西。',32,'御定全唐詩/json/702.json','["嘉陵路惡石和泥，行到長亭日已西。", "獨倚闌幹正惆悵，海棠花裏鷓鴣啼。"]'),
('yuding-95','龜山寺晚望','張蠙','唐','御定全唐诗','yuding','','[]','四面湖光絕路岐，鸊鵜飛起暮鐘時。',32,'御定全唐詩/json/702.json','["四面湖光絕路岐，鸊鵜飛起暮鐘時。", "漁舟不用懸帆席，歸去乘風插柳枝。"]'),
('yuding-96','華山孤松','張蠙','唐','御定全唐诗','yuding','','[]','石罅引根非土力，冒寒猶助嶽蓮光。',32,'御定全唐詩/json/702.json','["石罅引根非土力，冒寒猶助嶽蓮光。", "綠槐生在膏腴地，何得無心拒雪霜。"]'),
('yuding-97','吊萬人塚','張蠙','唐','御定全唐诗','yuding','','[]','兵罷淮邊客路通，亂鴉來去噪寒空。',32,'御定全唐詩/json/702.json','["兵罷淮邊客路通，亂鴉來去噪寒空。", "可憐白骨攢孤塚，盡為將軍覓戰功。"]'),
('yuding-98','送友尉蜀中','張蠙','唐','御定全唐诗','yuding','','[]','故友漢中尉，請為西蜀吟。人家多種橘，風土愛彈琴。',48,'御定全唐詩/json/702.json','["故友漢中尉，請為西蜀吟。人家多種橘，風土愛彈琴。", "水向昆明闊，山通大夏深。理閑無別事，時寄一登臨。"]'),
('yuding-99','長安寓懷','張蠙','唐','御定全唐诗','yuding','','[]','九衢秋雨掩閑扉，不似幹名似息機。',32,'御定全唐詩/json/702.json','["九衢秋雨掩閑扉，不似幹名似息機。", "貧病卻慚牆上土，年來猶自換新衣。"]'),
('yuding-100','費征君舊居','張蠙','唐','御定全唐诗','yuding','','[]','浮世拋身外，棲蹤入九華。遺篇補樂府，舊籍隸仙家。',48,'御定全唐詩/json/702.json','["浮世拋身外，棲蹤入九華。遺篇補樂府，舊籍隸仙家。", "池靜龜升樹，庭荒鶴隱花。古來天子命，還少到煙霞。"]'),
('yuding-0','晨興','翁承贊','唐','御定全唐诗','yuding','','[]','晨起竹軒外，逍遙清興多。早涼生戶牖，孤月照關河。',48,'御定全唐詩/json/703.json','["晨起竹軒外，逍遙清興多。早涼生戶牖，孤月照關河。", "旅食甘藜藿，歸心憶薜蘿。一尊如有地，放意且狂歌。"]'),
('yuding-1','題莒潭安閩院','翁承贊','唐','御定全唐诗','yuding','','[]','祧宗營祀舍，幽異勝珠林。名士穿雲訪，飛禽傍竹吟。',48,'御定全唐詩/json/703.json','["祧宗營祀舍，幽異勝珠林。名士穿雲訪，飛禽傍竹吟。", "窗含孤岫影，牧臥斷霞陰。景福滋閩壤，芳名亙古今。"]'),
('yuding-2','華下霽後曉眺','翁承贊','唐','御定全唐诗','yuding','','[]','結茅幽寂近禪林，霽景煙光著柳陰。千嶂華山雲外秀，',40,'御定全唐詩/json/703.json','["結茅幽寂近禪林，霽景煙光著柳陰。千嶂華山雲外秀，", "花畔水邊人不會，騰騰閒步一披襟。"]'),
('yuding-3','喜弟承檢登科','翁承贊','唐','御定全唐诗','yuding','','[]','兩篇佳句敵瓊瑰，憐我三清道路開。荊璞獻多還得售，',40,'御定全唐詩/json/703.json','["兩篇佳句敵瓊瑰，憐我三清道路開。荊璞獻多還得售，", "知爾苦心功業就，早攜長策出山來。"]'),
('yuding-4','蒙閩王改賜鄉里','翁承贊','唐','御定全唐诗','yuding','','[]','鄉名文秀裏光賢，別向鈞台造化權。閥閱便因今日貴，',40,'御定全唐詩/json/703.json','["鄉名文秀裏光賢，別向鈞台造化權。閥閱便因今日貴，", "歸闕路遙心更切，不嫌扶病倚旌旃。"]'),
('yuding-5','訪建陽馬驛僧亞齊','翁承贊','唐','御定全唐诗','yuding','','[]','蕭蕭風雨建陽溪，溪畔維舟訪亞齊。一軸新詩劍潭北，',40,'御定全唐詩/json/703.json','["蕭蕭風雨建陽溪，溪畔維舟訪亞齊。一軸新詩劍潭北，", "應笑乘軺青瑣客，此時無暇聽猿啼。"]'),
('yuding-6','題景祥院','翁承贊','唐','御定全唐诗','yuding','','[]','一溪拖碧繞崔嵬，瓶缽偏宜向此隈。農罷樹陰黃犢臥，',40,'御定全唐詩/json/703.json','["一溪拖碧繞崔嵬，瓶缽偏宜向此隈。農罷樹陰黃犢臥，", "三卷貝多金粟語，可能心煉得成灰。"]'),
('yuding-7','寄舍弟承裕員外','翁承贊','唐','御定全唐诗','yuding','','[]','江花岸草晚萋萋，公子王孫思合迷。無主園林饒採伐，',40,'御定全唐詩/json/703.json','["江花岸草晚萋萋，公子王孫思合迷。無主園林饒採伐，", "何事斜陽再回首，休愁離別峴山西。"]'),
('yuding-8','文明殿受冊封閩王','翁承贊','唐','御定全唐诗','yuding','','[]','龍墀班聽漏聲長，竹帛昭勳撲禦香。鳴佩洞庭辭帝主，',40,'御定全唐詩/json/703.json','["龍墀班聽漏聲長，竹帛昭勳撲禦香。鳴佩洞庭辭帝主，", "吟寄短篇追往事，留文功業不尋常。"]'),
('yuding-9','禦命歸鄉，蒙賜錦衣','翁承贊','唐','御定全唐诗','yuding','','[]','九重宣旨下丹墀，面對天顏賜錦衣。中使擎來三殿曉，',40,'御定全唐詩/json/703.json','["九重宣旨下丹墀，面對天顏賜錦衣。中使擎來三殿曉，", "更待臨軒陳鼓吹，星軺便指故鄉歸。"]'),
('yuding-10','奉使封閩王歸京洛','翁承贊','唐','御定全唐诗','yuding','','[]','泥緘紫誥禦恩光，信馬嘶風出洛陽。此去願言歸梓裏，',40,'御定全唐詩/json/703.json','["泥緘紫誥禦恩光，信馬嘶風出洛陽。此去願言歸梓裏，", "指日還家堪自重，恩榮晝錦賀封王。"]'),
('yuding-11','奉使封王，次宜春驛','翁承贊','唐','御定全唐诗','yuding','','[]','微宦淹留鬢已斑，此心長憶舊林泉。不因列土封千乘，',40,'御定全唐詩/json/703.json','["微宦淹留鬢已斑，此心長憶舊林泉。不因列土封千乘，", "夜來夢到南臺上，遍看江山勝往年。"]'),
('yuding-12','甲子歲銜命到家至榕城冊封次日閩王降旌旗于新豐…餞別','翁承贊','唐','御定全唐诗','yuding','','[]','登庸樓上方停樂，新市堤邊又舉杯。正是離情傷遠別，',40,'御定全唐詩/json/703.json','["登庸樓上方停樂，新市堤邊又舉杯。正是離情傷遠別，", "爭得長房猶在世，縮教地近釣魚臺。"]'),
('yuding-13','寄示兒孫','翁承贊','唐','御定全唐诗','yuding','','[]','力學燒丹二十年，辛勤方得遇真仙。便隨羽客歸三島，',40,'御定全唐詩/json/703.json','["力學燒丹二十年，辛勤方得遇真仙。便隨羽客歸三島，", "予家藥鼎分明在，好把仙方次第傳。"]'),
('yuding-14','天佑元年以右拾遺使冊閩王而作','翁承贊','唐','御定全唐诗','yuding','','[]','蓬萊宮闕曉光勻，紅案舁麻降紫宸。鸞奏八音諧律呂，',40,'御定全唐詩/json/703.json','["蓬萊宮闕曉光勻，紅案舁麻降紫宸。鸞奏八音諧律呂，", "得侍丹墀官異寵，此身何幸沐恩頻。"]'),
('yuding-15','漢上登舟憶閩','翁承贊','唐','御定全唐诗','yuding','','[]','漢皋亭畔起西風，半掛征帆立向東。久客自憐歸路近，',40,'御定全唐詩/json/703.json','["漢皋亭畔起西風，半掛征帆立向東。久客自憐歸路近，", "一片歸心隨去棹，願言指日拜文翁。"]'),
('yuding-16','對雨述懷示弟承檢','翁承贊','唐','御定全唐诗','yuding','','[]','淋淋霎霎結秋霖，欲使秦城歎陸沈。曉勢遮回朝客馬，',40,'御定全唐詩/json/703.json','["淋淋霎霎結秋霖，欲使秦城歎陸沈。曉勢遮回朝客馬，", "不有惠連同此景，江南歸思幾般深。"]'),
('yuding-17','題壺山','翁承贊','唐','御定全唐诗','yuding','','[]','井邑斜連北，蓬瀛直倚東。秋高岩溜白，日上海波紅。',24,'御定全唐詩/json/703.json','["井邑斜連北，蓬瀛直倚東。秋高岩溜白，日上海波紅。"]'),
('yuding-18','題故居','翁承贊','唐','御定全唐诗','yuding','','[]','一為鵝子二連花，三望青湖四石斜。',32,'御定全唐詩/json/703.json','["一為鵝子二連花，三望青湖四石斜。", "惟有嶺湖居第五，山前卻是宰臣家。"]'),
('yuding-19','題槐','翁承贊','唐','御定全唐诗','yuding','','[]','雨中妝點望中黃，句引蟬聲送夕陽。',32,'御定全唐詩/json/703.json','["雨中妝點望中黃，句引蟬聲送夕陽。", "憶昔當年隨計吏，馬蹄終日為君忙。"]'),
('yuding-20','擢進士','翁承贊','唐','御定全唐诗','yuding','','[]','霓旌引上大羅天，別領新銜意自憐。',32,'御定全唐詩/json/703.json','["霓旌引上大羅天，別領新銜意自憐。", "蝴蝶流鶯莫先去，滿城春色屬群仙。"]'),
('yuding-21','擢探花使三首','翁承贊','唐','御定全唐诗','yuding','','[]','洪崖差遣探花來，檢點芳叢飲數杯。',96,'御定全唐詩/json/703.json','["洪崖差遣探花來，檢點芳叢飲數杯。", "深紫濃香三百朵，明朝為我一時開。", "九重煙暖折槐芽，自是升平好物華。", "今日始知春氣味，長安虛過四年花。", "探花時節日偏長，恬淡春風稱意忙。", "每到黃昏醉歸去，紵衣惹得牡丹香。"]'),
('yuding-22','書齋謾興二首','翁承贊','唐','御定全唐诗','yuding','','[]','池塘四五尺深水，籬落兩三般樣花。',64,'御定全唐詩/json/703.json','["池塘四五尺深水，籬落兩三般樣花。", "過客不須頻問姓，讀書聲裏是吾家。", "官事歸來衣雪埋，兒童燈火小茅齋。", "人家不必論貧富，惟有讀書聲最佳。"]'),
('yuding-23','辭閩王歸朝寄倪先輩','翁承贊','唐','御定全唐诗','yuding','','[]','時人莫訝再還鄉，簡冊分明劍佩光。',32,'御定全唐詩/json/703.json','["時人莫訝再還鄉，簡冊分明劍佩光。", "駟馬高車太常樂，登庸門下憶賢良。"]'),
('yuding-24','曉望','翁承贊','唐','御定全唐诗','yuding','','[]','清霜散漫似輕嵐，玉闕參差萬象涵。',32,'御定全唐詩/json/703.json','["清霜散漫似輕嵐，玉闕參差萬象涵。", "獨上秦台最高處，舊山依約在東南。"]'),
('yuding-25','萬壽寺牡丹','翁承贊','唐','御定全唐诗','yuding','','[]','爛熳香風引貴游，高僧移步亦遲留。',32,'御定全唐詩/json/703.json','["爛熳香風引貴游，高僧移步亦遲留。", "可憐殿角長松色，不得王孫一舉頭。"]'),
('yuding-26','松','翁承贊','唐','御定全唐诗','yuding','','[]','倚澗臨溪自屈蟠，雪花銷盡蘚花幹。',32,'御定全唐詩/json/703.json','["倚澗臨溪自屈蟠，雪花銷盡蘚花幹。", "幽枝好折為談柄，入手方知有歲寒。"]'),
('yuding-27','柳','翁承贊','唐','御定全唐诗','yuding','','[]','斜拂中橋遠映樓，翠光駘蕩曉煙收。',160,'御定全唐詩/json/703.json','["斜拂中橋遠映樓，翠光駘蕩曉煙收。", "洛陽才子多情思，橫把金鞭約馬頭。", "高出營門遠出牆，朱闌門閉綠成行。", "將軍宴罷東風急，閑襯旌旗簇畫堂。", "彭澤先生酒滿船，五株栽向九江邊。", "長條細葉無窮盡，管領春風不計年。", "煬帝東遊意緒多，宮娃眉翠兩相和。", "一聲水調春風暮，千里交陰鎖汴河。", "纏繞春情卒未休，秦娥蕭史兩相求。", "玉句闌內朱簾卷，瑟瑟絲籠十二樓。"]'),
('yuding-28','隋堤柳','翁承贊','唐','御定全唐诗','yuding','','[]','春半煙深汴水東，黃金絲軟不勝風。',32,'御定全唐詩/json/703.json','["春半煙深汴水東，黃金絲軟不勝風。", "輕籠行殿迷天子，拋擲長安似夢中。"]'),
('yuding-29','句','翁承贊','唐','御定全唐诗','yuding','','[]','煙蘿況逼神仙窟，丹灶還應許獨尋。（《贈黃璞》，',23,'御定全唐詩/json/703.json','["煙蘿況逼神仙窟，丹灶還應許獨尋。（《贈黃璞》，"]'),
('yuding-0','送僧歸北岩寺','黃滔','唐','御定全唐诗','yuding','','[]','北岩泉石清，本自高僧住。新松五十年，藤蘿成古樹。',120,'御定全唐詩/json/704.json','["北岩泉石清，本自高僧住。新松五十年，藤蘿成古樹。", "題詩昔佳士，清風二林喻。上智失扣關，多被浮名誤。", "蓮扃壓月澗，空美黃金布。江翻島嶼沈，木落樓臺露。", "伊餘東還際，每起煙霞慕。旋為儉府招，未得窮野步。", "西軒白雲閣，師辭洞庭寓。越城今送歸，心到焚香處。"]'),
('yuding-1','寓言','黃滔','唐','御定全唐诗','yuding','','[]','流年五十前，朝朝倚少年。流年五十後，日日侵皓首。',48,'御定全唐詩/json/704.json','["流年五十前，朝朝倚少年。流年五十後，日日侵皓首。", "非通非介人，誰論四十九。賢哉蘧伯玉，清風獨不朽。"]'),
('yuding-2','長安書事','黃滔','唐','御定全唐诗','yuding','','[]','終不離青山，誰道雲無心。卻是白雲士，有時出中林。',60,'御定全唐詩/json/704.json','["終不離青山，誰道雲無心。卻是白雲士，有時出中林。", "昨日擎紫泥，明日要黃金。炎夏群木死，北海驚波深。", "伏蒲無一言，草疏賀德音。"]'),
('yuding-3','賈客','黃滔','唐','御定全唐诗','yuding','','[]','大舟有深利，滄海無淺波。利深波也深，君意竟如何。',36,'御定全唐詩/json/704.json','["大舟有深利，滄海無淺波。利深波也深，君意竟如何。", "鯨鯢齒上路，何如少經過。"]'),
('yuding-4','寄友人','黃滔','唐','御定全唐诗','yuding','','[]','君愛桃李花，桃李花易飄。妾憐松柏色，松柏色難凋。',60,'御定全唐詩/json/704.json','["君愛桃李花，桃李花易飄。妾憐松柏色，松柏色難凋。", "當年識君初，指期非一朝。今辰見君意，日暮何蕭條。", "入門有勢利，孰能無囂囂。"]'),
('yuding-5','落花','黃滔','唐','御定全唐诗','yuding','','[]','落花辭高樹，最是愁人處。一一旋成泥，日暮有風雨。',48,'御定全唐詩/json/704.json','["落花辭高樹，最是愁人處。一一旋成泥，日暮有風雨。", "不如沙上蓬，根斷隨長風。飄然與道俱，無情任西東。"]'),
('yuding-6','寄徐正字夤','黃滔','唐','御定全唐诗','yuding','','[]','八月月如冰，登樓見姑射。美人隔千里，相思無羽駕。',48,'御定全唐詩/json/704.json','["八月月如冰，登樓見姑射。美人隔千里，相思無羽駕。", "紅蘭裛露衰，誰以流光訝。何當詩一句，同吟祝玄化。"]'),
('yuding-7','秋夕貧居','黃滔','唐','御定全唐诗','yuding','','[]','聽歌桂席闌，下馬槐煙裏。豪門腐粱肉，窮巷思糠秕。',48,'御定全唐詩/json/704.json','["聽歌桂席闌，下馬槐煙裏。豪門腐粱肉，窮巷思糠秕。", "孤燈照獨吟，半壁秋花死。遲明亦如晦，雞唱徒為爾。"]'),
('yuding-8','書懷寄友人','黃滔','唐','御定全唐诗','yuding','','[]','此生如孤燈，素心挑易盡。不及如頑石，非與磨礱近。',48,'御定全唐詩/json/704.json','["此生如孤燈，素心挑易盡。不及如頑石，非與磨礱近。", "常思揚子雲，五藏曾離身。寂寞一生中，千載空清芬。"]'),
('yuding-9','閨怨','黃滔','唐','御定全唐诗','yuding','','[]','妾家五嶺南，君戍三城北。雁來雖有書，衡陽越不得。',48,'御定全唐詩/json/704.json','["妾家五嶺南，君戍三城北。雁來雖有書，衡陽越不得。", "別久情易料，豈在窺翰墨。塞上無煙花，寧思妾顏色。"]'),
('yuding-10','喜翁文堯員外病起','黃滔','唐','御定全唐诗','yuding','','[]','衛玠羊車懸，長卿駟馬姿。天嫌太端正，神乃減風儀。',120,'御定全唐詩/json/704.json','["衛玠羊車懸，長卿駟馬姿。天嫌太端正，神乃減風儀。", "飲冰俾消渴，斷穀皆清羸。越僧誇艾炷，秦女隔花枝。", "自能論苦器，不假求良醫。驚殺漳濱鬼，錯與劉生隨。", "昨日已如虎，今朝謁荀池。揚鞭入王門，四面人熙熙。", "青桂任霜霰，尺璧無瑕疵。回塵卻惆悵，歸闕難遲遲。"]'),
('yuding-11','寄鄭縣李侍禦','黃滔','唐','御定全唐诗','yuding','','[]','古縣新煙火，東西入客詩。靜長如假日，貧更甚閒時。',48,'御定全唐詩/json/704.json','["古縣新煙火，東西入客詩。靜長如假日，貧更甚閒時。", "僧借松蘿住，人將雨雪期。三年一官罷，岳石看成碑。"]'),
('yuding-12','上李補闕','黃滔','唐','御定全唐诗','yuding','','[]','十洲非暫別，龍尾肯慵登。諫草封山藥，朝衣施衲僧。',48,'御定全唐詩/json/704.json','["十洲非暫別，龍尾肯慵登。諫草封山藥，朝衣施衲僧。", "月留江客待，句曆釣船征。終恐林棲去，餐霞葉上升。"]'),
('yuding-13','送李山人往湘中','黃滔','唐','御定全唐诗','yuding','','[]','漢渚往湘川，乘流入遠天。新秋無岸水，明月有琴船。',48,'御定全唐詩/json/704.json','["漢渚往湘川，乘流入遠天。新秋無岸水，明月有琴船。", "露坐應通曉，萍居恐來年。嶽峰千萬仞，知上嘯猿巔。"]'),
('yuding-14','書崔少府居','黃滔','唐','御定全唐诗','yuding','','[]','魯史蜀琴旁，陶然舉一觴。夕陽明島嶼，秋水淺池塘。',48,'御定全唐詩/json/704.json','["魯史蜀琴旁，陶然舉一觴。夕陽明島嶼，秋水淺池塘。", "世亂憐官替，家貧值歲荒。前峰亦曾宿，知有辟寒方。"]'),
('yuding-15','敷水盧校書','黃滔','唐','御定全唐诗','yuding','','[]','九霄無詔下，何事近清塵。宅帶松蘿僻，日唯猿鳥親。',48,'御定全唐詩/json/704.json','["九霄無詔下，何事近清塵。宅帶松蘿僻，日唯猿鳥親。", "吟高仙掌月，期有洞庭人。莫問煙霞句，懸知見嶽神。"]'),
('yuding-16','寄漢上友人','黃滔','唐','御定全唐诗','yuding','','[]','襄漢多清景，東遊已不能。蒹葭照流水，風雨撲孤燈。',48,'御定全唐詩/json/704.json','["襄漢多清景，東遊已不能。蒹葭照流水，風雨撲孤燈。", "獻賦聞新雁，思山見去僧。知君北來日，惆悵亦難勝。"]'),
('yuding-17','貽林鐸','黃滔','唐','御定全唐诗','yuding','','[]','終被春闈屈，低回至白頭。寄家僧許嶽，釣浦雨移洲。',48,'御定全唐詩/json/704.json','["終被春闈屈，低回至白頭。寄家僧許嶽，釣浦雨移洲。", "戰士曾憐善，豪門不信愁。王孫草還綠，何處擬羈遊。"]'),
('yuding-18','書懷','黃滔','唐','御定全唐诗','yuding','','[]','退耕逢歉歲，逐貢愧行朝。道在愁雖淺，吟勞鬢欲凋。',48,'御定全唐詩/json/704.json','["退耕逢歉歲，逐貢愧行朝。道在愁雖淺，吟勞鬢欲凋。", "破村虹入井，孤館客投魈。誰怕秋風起，聽蟬度渭橋。"]'),
('yuding-19','送陳明府歸衡陽','黃滔','唐','御定全唐诗','yuding','','[]','雛鶴兼留下，單車出柳煙。三年兩殊考，一日數離筵。',48,'御定全唐詩/json/704.json','["雛鶴兼留下，單車出柳煙。三年兩殊考，一日數離筵。", "久別湖波綠，相思嶽月圓。翠蘿曾隱處，定恐卻求仙。"]'),
('yuding-20','秋辭江南','黃滔','唐','御定全唐诗','yuding','','[]','灞陵橋上路，難負一年期。積雨鴻來夜，重江客去時。',48,'御定全唐詩/json/704.json','["灞陵橋上路，難負一年期。積雨鴻來夜，重江客去時。", "勞生多故疾，漸老少新知。惆悵都堂內，無門雪滯遺。"]'),
('yuding-21','入關旅次言懷','黃滔','唐','御定全唐诗','yuding','','[]','寸心唯自切，上國與誰期。月晦時風雨，秋深日別離。',48,'御定全唐詩/json/704.json','["寸心唯自切，上國與誰期。月晦時風雨，秋深日別離。", "便休終未肯，已苦不能疑。獨愧商山路，千年四皓祠。"]'),
('yuding-22','貽李山人','黃滔','唐','御定全唐诗','yuding','','[]','野步愛江濱，江僧得見頻。新文無古集，往事有清塵。',48,'御定全唐詩/json/704.json','["野步愛江濱，江僧得見頻。新文無古集，往事有清塵。", "松竹寒時雨，池塘勝處春。定應雲雨內，陶謝是前身。"]'),
('yuding-23','寄邊上從事','黃滔','唐','御定全唐诗','yuding','','[]','斜日下孤城，長吟出點兵。羽書和客卷，邊思雜詩情。',48,'御定全唐詩/json/704.json','["斜日下孤城，長吟出點兵。羽書和客卷，邊思雜詩情。", "朔雪定鴻翼，西風嚴角聲。吟餘多獨坐，沙月對樓生。"]'),
('yuding-24','題東林寺元佑上人院','黃滔','唐','御定全唐诗','yuding','','[]','廬阜東林寺，良遊恥未曾。半生隨計吏，一日對禪僧。',48,'御定全唐詩/json/704.json','["廬阜東林寺，良遊恥未曾。半生隨計吏，一日對禪僧。", "泉遠攜茶看，峰高結伴登。迷津出門是，子細問三乘。"]'),
('yuding-25','送陳樵下第東歸','黃滔','唐','御定全唐诗','yuding','','[]','青山烹茗石，滄海寄家船。雖得重吟曆，終難任意眠。',48,'御定全唐詩/json/704.json','["青山烹茗石，滄海寄家船。雖得重吟曆，終難任意眠。", "砧疏連寺柳，風爽徹城泉。送目紅蕉外，來期已杳然。"]'),
('yuding-26','寄陳磻隱居','黃滔','唐','御定全唐诗','yuding','','[]','道經前輩許，名拔後時喧。虛左中興榜，無先北海尊。',48,'御定全唐詩/json/704.json','["道經前輩許，名拔後時喧。虛左中興榜，無先北海尊。", "新文漢氏史，別墅謝公村。須到三征處，堂堂謁帝閽。"]'),
('yuding-27','寄林寬','黃滔','唐','御定全唐诗','yuding','','[]','相知四十年，故國與長安。俱喜今辰在，休論往歲難。',48,'御定全唐詩/json/704.json','["相知四十年，故國與長安。俱喜今辰在，休論往歲難。", "海鳴秋日黑，山直夏風寒。終始前儒道，升沈盡一般。"]'),
('yuding-28','退居','黃滔','唐','御定全唐诗','yuding','','[]','老歸江上村，孤寂欲何言。世亂時人物，家貧後子孫。',48,'御定全唐詩/json/704.json','["老歸江上村，孤寂欲何言。世亂時人物，家貧後子孫。", "青山寒帶雨，古木夜啼猿。惆悵西川舉，戎裝度劍門。"]'),
('yuding-29','送友人邊游','黃滔','唐','御定全唐诗','yuding','','[]','銜杯國門外，分手見殘陽。何日還南越，今朝往北荒。',48,'御定全唐詩/json/704.json','["銜杯國門外，分手見殘陽。何日還南越，今朝往北荒。", "砂城經雨壞，虜騎入秋狂。親詠關山月，歸吟鬢的霜。"]'),
('yuding-30','下第出京','黃滔','唐','御定全唐诗','yuding','','[]','還失禮官求，花時出雍州。一生為遠客，幾處未曾遊。',48,'御定全唐詩/json/704.json','["還失禮官求，花時出雍州。一生為遠客，幾處未曾遊。", "故疾江南雨，單衣薊北秋。茫茫數年事，今日淚俱流。"]'),
('yuding-31','游東林寺','黃滔','唐','御定全唐诗','yuding','','[]','平生愛山水，下馬虎溪時。已到終嫌晚，重遊預作期。',48,'御定全唐詩/json/704.json','["平生愛山水，下馬虎溪時。已到終嫌晚，重遊預作期。", "寺寒三伏雨，松偃數朝枝。翻譯如曾見，白蓮開舊池。"]'),
('yuding-32','贈懷光上人','黃滔','唐','御定全唐诗','yuding','','[]','謝城還擁入，師以接人勞。過午休齋慣，離經吐論高。',48,'御定全唐詩/json/704.json','["謝城還擁入，師以接人勞。過午休齋慣，離經吐論高。", "頂寒拳素發，珠銳走紅絛。終憶泉山寺，聽猿看海濤。"]'),
('yuding-33','憶廬山舊游','黃滔','唐','御定全唐诗','yuding','','[]','前年入廬嶽，數宿在靈溪。殘燭松堂掩，孤峰月狖啼。',48,'御定全唐詩/json/704.json','["前年入廬嶽，數宿在靈溪。殘燭松堂掩，孤峰月狖啼。", "平生為客老，勝境失雲棲。縱有重游日，煙霞會恐迷。"]'),
('yuding-34','別友人','黃滔','唐','御定全唐诗','yuding','','[]','莫恨東牆下，頻傷命不通。苦心如有感，他日自推公。',48,'御定全唐詩/json/704.json','["莫恨東牆下，頻傷命不通。苦心如有感，他日自推公。", "雨夜扁舟發，花時別酒空。越山煙翠在，終愧臥雲翁。"]'),
('yuding-35','陳侍禦新居','黃滔','唐','御定全唐诗','yuding','','[]','幕客開新第，詞人遍有詩。山憐九仙近，石買太湖奇。',48,'御定全唐詩/json/704.json','["幕客開新第，詞人遍有詩。山憐九仙近，石買太湖奇。", "樹勢想高日，地形誇得時。自然成避俗，休與白雲期。"]'),
('yuding-36','寄從兄璞','黃滔','唐','御定全唐诗','yuding','','[]','縱征終不起，相與避煙塵。待到中興日，同看上國春。',48,'御定全唐詩/json/704.json','["縱征終不起，相與避煙塵。待到中興日，同看上國春。", "新詩說人盡，舊宅落花頻。移覓深山住，啼猿作四鄰。"]'),
('yuding-37','寄李校書游簡寂觀','黃滔','唐','御定全唐诗','yuding','','[]','古觀雲溪上，孤懷永夜中。梧桐四更雨，山水一庭風。',48,'御定全唐詩/json/704.json','["古觀雲溪上，孤懷永夜中。梧桐四更雨，山水一庭風。", "詩得如何句，仙游最勝宮。卻愁逢羽客，相與入煙空。"]'),
('yuding-38','寄友人山居','黃滔','唐','御定全唐诗','yuding','','[]','斷嶠滄江上，相思恨阻尋。高齋秋不掩，幾夜月當吟。',48,'御定全唐詩/json/704.json','["斷嶠滄江上，相思恨阻尋。高齋秋不掩，幾夜月當吟。", "落石有泉滴，盈庭無樹陰。茫茫名利內，何以拂塵襟。"]'),
('yuding-39','上刑部盧員外','黃滔','唐','御定全唐诗','yuding','','[]','誰識在官意，開門樹色間。尋幽頻宿寺，乞假擬歸山。',48,'御定全唐詩/json/704.json','["誰識在官意，開門樹色間。尋幽頻宿寺，乞假擬歸山。", "半白侵吟鬢，微紅見藥顏。不知琴月夜，幾客得同閑。"]'),
('yuding-40','送友人游邊','黃滔','唐','御定全唐诗','yuding','','[]','虜酒不能濃，縱傾愁亦重。關河初落日，霜雪下窮冬。',48,'御定全唐詩/json/704.json','["虜酒不能濃，縱傾愁亦重。關河初落日，霜雪下窮冬。", "野燒枯蓬旋，沙風匹馬沖。薊門無易過，千里斷人蹤。"]'),
('yuding-41','和友人酬寄','黃滔','唐','御定全唐诗','yuding','','[]','新發煙霞詠，高人得以傳。吟銷松際雨，冷咽石間泉。',48,'御定全唐詩/json/704.json','["新發煙霞詠，高人得以傳。吟銷松際雨，冷咽石間泉。", "大國兵戈日，故鄉饑饉年。相逢江海上，寧免一潸然。"]'),
('yuding-42','下第','黃滔','唐','御定全唐诗','yuding','','[]','昨夜孤燈下，闌幹泣數行。辭家從早歲，落第在初場。',48,'御定全唐詩/json/704.json','["昨夜孤燈下，闌幹泣數行。辭家從早歲，落第在初場。", "青草湖田改，單車客路忙。何人立功業，新命到封王。"]'),
('yuding-43','過商山','黃滔','唐','御定全唐诗','yuding','','[]','燕雁一來後，人人盡到關。如何沖臘雪，獨自過商山。',48,'御定全唐詩/json/704.json','["燕雁一來後，人人盡到關。如何沖臘雪，獨自過商山。", "羸馬高坡下，哀猿絕壁間。此心無處說，鬢向少年斑。"]'),
('yuding-44','旅懷','黃滔','唐','御定全唐诗','yuding','','[]','蕭颯聞風葉，驚時不自堪。宦名中夜切，人事長年諳。',48,'御定全唐詩/json/704.json','["蕭颯聞風葉，驚時不自堪。宦名中夜切，人事長年諳。", "古畫僧留與，新知客遇談。鄉心隨去雁，一一到江南。"]'),
('yuding-45','冬暮山舍喜標上人見訪','黃滔','唐','御定全唐诗','yuding','','[]','寂寞三冬杪，深居業盡拋。徑鬆開雪後，砌竹忽僧敲。',48,'御定全唐詩/json/704.json','["寂寞三冬杪，深居業盡拋。徑鬆開雪後，砌竹忽僧敲。", "茗汲冰銷溜，爐燒鵲去巢。共談慵僻意，微日下林梢。"]'),
('yuding-46','關中言懷','黃滔','唐','御定全唐诗','yuding','','[]','三秦五嶺意，不得不依然。跡寓枯槐曲，業蕪芳草川。',48,'御定全唐詩/json/704.json','["三秦五嶺意，不得不依然。跡寓枯槐曲，業蕪芳草川。", "花當落第眼，雨暗出城天。層閣浮雲外，何人動管弦。"]'),
('yuding-47','題友人山居','黃滔','唐','御定全唐诗','yuding','','[]','到君棲跡所，竹徑與衡門。亦在乾坤內，獨無塵俗喧。',48,'御定全唐詩/json/704.json','["到君棲跡所，竹徑與衡門。亦在乾坤內，獨無塵俗喧。", "新泉浮石蘚，崩壁露松根。更說尋僧處，孤峰上嘯猿。"]'),
('yuding-48','寄敷水盧校書','黃滔','唐','御定全唐诗','yuding','','[]','諫省垂清論，仙曹豈久臨。雖專良史業，未畏直臣心。',48,'御定全唐詩/json/704.json','["諫省垂清論，仙曹豈久臨。雖專良史業，未畏直臣心。", "路入丹霄近，家藏華嶽深。還如韓吏部，誰不望知音。"]'),
('yuding-49','贈明州霍員外','黃滔','唐','御定全唐诗','yuding','','[]','惠化如施雨，鄰州亦可依。正衙無吏近，高會覺人稀。',48,'御定全唐詩/json/704.json','["惠化如施雨，鄰州亦可依。正衙無吏近，高會覺人稀。", "海日旗邊出，沙禽角外歸。四明多隱客，閑約到岩扉。"]'),
('yuding-50','題友人山齋','黃滔','唐','御定全唐诗','yuding','','[]','疏竹漏斜暉，庭間陰複遺。句成苔石茗，吟弄雪窗棋。',48,'御定全唐詩/json/704.json','["疏竹漏斜暉，庭間陰複遺。句成苔石茗，吟弄雪窗棋。", "沙草泉經澀，林齋客集遲。西風虛見逼，未擬問京師。"]'),
('yuding-51','書事','黃滔','唐','御定全唐诗','yuding','','[]','望歲心空切，耕夫盡把弓。千家數人在，一稅十年空。',48,'御定全唐詩/json/704.json','["望歲心空切，耕夫盡把弓。千家數人在，一稅十年空。", "沒陣風沙黑，燒城水陸紅。飛章奏西蜀，明詔與殊功。"]'),
('yuding-52','題山居逸人','黃滔','唐','御定全唐诗','yuding','','[]','十畝餘蘆葦，新秋看雪霜。世人誰到此，塵念自應忘。',48,'御定全唐詩/json/704.json','["十畝餘蘆葦，新秋看雪霜。世人誰到此，塵念自應忘。", "斜日風收釣，深秋雨信梁。不知雙闕下，何以謂軒裳。"]'),
('yuding-53','題鄭山人居','黃滔','唐','御定全唐诗','yuding','','[]','履跡遍莓苔，幽枝間藥裁。枯杉擎雪朵，破牖觸風開。',48,'御定全唐詩/json/704.json','["履跡遍莓苔，幽枝間藥裁。枯杉擎雪朵，破牖觸風開。", "泉自孤峰落，人從諸洞來。終期宿清夜，斟茗說天臺。"]'),
('yuding-54','秋晚山居','黃滔','唐','御定全唐诗','yuding','','[]','爽氣遍搜空，難堪倚望中。孤煙愁落日，高木病西風。',48,'御定全唐詩/json/704.json','["爽氣遍搜空，難堪倚望中。孤煙愁落日，高木病西風。", "山寂樵聲出，露涼蟬思窮。此時塵外事，幽默幾人同。"]'),
('yuding-55','游山','黃滔','唐','御定全唐诗','yuding','','[]','洞門穿瀑布，塵世豈能通。曾有遊山客，來逢采藥翁。',48,'御定全唐詩/json/704.json','["洞門穿瀑布，塵世豈能通。曾有遊山客，來逢采藥翁。", "異花尋複失，幽徑躡還窮。擬作經宵計，風雷立滿空。"]'),
('yuding-56','題王侍禦宅內亭子','黃滔','唐','御定全唐诗','yuding','','[]','俗間塵外境，郭內宅中亭。或有人家創，還無蓮幕馨。',48,'御定全唐詩/json/704.json','["俗間塵外境，郭內宅中亭。或有人家創，還無蓮幕馨。", "石曾湖岸見，琴誤岳樓聽。來客頻頻說，終須作畫屏。"]'),
('yuding-57','題道成上人院','黃滔','唐','御定全唐诗','yuding','','[]','花宮城郭內，師住亦清涼。何必天臺寺，幽禪瀑布房。',48,'御定全唐詩/json/704.json','["花宮城郭內，師住亦清涼。何必天臺寺，幽禪瀑布房。", "簟舒湘竹滑，茗煮蜀芽香。更看道高處，君侯題翠梁。"]'),
('yuding-58','貧居冬杪','黃滔','唐','御定全唐诗','yuding','','[]','數塞未求通，吾非學養蒙。窮居歲杪雨，孤坐夜深風。',48,'御定全唐詩/json/704.json','["數塞未求通，吾非學養蒙。窮居歲杪雨，孤坐夜深風。", "年長慚昭代，才微辱至公。還愁把春酒，雙淚汙杯中。"]'),
('yuding-59','貽張蠙','黃滔','唐','御定全唐诗','yuding','','[]','夢思非一日，攜手卻淒涼。詩見江南雹，遊經塞北霜。',48,'御定全唐詩/json/704.json','["夢思非一日，攜手卻淒涼。詩見江南雹，遊經塞北霜。", "驅車先五漏，把菊後重陽。惆悵天邊桂，誰教歲歲香。"]'),
('yuding-60','晚春關中','黃滔','唐','御定全唐诗','yuding','','[]','忍曆通莊出，東風舞酒旗。百花無看處，三月到殘時。',48,'御定全唐詩/json/704.json','["忍曆通莊出，東風舞酒旗。百花無看處，三月到殘時。", "游塞聞兵起，還吳值歲饑。定唯荒寺裏，坐與噪蟬期。"]'),
('yuding-61','河梁','黃滔','唐','御定全唐诗','yuding','','[]','五原人走馬，昨夜到京師。繡戶新夫婦，河梁生別離。',48,'御定全唐詩/json/704.json','["五原人走馬，昨夜到京師。繡戶新夫婦，河梁生別離。", "隴花開不豔，羌笛靜猶悲。惆悵良哉輔，鏘鏘立鳳池。"]'),
('yuding-62','送翁拾遺','黃滔','唐','御定全唐诗','yuding','','[]','還家俄赴闕，別思肯淒淒。山坐軺車看，詩持諫筆題。',48,'御定全唐詩/json/704.json','["還家俄赴闕，別思肯淒淒。山坐軺車看，詩持諫筆題。", "天開中國大，地設四維低。拜舞吾君後，青雲更有梯。"]'),
('yuding-63','逢友人','黃滔','唐','御定全唐诗','yuding','','[]','彼此若飄蓬，二年何所從。帝都秋未入，江館夜相逢。',48,'御定全唐詩/json/704.json','["彼此若飄蓬，二年何所從。帝都秋未入，江館夜相逢。", "瘴嶺行沖夏，邊沙住隔冬。旅愁論未盡，古寺扣晨鐘。"]'),
('yuding-64','寄湘中鄭明府','黃滔','唐','御定全唐诗','yuding','','[]','縣與白雲連，滄洲況縣前。岳僧同夜坐，江月看秋圓。',48,'御定全唐詩/json/704.json','["縣與白雲連，滄洲況縣前。岳僧同夜坐，江月看秋圓。", "琴拂莎庭石，茶擔乳洞泉。莫耽雲水興，疲俗待君痊。"]'),
('yuding-65','寄少常盧同年','黃滔','唐','御定全唐诗','yuding','','[]','官拜少常休，青緺換鹿裘狂歌離樂府，醉夢到瀛洲。',47,'御定全唐詩/json/704.json','["官拜少常休，青緺換鹿裘狂歌離樂府，醉夢到瀛洲。", "古器岩耕得，神方客謎留。清溪莫沈釣，王者或畋遊。"]'),
('yuding-66','傷翁外甥','黃滔','唐','御定全唐诗','yuding','','[]','江頭去時路，歸客幾紛紛。獨在異鄉歿，若為慈母聞。',48,'御定全唐詩/json/704.json','["江頭去時路，歸客幾紛紛。獨在異鄉歿，若為慈母聞。", "青春成大夜，新雨壞孤墳。應作芝蘭出，泉台月桂分。"]'),
('yuding-67','東山之遊未遂漸逼行期作四十字奉寄翁文堯員外','黃滔','唐','御定全唐诗','yuding','','[]','軺車難久駐，須到別離時。北闕定歸去，東山空作期。',48,'御定全唐詩/json/704.json','["軺車難久駐，須到別離時。北闕定歸去，東山空作期。", "綠苔勞掃徑，丹鳳欲銜詞。楊柳開帆岸，今朝淚已垂。"]'),
('yuding-0','送林寬下第東歸','黃滔','唐','御定全唐诗','yuding','','[]','為君惆悵惜離京，年少無人有屈名。積雪未開移發日，',40,'御定全唐詩/json/705.json','["為君惆悵惜離京，年少無人有屈名。積雪未開移發日，", "又得新詩幾章別，煙村竹徑海濤聲。"]'),
('yuding-1','商山贈隱者','黃滔','唐','御定全唐诗','yuding','','[]','誰不相逢話息機，九重城裏自依依。蓬萊水淺有人說，',40,'御定全唐詩/json/705.json','["誰不相逢話息機，九重城裏自依依。蓬萊水淺有人說，", "西窗昨夜鳴蛩盡，知夢芝翁起扣扉。"]'),
('yuding-2','送二友游湘中','黃滔','唐','御定全唐诗','yuding','','[]','千里楚江新雨晴，同征肯恨跡如萍。孤舟泊處聯詩句，',40,'御定全唐詩/json/705.json','["千里楚江新雨晴，同征肯恨跡如萍。孤舟泊處聯詩句，", "今來無計相從去，歸日汀洲乞畫屏。"]'),
('yuding-3','塞下','黃滔','唐','御定全唐诗','yuding','','[]','匹馬蕭蕭去不前，平蕪千里見窮邊。關山色死秋深日，',40,'御定全唐詩/json/705.json','["匹馬蕭蕭去不前，平蕪千里見窮邊。關山色死秋深日，", "隴頭冤氣無歸處，化作陰雲飛杳然。"]'),
('yuding-4','下第東歸，留辭刑部鄭郎中諴','黃滔','唐','御定全唐诗','yuding','','[]','去違知己住違親，欲發羸蹄進退頻。萬里家山歸養志，',40,'御定全唐詩/json/705.json','["去違知己住違親，欲發羸蹄進退頻。萬里家山歸養志，", "明日藍田關外路，連天風雨一行人。"]'),
('yuding-5','寄懷南北故人','黃滔','唐','御定全唐诗','yuding','','[]','秋風昨夜落芙蕖，一片離心到外區。南海浪高書墮水，',40,'御定全唐詩/json/705.json','["秋風昨夜落芙蕖，一片離心到外區。南海浪高書墮水，", "嶺上青嵐隴頭月，時通魂夢出來無。"]'),
('yuding-6','關中言懷','黃滔','唐','御定全唐诗','yuding','','[]','事事朝朝委一尊，自知無複解趨奔。試期交後猶為客，',40,'御定全唐詩/json/705.json','["事事朝朝委一尊，自知無複解趨奔。試期交後猶為客，", "舉頭盡到斷腸處，何必秋風江上猿。"]'),
('yuding-7','閨怨','黃滔','唐','御定全唐诗','yuding','','[]','寸心杳與馬蹄隨，如蛻形容在錦帷。江上月明船發後，',40,'御定全唐詩/json/705.json','["寸心杳與馬蹄隨，如蛻形容在錦帷。江上月明船發後，", "待到乘軺入門處，淚珠流盡玉顏衰。"]'),
('yuding-8','旅懷','黃滔','唐','御定全唐诗','yuding','','[]','未吃金丹看十洲，乃將身世作仇讎。羈遊數地值兵亂，',40,'御定全唐詩/json/705.json','["未吃金丹看十洲，乃將身世作仇讎。羈遊數地值兵亂，", "他人折盡月中桂，惆悵當年江上鷗。"]'),
('yuding-9','別友人','黃滔','唐','御定全唐诗','yuding','','[]','已喜相逢又怨嗟，十年飄泊在京華。大朝多事還停舉，',40,'御定全唐詩/json/705.json','["已喜相逢又怨嗟，十年飄泊在京華。大朝多事還停舉，", "夢魂空系瀟湘岸，煙水茫茫蘆葦花。"]'),
('yuding-10','寄羅浮山道者二首','黃滔','唐','御定全唐诗','yuding','','[]','天際雙山壓海濆，天漫絕頂海漫根。時聞雷雨驚樵客，',80,'御定全唐詩/json/705.json','["天際雙山壓海濆，天漫絕頂海漫根。時聞雷雨驚樵客，", "林間學道如容我，今便辭他寵辱喧。", "有人曾見洞中仙，才到人間便越年。金鼎藥成龍入海，", "誰到月明朝禮處，翠岩深鎖荔枝煙。"]'),
('yuding-11','喜侯舍人蜀中新命三首','黃滔','唐','御定全唐诗','yuding','','[]','八都詞客漫喧然，誰解飛揚誥誓間。五色彩毫裁鳳詔，',120,'御定全唐詩/json/705.json','["八都詞客漫喧然，誰解飛揚誥誓間。五色彩毫裁鳳詔，", "謀及中興多少事，莫愁明月不收關。", "卻搜文學起吾唐，暫失都城亦未妨。錦裏幸為丹鳳闕，", "若以掌言看諫獵，相如從此病輝光。", "賈誼才承宣室召，左思唯預秘書流。賦家達者無過此，", "內人未識江淹筆，竟問當時不早求。"]'),
('yuding-12','經安州感故鄭郎中二首','黃滔','唐','御定全唐诗','yuding','','[]','雲夢江頭見故城，人間四十載垂名。馬蹄踐處東風急，',80,'御定全唐詩/json/705.json','["雲夢江頭見故城，人間四十載垂名。馬蹄踐處東風急，", "騰身飛上鳳凰閣，惆悵終乖吾黨情。", "錦帳先生作牧州，干戈缺後見荒丘。兼無姓賈兒童在，", "旅魂頻此歸來否，千載雲山屬一遊。"]'),
('yuding-13','出京別崔學士','黃滔','唐','御定全唐诗','yuding','','[]','一從門館遍投文，旋忝恩知驟出群。不道鶴雞殊羽翼，',40,'御定全唐詩/json/705.json','["一從門館遍投文，旋忝恩知驟出群。不道鶴雞殊羽翼，", "欲逐飄蓬向岐路，數宵垂淚戀清芬。"]'),
('yuding-14','雁','黃滔','唐','御定全唐诗','yuding','','[]','楚岸花晴塞柳衰，年年南北去來期。江城日暮見飛處，',40,'御定全唐詩/json/705.json','["楚岸花晴塞柳衰，年年南北去來期。江城日暮見飛處，", "洞庭雲水瀟湘雨，好把寒更一一知。"]'),
('yuding-15','寄越從事林嵩侍禦','黃滔','唐','御定全唐诗','yuding','','[]','子虛詞賦動君王，誰不期君入對揚。莫戀兔園留看雪，',40,'御定全唐詩/json/705.json','["子虛詞賦動君王，誰不期君入對揚。莫戀兔園留看雪，", "應念都城舊吟客，十年蹤跡委滄浪。"]'),
('yuding-16','長安書事','黃滔','唐','御定全唐诗','yuding','','[]','一年年課數千言，口祝心祠挈出門。孤進難時誰肯薦。',64,'御定全唐詩/json/705.json','["一年年課數千言，口祝心祠挈出門。孤進難時誰肯薦。", "主司通處不須論。頻秋入自邊城雪，昨日聽來嶺樹猿。", "若有水田過十畝，早應歸去狄江村。"]'),
('yuding-17','旅懷寄友人','黃滔','唐','御定全唐诗','yuding','','[]','重疊愁腸只自知，苦於吞蘖亂於絲。一船風雨分襟處，',40,'御定全唐詩/json/705.json','["重疊愁腸只自知，苦於吞蘖亂於絲。一船風雨分襟處，", "鳴蟬似會悠揚意，陌上聲聲怨柳衰。"]'),
('yuding-18','寄蔣先輩','黃滔','唐','御定全唐诗','yuding','','[]','夫差宮苑悉蒼苔，攜客朝遊夜未回。塚上題詩蘇小見，',40,'御定全唐詩/json/705.json','["夫差宮苑悉蒼苔，攜客朝遊夜未回。塚上題詩蘇小見，", "千載三吳有高跡，虎丘山翠益崔嵬。"]'),
('yuding-19','旅懷','黃滔','唐','御定全唐诗','yuding','','[]','雪貌潛凋雪發生，故園魂斷弟兼兄。十年除夜在孤館，',40,'御定全唐詩/json/705.json','["雪貌潛凋雪發生，故園魂斷弟兼兄。十年除夜在孤館，", "侯門莫問曾遊處，槐柳影中肝膽傾。"]'),
('yuding-20','放榜日','黃滔','唐','御定全唐诗','yuding','','[]','吾唐取士最堪誇，仙榜標名出曙霞。白馬嘶風三十轡，',40,'御定全唐詩/json/705.json','["吾唐取士最堪誇，仙榜標名出曙霞。白馬嘶風三十轡，", "歲歲人人來不得，曲江煙水杏園花。"]'),
('yuding-21','二月二日宴中貽同年封先輩渭','黃滔','唐','御定全唐诗','yuding','','[]','帝堯城裏日銜杯，每倚嵇康到玉頹。桂苑五更聽榜後，',40,'御定全唐詩/json/705.json','["帝堯城裏日銜杯，每倚嵇康到玉頹。桂苑五更聽榜後，", "同戴大恩何處報，永言交道契陳雷。"]'),
('yuding-22','新野道中','黃滔','唐','御定全唐诗','yuding','','[]','野堂如雪草如茵，光武城邊一水濱。越客歸遙春有雨，',40,'御定全唐詩/json/705.json','["野堂如雪草如茵，光武城邊一水濱。越客歸遙春有雨，", "莫道還家不惆悵，蘇秦羈旅長卿貧。"]'),
('yuding-23','酬俞鈞','黃滔','唐','御定全唐诗','yuding','','[]','鄉書一忝薦延恩，二紀三朝泣省門。雖忝立名經聖鑒，',40,'御定全唐詩/json/705.json','["鄉書一忝薦延恩，二紀三朝泣省門。雖忝立名經聖鑒，", "今日朝廷推草澤，佇君承詔出雲根。"]'),
('yuding-24','寄同年崔學士','黃滔','唐','御定全唐诗','yuding','','[]','半因同醉杏花園，塵忝鴻爐與鑄顏。已脫素衣酬素發，',40,'御定全唐詩/json/705.json','["半因同醉杏花園，塵忝鴻爐與鑄顏。已脫素衣酬素發，", "畢使海涯能拔宅，三秦二十四畿寰。"]'),
('yuding-25','禦試二首','黃滔','唐','御定全唐诗','yuding','','[]','已表隋珠各自攜，更從瓊殿立丹梯。九華燈作三條燭，',80,'御定全唐詩/json/705.json','["已表隋珠各自攜，更從瓊殿立丹梯。九華燈作三條燭，", "明朝莫惜場場醉，青桂新香有紫泥。", "六曹三省列簪裾，丹詔宣來試士初。不是玉皇疑羽客，", "禦目四篇酬九百，敢從燈下略躊躇。"]'),
('yuding-26','寄陳侍禦','黃滔','唐','御定全唐诗','yuding','','[]','千年二相未全誇，猶闕閩城賀降麻。何必錦衣須太守，',40,'御定全唐詩/json/705.json','["千年二相未全誇，猶闕閩城賀降麻。何必錦衣須太守，", "九級燕金滿尊酒，卻愁隨詔謁承華。"]'),
('yuding-27','酬徐正字夤','黃滔','唐','御定全唐诗','yuding','','[]','已免蹉跎負歲華，敢辭霜鬢雪呈花。名從兩榜考升第，',40,'御定全唐詩/json/705.json','["已免蹉跎負歲華，敢辭霜鬢雪呈花。名從兩榜考升第，", "莫言蓬閣從容久，披處終知金在砂。"]'),
('yuding-28','辭相府','黃滔','唐','御定全唐诗','yuding','','[]','從漢至唐分五州，誰為將相作諸侯。閩江似鏡正堪戀，',40,'御定全唐詩/json/705.json','["從漢至唐分五州，誰為將相作諸侯。閩江似鏡正堪戀，", "今朝拜別幡幢下，雙淚如珠滴不休。"]'),
('yuding-29','寄羅郎中隱','黃滔','唐','御定全唐诗','yuding','','[]','休向中興雪至冤，錢塘江上看濤翻。三征不起時賢議，',40,'御定全唐詩/json/705.json','["休向中興雪至冤，錢塘江上看濤翻。三征不起時賢議，", "瑤蟾若使知人事，仙桂應遭蠹卻根。"]'),
('yuding-30','江行遇王侍禦','黃滔','唐','御定全唐诗','yuding','','[]','數年分散秦吳隔，暫泊官船浦柳中。新草軍書名更重，',40,'御定全唐詩/json/705.json','["數年分散秦吳隔，暫泊官船浦柳中。新草軍書名更重，", "此日相逢魂合斷，賴君身事漸飛沖。"]'),
('yuding-31','客舍秋晚夜懷故山','黃滔','唐','御定全唐诗','yuding','','[]','寥寥深巷客中居，況值窮秋百事疏。孤枕憶山千裏外，',40,'御定全唐詩/json/705.json','["寥寥深巷客中居，況值窮秋百事疏。孤枕憶山千裏外，", "長系寸心歸未得，起挑殘燭獨躊躇。"]'),
('yuding-32','絳州鄭尚書','黃滔','唐','御定全唐诗','yuding','','[]','旌旗日日展東風，雲稼連山雪刃空。剖竹已知垂鳳食，',40,'御定全唐詩/json/705.json','["旌旗日日展東風，雲稼連山雪刃空。剖竹已知垂鳳食，", "誰謂唐城諸父老，今時得見蜀文翁。"]'),
('yuding-33','喜陳先輩及第','黃滔','唐','御定全唐诗','yuding','','[]','今年春已到京華，天與吾曹雪怨嗟。甲乙中時公道複，',40,'御定全唐詩/json/705.json','["今年春已到京華，天與吾曹雪怨嗟。甲乙中時公道複，", "不是駕前偏落羽，錦城爭得杏園花。"]'),
('yuding-34','延福裏居，和林寬、何紹餘酬寄','黃滔','唐','御定全唐诗','yuding','','[]','長說愁吟逆旅中，一庭深雪一窗風。眼前道路無心覓，',40,'御定全唐詩/json/705.json','["長說愁吟逆旅中，一庭深雪一窗風。眼前道路無心覓，", "高情未以幹時廢，屬和因知興不窮。"]'),
('yuding-35','贈宿松楊明府','黃滔','唐','御定全唐诗','yuding','','[]','溪上家家禮樂新，始知為政異常倫。若非似水清無底，',40,'御定全唐詩/json/705.json','["溪上家家禮樂新，始知為政異常倫。若非似水清無底，", "宦遊兼得逍遙趣，休憶三吳舊釣津。"]'),
('yuding-36','送僧','黃滔','唐','御定全唐诗','yuding','','[]','才年七歲便從師，猶說辭家學佛遲。新劚松蘿還不住，',40,'御定全唐詩/json/705.json','["才年七歲便從師，猶說辭家學佛遲。新劚松蘿還不住，", "鳥道瀧湫悉行後，豈將翻譯負心期。"]'),
('yuding-37','贈鄭明府','黃滔','唐','御定全唐诗','yuding','','[]','庭羅衙吏眼看山，真恐風流是謫仙。垂柳五株春婭姹，',40,'御定全唐詩/json/705.json','["庭羅衙吏眼看山，真恐風流是謫仙。垂柳五株春婭姹，", "莫起陶潛折腰歎，才高位下始稱賢。"]'),
('yuding-38','江州夜宴獻陳員外','黃滔','唐','御定全唐诗','yuding','','[]','多少歡娛簇眼前，潯陽江上夜開筵。數枝紅蠟啼香淚，',40,'御定全唐詩/json/705.json','["多少歡娛簇眼前，潯陽江上夜開筵。數枝紅蠟啼香淚，", "因知往歲樓中月，占得風流是偶然。"]'),
('yuding-39','湘中贈張逸人','黃滔','唐','御定全唐诗','yuding','','[]','羽衣零落帽欹斜，不自孤峰即海沙。曾為蜀山成寓跡，',40,'御定全唐詩/json/705.json','["羽衣零落帽欹斜，不自孤峰即海沙。曾為蜀山成寓跡，", "更愛扁舟宿寒夜，獨聽風雨過蘆花。"]'),
('yuding-40','寓題','黃滔','唐','御定全唐诗','yuding','','[]','紛紛墨敕除官日，處處紅旗打賊時。竿底得璜猶未用，',40,'御定全唐詩/json/705.json','["紛紛墨敕除官日，處處紅旗打賊時。竿底得璜猶未用，", "兩岸蘆花一江水，依前且把釣魚絲。"]'),
('yuding-41','題陳山人居','黃滔','唐','御定全唐诗','yuding','','[]','猶自莓苔馬跡重，石嵌泉冷懶移峰。空垂鳳食簷前竹，',40,'御定全唐詩/json/705.json','["猶自莓苔馬跡重，石嵌泉冷懶移峰。空垂鳳食簷前竹，", "誰能惆悵磻溪事，今古悠悠不再逢。"]'),
('yuding-42','宿李少府園林','黃滔','唐','御定全唐诗','yuding','','[]','一壺濁酒百家詩，住此園林守選期。深院月涼留客夜，',40,'御定全唐詩/json/705.json','["一壺濁酒百家詩，住此園林守選期。深院月涼留客夜，", "明日綠苔渾掃後，石庭吟坐複容誰。"]'),
('yuding-43','送人明經及第東歸','黃滔','唐','御定全唐诗','yuding','','[]','十問九通離義床，今時登第信非常。亦從南院看新榜，',40,'御定全唐詩/json/705.json','["十問九通離義床，今時登第信非常。亦從南院看新榜，", "知君已塞平生願，日與交親醉幾場。"]'),
('yuding-44','斷酒','黃滔','唐','御定全唐诗','yuding','','[]','未老先為百病仍，醉杯無計接賓朋。免遭拽盞郎君謔，',40,'御定全唐詩/json/705.json','["未老先為百病仍，醉杯無計接賓朋。免遭拽盞郎君謔，", "何因澆得離腸爛，南浦東門恨不勝。"]'),
('yuding-45','南海幕和段先輩送韋侍禦赴闕','黃滔','唐','御定全唐诗','yuding','','[]','樹色川光入暮秋，使車西發不勝愁。璧連標格驚分散，',40,'御定全唐詩/json/705.json','["樹色川光入暮秋，使車西發不勝愁。璧連標格驚分散，", "滿園歌管涼宵月，此後相思幾上樓。"]'),
('yuding-46','寄南海黃尚書','黃滔','唐','御定全唐诗','yuding','','[]','五羊城下駐行車，此事如今八載餘。燕頷已知飛食肉，',40,'御定全唐詩/json/705.json','["五羊城下駐行車，此事如今八載餘。燕頷已知飛食肉，", "西望清光寄消息，萬重煙水一封書。"]'),
('yuding-47','送人往蘇州覲其兄','黃滔','唐','御定全唐诗','yuding','','[]','闔閭城外越江頭，兩地煙濤一葉舟。到日荊枝應便茂，',40,'御定全唐詩/json/705.json','["闔閭城外越江頭，兩地煙濤一葉舟。到日荊枝應便茂，", "明日尊前若相問，為言今訪赤松遊。"]'),
('yuding-48','游東林寺','黃滔','唐','御定全唐诗','yuding','','[]','長生猶自重無生，言讓仙祠佛寺成。碑折誰忘康樂制，',40,'御定全唐詩/json/705.json','["長生猶自重無生，言讓仙祠佛寺成。碑折誰忘康樂制，", "莫怪遲遲不歸去，童年已夢繞林行。"]'),
('yuding-49','贈旌德呂明府','黃滔','唐','御定全唐诗','yuding','','[]','渥窪步數太阿姿，爭遣王侯不奉知。花作城池入官處，',40,'御定全唐詩/json/705.json','["渥窪步數太阿姿，爭遣王侯不奉知。花作城池入官處，", "須信隔簾看刺史，錦章朱紱已葳蕤。"]'),
('yuding-50','賀清源僕射新命','黃滔','唐','御定全唐诗','yuding','','[]','雖言嵩嶽秀崔嵬，少降連枝命世才。南史兩榮唯百揆，',40,'御定全唐詩/json/705.json','["雖言嵩嶽秀崔嵬，少降連枝命世才。南史兩榮唯百揆，", "虛說古賢龍虎盛，誰攀荊樹上金台。"]'),
('yuding-51','浙幕李端公泛建溪','黃滔','唐','御定全唐诗','yuding','','[]','越城吳國結良姻，交發芙蓉幕內賓。自顧幽沈槐省跡，',40,'御定全唐詩/json/705.json','["越城吳國結良姻，交發芙蓉幕內賓。自顧幽沈槐省跡，", "更愛延平津上過，一雙神劍是龍鱗。"]'),
('yuding-52','貽宋評事','黃滔','唐','御定全唐诗','yuding','','[]','河陽城裏謝城中，入曳長裾出佩銅。燕國金台無別客，',40,'御定全唐詩/json/705.json','["河陽城裏謝城中，入曳長裾出佩銅。燕國金台無別客，", "時說三吳欲歸處，綠波洲渚紫蒲叢。"]'),
('yuding-53','催妝','黃滔','唐','御定全唐诗','yuding','','[]','北府迎塵南郡來，莫將芳意更遲回。雖言天上光陰別，',40,'御定全唐詩/json/705.json','["北府迎塵南郡來，莫將芳意更遲回。雖言天上光陰別，", "吹簫不是神仙曲，爭引秦娥下鳳台。"]'),
('yuding-54','寓題','黃滔','唐','御定全唐诗','yuding','','[]','每憶家山即涕零，定須歸老舊雲扃。銀河水到人間濁，',40,'御定全唐詩/json/705.json','["每憶家山即涕零，定須歸老舊雲扃。銀河水到人間濁，", "三千九萬平生事，卻恨南華說北溟。"]'),
('yuding-55','傷蔣校書德山','黃滔','唐','御定全唐诗','yuding','','[]','誰到雙溪溪岸傍，與招魂魄上蒼蒼。世間無樹勝青桂，',40,'御定全唐詩/json/705.json','["誰到雙溪溪岸傍，與招魂魄上蒼蒼。世間無樹勝青桂，", "如何萬古雕龍手，獨是相如識漢皇。"]'),
('yuding-56','寄楊贊圖學士','黃滔','唐','御定全唐诗','yuding','','[]','東堂第一領春風，時怪關西小驥慵。華表柱頭還有鶴，',40,'御定全唐詩/json/705.json','["東堂第一領春風，時怪關西小驥慵。華表柱頭還有鶴，", "今日江南駐舟處，莫言歸計為雲峰。"]'),
('yuding-57','酬楊學士','黃滔','唐','御定全唐诗','yuding','','[]','神仙簿上愧非夫，詔作疑丹兩入爐。詩裏幾曾吟芍藥，',40,'御定全唐詩/json/705.json','["神仙簿上愧非夫，詔作疑丹兩入爐。詩裏幾曾吟芍藥，", "莫下蓬山不回首，東風猶待重摶扶。"]'),
('yuding-58','寄同年李侍郎龜正','黃滔','唐','御定全唐诗','yuding','','[]','石門南面淚浪浪，自此東西失帝鄉。昆璞要疑方卓絕，',40,'御定全唐詩/json/705.json','["石門南面淚浪浪，自此東西失帝鄉。昆璞要疑方卓絕，", "莫道秋霜不滋物，菊花還借後時黃。"]'),
('yuding-59','鐘陵故人','黃滔','唐','御定全唐诗','yuding','','[]','滕王閣下昔相逢，此地今難訪所從。唯愛金籠貯鸚鵡，',24,'御定全唐詩/json/705.json','["滕王閣下昔相逢，此地今難訪所從。唯愛金籠貯鸚鵡，"]'),
('yuding-60','故山','黃滔','唐','御定全唐诗','yuding','','[]','支頤默省舊林泉，石徑茅堂到目前。衰碧鳴蛩莎有露，',40,'御定全唐詩/json/705.json','["支頤默省舊林泉，石徑茅堂到目前。衰碧鳴蛩莎有露，", "何事蒼髯不歸去，燕昭臺上一年年。"]'),
('yuding-61','塞上','黃滔','唐','御定全唐诗','yuding','','[]','塞門關外日光微，角怨單于雁駐飛。沖水路從冰解斷，',40,'御定全唐詩/json/705.json','["塞門關外日光微，角怨單于雁駐飛。沖水路從冰解斷，", "欲吊昭君倍惆悵，漢家甥舅竟相違。"]'),
('yuding-62','烏石村','黃滔','唐','御定全唐诗','yuding','','[]','往日江村今物華，一回登覽一悲嗟。故人歿後城頭月，',40,'御定全唐詩/json/705.json','["往日江村今物華，一回登覽一悲嗟。故人歿後城頭月，", "謝公古郡青山在，三尺孤墳撲海沙。"]'),
('yuding-63','寄同年盧員外','黃滔','唐','御定全唐诗','yuding','','[]','聽盡鶯聲出雍州，秦吳煙月十經秋。龍門在地從人上，',40,'御定全唐詩/json/705.json','["聽盡鶯聲出雍州，秦吳煙月十經秋。龍門在地從人上，", "當年甲乙皆華顯，應念槐宮今雪頭。"]'),
('yuding-64','寄同年封舍人渭','黃滔','唐','御定全唐诗','yuding','','[]','唐城接軫赴秦川，憂合歡離驟十年。龍頷摘珠同泳海，',40,'御定全唐詩/json/705.json','["唐城接軫赴秦川，憂合歡離驟十年。龍頷摘珠同泳海，", "能使丘門終始雪，莫教華髮獨潸然。"]'),
('yuding-65','遇羅員外袞','黃滔','唐','御定全唐诗','yuding','','[]','灞陵橋外駐征轅，此一分飛十六年。豸角戴時垂素發，',40,'御定全唐詩/json/705.json','["灞陵橋外駐征轅，此一分飛十六年。豸角戴時垂素發，", "可忘自初相識地，秋風明月客鄜延。"]'),
('yuding-66','送翁員外承贊','黃滔','唐','御定全唐诗','yuding','','[]','誰言吾黨命多奇，榮美如君歷數稀。衣錦還鄉翻是客，',40,'御定全唐詩/json/705.json','["誰言吾黨命多奇，榮美如君歷數稀。衣錦還鄉翻是客，", "已分十旬無急詔，天涯相送只沾衣。"]'),
('yuding-67','奉和翁文堯十九員外中謝日蒙恩賜金紫之什','黃滔','唐','御定全唐诗','yuding','','[]','面蒙君賜自龍墀，誰是還鄉一襲衣。三品易懸鱗鬣赫，',40,'御定全唐詩/json/705.json','["面蒙君賜自龍墀，誰是還鄉一襲衣。三品易懸鱗鬣赫，", "嚴助買臣精魄在，定應羞著昔年歸。"]'),
('yuding-68','翁文堯員外捧金紫還鄉之命雅發篇章將原交情…以質獎私','黃滔','唐','御定全唐诗','yuding','','[]','摶將盛事更無餘，還向橋邊看舊書。東越獨推生竹箭，',40,'御定全唐詩/json/705.json','["摶將盛事更無餘，還向橋邊看舊書。東越獨推生竹箭，", "須把頭冠彈盡日，憐君不與故人疏。"]'),
('yuding-69','奉和翁文堯員外經過七林書堂見寄之什','黃滔','唐','御定全唐诗','yuding','','[]','朱旗引入昔茆堂，半日從容盡日忙。駟馬寶車行錫禮，',40,'御定全唐詩/json/705.json','["朱旗引入昔茆堂，半日從容盡日忙。駟馬寶車行錫禮，", "定恐故園留不住，竹風松韻漫淒鏘。"]'),
('yuding-70','奉酬翁文堯員外駐南台見寄之什','黃滔','唐','御定全唐诗','yuding','','[]','人指南臺山與川，大驚喜氣異當年。花迎金冊非時拆，',40,'御定全唐詩/json/705.json','["人指南臺山與川，大驚喜氣異當年。花迎金冊非時拆，", "殷勤更抱鳴琴撫，為憶秦兒識斷弦。"]'),
('yuding-71','翁文堯員外擁冊禮之歸一路有詩名晝錦集…五十六字','黃滔','唐','御定全唐诗','yuding','','[]','六窠只佩諸侯印，爭比從天擁冊歸。一軸郢人歌處雪，',40,'御定全唐詩/json/705.json','["六窠只佩諸侯印，爭比從天擁冊歸。一軸郢人歌處雪，", "明日陪塵迎駟馬，定淮齋沐看光輝。"]'),
('yuding-72','奉和翁文堯員外文秀、光賢、晝錦之什','黃滔','唐','御定全唐诗','yuding','','[]','鄉名裏號一朝新，乃覺台恩重萬鈞。建水閩山無故事，',120,'御定全唐詩/json/705.json','["鄉名裏號一朝新，乃覺台恩重萬鈞。建水閩山無故事，", "莫憑欄幹剩留駐，內庭虛位待才臣。", "雖言閩越系生賢，誰是還家寵自天。山簡槐兼諸郡命，", "休說遲回未能去，夜來新夢禁中泉。", "君王面賜紫還鄉，金紫中推是甲裳。華構便將垂美號，", "珍重朱欄兼翠拱，來來皆自讀書堂。"]'),
('yuding-73','奉酬翁文堯員外神泉之遊見寄嘉什','黃滔','唐','御定全唐诗','yuding','','[]','含雞假豸喜同遊，野外嘶風並紫騮。松竹迥尋青障寺，',40,'御定全唐詩/json/705.json','["含雞假豸喜同遊，野外嘶風並紫騮。松竹迥尋青障寺，", "爭奈愛山尤戀闕，古來能有幾人休。"]'),
('yuding-74','輒吟七言四韻，攀寄翁文堯拾遺','黃滔','唐','御定全唐诗','yuding','','[]','唐設高科表用文，吾曹誰作諫垣臣。甄山秀氣曠千古，',40,'御定全唐詩/json/705.json','["唐設高科表用文，吾曹誰作諫垣臣。甄山秀氣曠千古，", "龍頭龍尾前年夢，今日須憐應若神。"]'),
('yuding-0','塞上','黃滔','唐','御定全唐诗','yuding','','[]','掘地破重城，燒山搜伏兵。金徽互嗚咽，玉笛自淒清。',96,'御定全唐詩/json/706.json','["掘地破重城，燒山搜伏兵。金徽互嗚咽，玉笛自淒清。", "使發西都聳，塵空北嶽橫。長河涉有路，曠野宿無程。", "沙雨黃鶯囀，轅門青草生。馬歸秦苑牧，人在虜雲耕。", "落日牛羊聚，秋風鼓角鳴。如何漢天子，青塚杳含情。"]'),
('yuding-1','寄獻梓橦山侯侍禦','黃滔','唐','御定全唐诗','yuding','','[]','漢宮行廟略，簪笏落民間。直道三湘水，高情四皓山。',96,'御定全唐詩/json/706.json','["漢宮行廟略，簪笏落民間。直道三湘水，高情四皓山。", "賜衣僧脫去，奏表主批還。地得松蘿塢，泉通雨雪灣。", "東門添故事，南省缺新班。片石秋從露，幽窗夜不關。", "夢餘蟾隱映，吟次鳥綿蠻。可惜相如作，當時事悉閑。"]'),
('yuding-2','壬癸歲書情','黃滔','唐','御定全唐诗','yuding','','[]','故園招隱客，應便笑無成。謁帝逢移國，投文值用兵。',96,'御定全唐詩/json/706.json','["故園招隱客，應便笑無成。謁帝逢移國，投文值用兵。", "孤松憐鶴在，疏柳惡蟬鳴。匹馬迷歸處，青雲失曩情。", "江頭寒夜宿，壟上歉年耕。冠蓋新人物，漁樵舊弟兄。", "易生唯白髮，難立是浮名。惆悵灞橋路，秋風誰入行。"]'),
('yuding-3','河南府試秋夕聞新雁','黃滔','唐','御定全唐诗','yuding','','[]','湘南飛去日，薊北乍驚秋。叫出隴雲夜，聞為客子愁。',72,'御定全唐詩/json/706.json','["湘南飛去日，薊北乍驚秋。叫出隴雲夜，聞為客子愁。", "一聲初觸夢，半白已侵頭。旅館移欹枕，江城起倚樓。", "餘燈依古壁，片月下滄洲。寂聽良宵徹，躊躇感歲流。"]'),
('yuding-4','省試奉詔漲曲江池','黃滔','唐','御定全唐诗','yuding','','[]','地脈寒來淺，恩波住後新。引將諸派水，別貯大都春。',72,'御定全唐詩/json/706.json','["地脈寒來淺，恩波住後新。引將諸派水，別貯大都春。", "幽咽疏通處，清泠迸入辰。漸平連杏岸，旋闊映樓津。", "沙沒迷行徑，洲寬恣躍鱗。願當舟楫便，一附濟川人。"]'),
('yuding-5','題宣一僧正院','黃滔','唐','御定全唐诗','yuding','','[]','五級淩虛塔，三生落發師。都僧須有托，孤嶠遂無期。',72,'御定全唐詩/json/706.json','["五級淩虛塔，三生落發師。都僧須有托，孤嶠遂無期。", "井邑焚香待，君侯減俸資。山衣隨疊破，萊骨逐年羸。", "茶取寒泉試，松於遠澗移。吾曹來頂手，不合不題詩。"]'),
('yuding-6','和吳學士對春雪獻韋令公次韻','黃滔','唐','御定全唐诗','yuding','','[]','春雪下盈空，翻疑臘未窮。連天寧認月，墮地屢兼風。',120,'御定全唐詩/json/706.json','["春雪下盈空，翻疑臘未窮。連天寧認月，墮地屢兼風。", "忽誤邊沙上，應平火嶺中。林間妨走獸，雲際落飛鴻。", "梁苑還吟客，齊都省創宮。掩扉皆墐北，移律愧居東。", "書幌飄全濕，茶鐺入旋融。奔川半留滯，疊樹互玲瓏。", "出戶行瑤砌，開園見粉叢。高才興詠處，真宰答殊功。"]'),
('yuding-7','省試一一吹竽','黃滔','唐','御定全唐诗','yuding','','[]','齊竽今曆試，真偽不難知。欲使聲聲別，須令個個吹。',72,'御定全唐詩/json/706.json','["齊竽今曆試，真偽不難知。欲使聲聲別，須令個個吹。", "後先無錯雜，能否立參差。次第教單進，宮商乃異宜。", "凡音皆竄跡，至藝始呈奇。以此論文學，終憑一一窺。"]'),
('yuding-8','明月照高樓','黃滔','唐','御定全唐诗','yuding','','[]','月滿長空朗，樓侵碧落橫。波文流藻井，桂魄拂雕楹。',72,'御定全唐詩/json/706.json','["月滿長空朗，樓侵碧落橫。波文流藻井，桂魄拂雕楹。", "深鑒羅紈薄，寒搜戶牖清。冰鋪梁燕噤，霜覆瓦松傾。", "卓午收全影，斜懸轉半明。佳人當此夕，多少別離情。"]'),
('yuding-9','廣州試越台懷古','黃滔','唐','御定全唐诗','yuding','','[]','南越千年事，興懷一旦來。歌鐘非舊俗，煙月有層台。',72,'御定全唐詩/json/706.json','["南越千年事，興懷一旦來。歌鐘非舊俗，煙月有層台。", "北望人何在，東流水不回。吹窗風雜瘴，沾檻雨經梅。", "壯氣曾難揖，空名信可哀。不堪登覽處，花落與花開。"]'),
('yuding-10','襄州試白雲歸帝鄉','黃滔','唐','御定全唐诗','yuding','','[]','杳杳複霏霏，應緣有所依。不言天路遠，終望帝鄉歸。',72,'御定全唐詩/json/706.json','["杳杳複霏霏，應緣有所依。不言天路遠，終望帝鄉歸。", "高嶽和霜過，遙關帶月飛。漸憐雙闕近，寧恨眾山違。", "陣觸銀河亂，光連粉署微。旅人隨計日，自笑比麻衣。"]'),
('yuding-11','省試內出白鹿宣示百官','黃滔','唐','御定全唐诗','yuding','','[]','上瑞何曾乏，毛群表色難。推於五靈少，宣示百寮觀。',72,'御定全唐詩/json/706.json','["上瑞何曾乏，毛群表色難。推於五靈少，宣示百寮觀。", "形奪場駒潔，光交月兔寒。已馴瑤草別，孤立雪花團。", "戴豸慚端士，抽毫躍史官。貴臣歌詠日，皆作白麟看。"]'),
('yuding-12','出關言懷','黃滔','唐','御定全唐诗','yuding','','[]','又乞書題出，關西謁列侯。寄家僧許嶽，釣浦雨移洲。',72,'御定全唐詩/json/706.json','["又乞書題出，關西謁列侯。寄家僧許嶽，釣浦雨移洲。", "賣馬登長陸，沾衣逐勝遊。菜腸終日餒，霜鬢度年秋。", "詩苦無人愛，言公是世仇。卻憐庭際草，中有號忘憂。"]'),
('yuding-13','壺公山','黃滔','唐','御定全唐诗','yuding','','[]','八面峰巒秀，孤高可偶然。數人遊頂上，滄海見東邊。',360,'御定全唐詩/json/706.json','["八面峰巒秀，孤高可偶然。數人遊頂上，滄海見東邊。", "不信無靈洞，相傳有古仙。橘如珠夏在，池象月垂穿。", "仿佛嘗聞樂，岧嶢半插天。山寒徹三伏，松偃出千年。", "樵牧時迷所，倉箱歲疊川。嚴祠風雨管，怪木薜蘿纏。", "青草方中藥，蒼苔石裏錢。瓊津流乳竇，春色駐芝田。", "烏兔中時近，龍蛇蟄處膻。嘉名光列土，秀氣產群賢。", "瀑鎖瑤台路，溪升釣浦船。鼇頭擎恐沒，地軸壓應旋。", "蠲疾寒甘露，藏珍起瑞煙。畫工飛夢寐，詩客寄林泉。", "掘地多雲母，緣霜欠木綿。井通鰍吐脈，僧隔虎棲禪。", "危磴千尋拔，奇花四季鮮。鶴歸懸圃少，鳳下碧梧偏。", "桃易炎涼熟，茶推醉醒煎。村家蒙棗栗，俗骨爽猿蟬。", "谷語升喬鳥，陂開共蒂蓮。落楓丹葉舞，新蕨紫芽拳。", "翠竹雕羌笛，懸藤煮蜀箋。白雲長掩映，流水別潺湲。", "作賦前儒闕，沖虛南國先。省郎求牧看，野老葺齋眠。", "寺立興衰創，碑須一二鐫。清吟思卻隱，簪紱奈縈牽。"]'),
('yuding-14','和王舍人、崔補闕題天王寺','黃滔','唐','御定全唐诗','yuding','','[]','郭內青山寺，難論此崛奇。白雲生院落，流水下城池。',168,'御定全唐詩/json/706.json','["郭內青山寺，難論此崛奇。白雲生院落，流水下城池。", "石像雷霆啟，江沙鼎鼐期。岳僧來坐夏，秦客會題詩。", "岡轉泉根滑，門升蘚級危。紫微今日句，黃絹昔年碑。", "歇鶴松低閣，鳴蛩徑出籬。粉垣千堵束，金塔九層支。", "啼鳥笙簧韻，開花錦繡姿。清齋奔井邑，玄發剃熊羆。", "極浦征帆小，平蕪落日遲。風篁清卻暑，煙草綠無時。", "信士三公作，靈蹤四絕推。良游如不宿，明月擬何之。"]'),
('yuding-15','投翰長趙侍郎','黃滔','唐','御定全唐诗','yuding','','[]','禹門西面逐飄蓬，忽喜仙都得入蹤。賈氏許頻趨季虎，',88,'御定全唐詩/json/706.json','["禹門西面逐飄蓬，忽喜仙都得入蹤。賈氏許頻趨季虎，", "五色筆驅神出沒，八花磚接帝從容。詩酬禦制風騷古，", "攀鴻日淺魂飛越，為鯉年深勢噞喁。澤國雨荒三徑草，", "願向明朝薦幽滯，免教號泣觸登庸。"]'),
('yuding-16','鄜畤李相公','黃滔','唐','御定全唐诗','yuding','','[]','秦城擇日發征轅，齋戒來投節制尊。分虎名高初命相，',96,'御定全唐詩/json/706.json','["秦城擇日發征轅，齋戒來投節制尊。分虎名高初命相，", "華舍未開寧有礙，彩毫雖乏敢無言。生兼文武為人傑，", "功高馬卸黃金甲，台迥賓歡白玉樽。九穗嘉禾垂綺陌，", "青草連沙無血濺，黃榆鎖塞有鶯翻。笙歌合遝春風郭，"]'),
('yuding-17','成名後呈同年','黃滔','唐','御定全唐诗','yuding','','[]','業詩攻賦薦鄉書，二紀如鴻曆九衢。待得至公搜草澤，',72,'御定全唐詩/json/706.json','["業詩攻賦薦鄉書，二紀如鴻曆九衢。待得至公搜草澤，", "蒙楚數疑休下泣，師劉大喝已為盧。人間灰管供紅杏，", "名推顏柳題金塔，飲自燕秦索玉姝。退愧單寒終預此，"]'),
('yuding-18','投刑部裴郎中','黃滔','唐','御定全唐诗','yuding','','[]','兩榜驅牽別海涔，佗門不合覓知音。瞻恩雖隔雲雷賜，',72,'御定全唐詩/json/706.json','["兩榜驅牽別海涔，佗門不合覓知音。瞻恩雖隔雲雷賜，", "已齊日月懸千古，肯誤風塵使陸沉。拜首敢將誠吐血，", "緇化衣空難抵雪，黑銷頭盡不勝簪。數行淚裏依投志，"]'),
('yuding-19','輦下寓題','黃滔','唐','御定全唐诗','yuding','','[]','對酒何曾醉，尋僧未覺閑。無人不惆悵，終日見南山。',24,'御定全唐詩/json/706.json','["對酒何曾醉，尋僧未覺閑。無人不惆悵，終日見南山。"]'),
('yuding-20','寄題崔校書郊舍','黃滔','唐','御定全唐诗','yuding','','[]','一片寒塘水，尋常立鷺鷥。主人貧愛客，沽酒往吟詩。',24,'御定全唐詩/json/706.json','["一片寒塘水，尋常立鷺鷥。主人貧愛客，沽酒往吟詩。"]'),
('yuding-21','秋思','黃滔','唐','御定全唐诗','yuding','','[]','碧嶂猿啼夜，新秋雨霽天。誰人愛明月，露坐洞庭船。',24,'御定全唐詩/json/706.json','["碧嶂猿啼夜，新秋雨霽天。誰人愛明月，露坐洞庭船。"]'),
('yuding-22','芳草','黃滔','唐','御定全唐诗','yuding','','[]','澤國多芳草，年年長自春。應從屈平後，更苦不歸人。',24,'御定全唐詩/json/706.json','["澤國多芳草，年年長自春。應從屈平後，更苦不歸人。"]'),
('yuding-23','輦下書事','黃滔','唐','御定全唐诗','yuding','','[]','北闕新王業，東城入羽書。秋風滿林起，誰道有鱸魚。',24,'御定全唐詩/json/706.json','["北闕新王業，東城入羽書。秋風滿林起，誰道有鱸魚。"]'),
('yuding-24','入關言懷','黃滔','唐','御定全唐诗','yuding','','[]','背將蹤跡向京師，出在先春入後時。',32,'御定全唐詩/json/706.json','["背將蹤跡向京師，出在先春入後時。", "落日灞橋飛雪裏，已聞南院有看期。"]'),
('yuding-25','過長江','黃滔','唐','御定全唐诗','yuding','','[]','曾搜景象恐通神，地下還應有主人。',32,'御定全唐詩/json/706.json','["曾搜景象恐通神，地下還應有主人。", "若把長江比湘浦，離騷不合自靈均。"]'),
('yuding-26','題靈峰僧院','黃滔','唐','御定全唐诗','yuding','','[]','系馬松間不忍歸，數巡香茗一枰棋。',32,'御定全唐詩/json/706.json','["系馬松間不忍歸，數巡香茗一枰棋。", "擬登絕頂留人宿，猶待滄溟月滿時。"]'),
('yuding-27','司馬長卿','黃滔','唐','御定全唐诗','yuding','','[]','一自梁園失意回，無人知有掞天才。',32,'御定全唐詩/json/706.json','["一自梁園失意回，無人知有掞天才。", "漢宮不鎖陳皇后，誰肯量金買賦來。"]'),
('yuding-28','歸思','黃滔','唐','御定全唐诗','yuding','','[]','薊北風煙空漢月，湘南雲水半蠻邊。',32,'御定全唐詩/json/706.json','["薊北風煙空漢月，湘南雲水半蠻邊。", "寒為旅雁暖還去，秦越離家可十年。"]'),
('yuding-29','東林寺貫休上人篆隸題詩','黃滔','唐','御定全唐诗','yuding','','[]','師名自越徹秦中，秦越難尋師所從。',32,'御定全唐詩/json/706.json','["師名自越徹秦中，秦越難尋師所從。", "墨蹟兩般詩一首，香爐峰下似相逢。"]'),
('yuding-30','寓江州李使君','黃滔','唐','御定全唐诗','yuding','','[]','使君曾被蟬聲苦，每見詞文即為愁。',32,'御定全唐詩/json/706.json','["使君曾被蟬聲苦，每見詞文即為愁。", "況是楚江鴻到後，可堪西望發孤舟。"]'),
('yuding-31','游南寓題','黃滔','唐','御定全唐诗','yuding','','[]','江山節被雪霜遺，毒草過秋未擬衰。',32,'御定全唐詩/json/706.json','["江山節被雪霜遺，毒草過秋未擬衰。", "天不當時命鄒衍，亦將寒律入南吹。"]'),
('yuding-32','和同年趙先輩觀文','黃滔','唐','御定全唐诗','yuding','','[]','玉兔輪中方是樹，金鼇頂上別無山。',32,'御定全唐詩/json/706.json','["玉兔輪中方是樹，金鼇頂上別無山。", "雖然回首見煙水，事主酬恩難便閑。"]'),
('yuding-33','出京別同年','黃滔','唐','御定全唐诗','yuding','','[]','一枝仙桂已攀援，歸去煙濤浦口村。',32,'御定全唐詩/json/706.json','["一枝仙桂已攀援，歸去煙濤浦口村。", "雖恨別離還有意，槐花黃日出青門。"]'),
('yuding-34','木芙蓉三首','黃滔','唐','御定全唐诗','yuding','','[]','黃鳥啼煙二月朝，若教開即牡丹饒。',96,'御定全唐詩/json/706.json','["黃鳥啼煙二月朝，若教開即牡丹饒。", "天嫌青帝恩光盛，留與秋風雪寂寥。", "卻假青腰女剪成，綠羅囊綻彩霞呈。", "誰憐不及黃花菊，只遇陶潛便得名。", "須到露寒方有態，為經霜裛稍無香。", "移根若在秦宮裏，多少佳人泣曉妝。"]'),
('yuding-35','九日','黃滔','唐','御定全唐诗','yuding','','[]','陽數重時陰數殘，露濃風硬欲成寒。',32,'御定全唐詩/json/706.json','["陽數重時陰數殘，露濃風硬欲成寒。", "莫言黃菊花開晚，獨佔樽前一日歡。"]'),
('yuding-36','夏州道中','黃滔','唐','御定全唐诗','yuding','','[]','隴雁南飛河水流，秦城千里忍回頭。',32,'御定全唐詩/json/706.json','["隴雁南飛河水流，秦城千里忍回頭。", "征行渾與求名背，九月中旬往夏州。"]'),
('yuding-37','經慈州感謝郎中','黃滔','唐','御定全唐诗','yuding','','[]','金聲乃是古詩流，況有池塘春草儔。',32,'御定全唐詩/json/706.json','["金聲乃是古詩流，況有池塘春草儔。", "莫遣宣城獨垂號，雲山彼此謝公遊。"]'),
('yuding-38','寓題','黃滔','唐','御定全唐诗','yuding','','[]','吳中煙水越中山，莫把漁樵謾自寬。',32,'御定全唐詩/json/706.json','["吳中煙水越中山，莫把漁樵謾自寬。", "歸泛扁舟可容易，五湖高士是拋官。"]'),
('yuding-39','寄宋明府','黃滔','唐','御定全唐诗','yuding','','[]','北闕秋期南國身，重關煙月五溪雲。',32,'御定全唐詩/json/706.json','["北闕秋期南國身，重關煙月五溪雲。", "風蟬已有數聲急，賴在陶家柳下聞。"]'),
('yuding-40','靈均','黃滔','唐','御定全唐诗','yuding','','[]','莫問靈均昔日游，江籬春盡岸楓秋。',32,'御定全唐詩/json/706.json','["莫問靈均昔日游，江籬春盡岸楓秋。", "至今此事何人雪，月照楚山湘水流。"]'),
('yuding-41','馬嵬','黃滔','唐','御定全唐诗','yuding','','[]','錦江晴碧劍鋒奇，合有千年降聖時。',32,'御定全唐詩/json/706.json','["錦江晴碧劍鋒奇，合有千年降聖時。", "天意從來知幸蜀，不關胎禍自蛾眉。"]'),
('yuding-42','和陳先輩陪陸舍人春日游曲江','黃滔','唐','御定全唐诗','yuding','','[]','劉超遊召郤詵陪，為憶池亭舊賞來。',32,'御定全唐詩/json/706.json','["劉超遊召郤詵陪，為憶池亭舊賞來。", "紅杏花旁見山色，詩成因觸鼓聲回。"]'),
('yuding-43','花','黃滔','唐','御定全唐诗','yuding','','[]','莫道顏色如渥丹，莫道馨香過蕖蘭。',32,'御定全唐詩/json/706.json','["莫道顏色如渥丹，莫道馨香過蕖蘭。", "東風吹綻還吹落，明日誰為今日看。"]'),
('yuding-44','捲簾','黃滔','唐','御定全唐诗','yuding','','[]','綠鬟侍女手纖纖，新捧嫦娥出素蟾。',32,'御定全唐詩/json/706.json','["綠鬟侍女手纖纖，新捧嫦娥出素蟾。", "衛玠官高難久立，莫辭雙卷水精簾。"]'),
('yuding-45','啟帳','黃滔','唐','御定全唐诗','yuding','','[]','得人憎定繡芙蓉，愛鎖嫦娥出月蹤。',32,'御定全唐詩/json/706.json','["得人憎定繡芙蓉，愛鎖嫦娥出月蹤。", "侍女莫嫌抬素手，撥開珠翠待相逢。"]'),
('yuding-46','去扇','黃滔','唐','御定全唐诗','yuding','','[]','城上風生蠟炬寒，錦帷開處露翔鸞。',32,'御定全唐詩/json/706.json','["城上風生蠟炬寒，錦帷開處露翔鸞。", "已知秦女升仙態，休把圓輕隔牡丹。"]'),
('yuding-47','別後','黃滔','唐','御定全唐诗','yuding','','[]','夢裏相逢無後期，煙中解佩杳何之。',32,'御定全唐詩/json/706.json','["夢裏相逢無後期，煙中解佩杳何之。", "虧蟾便是陳宮鏡，莫吐清光照別離。"]'),
('yuding-48','嚴陵釣台','黃滔','唐','御定全唐诗','yuding','','[]','終向煙霞作野夫，一竿竹不換簪裾。',32,'御定全唐詩/json/706.json','["終向煙霞作野夫，一竿竹不換簪裾。", "直鉤猶逐熊羆起，獨是先生真釣魚。"]'),
('yuding-49','馬嵬二首','黃滔','唐','御定全唐诗','yuding','','[]','鐵馬嘶風一渡河，淚珠零便作驚波。',64,'御定全唐詩/json/706.json','["鐵馬嘶風一渡河，淚珠零便作驚波。", "鳴泉亦感上皇意，流下隴頭嗚咽多。", "龍腦移香鳳輦留，可能千古永悠悠。", "夜台若使香魂在，應作煙花出隴頭。"]'),
('yuding-50','閏八月','黃滔','唐','御定全唐诗','yuding','','[]','無人不愛今年閏，月看中秋兩度圓。',32,'御定全唐詩/json/706.json','["無人不愛今年閏，月看中秋兩度圓。", "唯恐雨師風伯意，至時還奪上樓天。"]'),
('yuding-51','奉和翁文堯戲寄','黃滔','唐','御定全唐诗','yuding','','[]','掘蘭宮裏數名郎，好是乘軺出帝鄉。',32,'御定全唐詩/json/706.json','["掘蘭宮裏數名郎，好是乘軺出帝鄉。", "兩度還家還未有，別論光彩向冠裳。"]'),
('yuding-52','奉和文堯對庭前千葉石榴','黃滔','唐','御定全唐诗','yuding','','[]','一朵千英綻曉枝，彩霞堪與別為期。',32,'御定全唐詩/json/706.json','["一朵千英綻曉枝，彩霞堪與別為期。", "移根若在芙蓉苑，豈向當年有醒時。"]'),
('yuding-53','翁文堯以美疹暫滯令公大王益得異禮觀今日…輒成一章','黃滔','唐','御定全唐诗','yuding','','[]','滋賦諴文侯李盛，終求一襲錦衣難。',32,'御定全唐詩/json/706.json','["滋賦諴文侯李盛，終求一襲錦衣難。", "如何兩度還州裏，兼借鄉人更剩觀。"]'),
('yuding-54','贈友人','黃滔','唐','御定全唐诗','yuding','','[]','超達陶子性，留琴不設弦。覓句朝忘食，傾杯夜廢眠。',48,'御定全唐詩/json/706.json','["超達陶子性，留琴不設弦。覓句朝忘食，傾杯夜廢眠。", "愛月影為伴，吟風聲自連。聽此鶯飛谷，心懷迷遠川。"]'),
('yuding-0','八月十五夜','殷文圭','唐','御定全唐诗','yuding','','[]','萬里無雲鏡九州，最團圓夜是中秋。滿衣冰彩拂不落，',40,'御定全唐詩/json/707.json','["萬里無雲鏡九州，最團圓夜是中秋。滿衣冰彩拂不落，", "因君照我丹心事，減得愁人一夕愁。"]'),
('yuding-1','省試夜投獻座主','殷文圭','唐','御定全唐诗','yuding','','[]','辟開公道選時英，神鏡高懸鑒百靈。混沌分來融間氣，',40,'御定全唐詩/json/707.json','["辟開公道選時英，神鏡高懸鑒百靈。混沌分來融間氣，", "聖教中興周禮在，不勞幹羽舞明庭。"]'),
('yuding-2','觀賀皇太子冊命','殷文圭','唐','御定全唐诗','yuding','','[]','嗣冊儲皇帝命行，萬方臣妾躍歡聲。鸞旃再立星辰正，',40,'御定全唐詩/json/707.json','["嗣冊儲皇帝命行，萬方臣妾躍歡聲。鸞旃再立星辰正，", "春宮保傅皆周召，致主何憂不太平。"]'),
('yuding-3','行朝早春侍師門宴西溪席上作','殷文圭','唐','御定全唐诗','yuding','','[]','西溪水色淨於苔，畫鷁橫風絳帳開。弦管旋飄蓬島去，',40,'御定全唐詩/json/707.json','["西溪水色淨於苔，畫鷁橫風絳帳開。弦管旋飄蓬島去，", "三榜生徒逾七十，豈期龍阪納非才。"]'),
('yuding-4','賀同年第三人劉先輩咸辟命','殷文圭','唐','御定全唐诗','yuding','','[]','甲門才子鼎科人，拂地藍衫榜下新。脫俗文章笑鸚鵡，',40,'御定全唐詩/json/707.json','["甲門才子鼎科人，拂地藍衫榜下新。脫俗文章笑鸚鵡，", "多愧受恩同闕裏，不嫌師僻與顏貧。"]'),
('yuding-5','寄廣南劉僕射','殷文圭','唐','御定全唐诗','yuding','','[]','戰國從今卻尚文，品流才子作將軍。畫船清宴蠻溪雨，',40,'御定全唐詩/json/707.json','["戰國從今卻尚文，品流才子作將軍。畫船清宴蠻溪雨，", "漢儀一化南人後，牧馬無因更夜聞。"]'),
('yuding-6','題吳中陸龜蒙山齋','殷文圭','唐','御定全唐诗','yuding','','[]','萬卷圖書千戶貴，十洲煙景四時和。花心露洗猩猩血，',40,'御定全唐詩/json/707.json','["萬卷圖書千戶貴，十洲煙景四時和。花心露洗猩猩血，", "天麟不觸人間網，擬把公卿換得麼。"]'),
('yuding-7','經李翰林墓','殷文圭','唐','御定全唐诗','yuding','','[]','詩中日月酒中仙，平地雄飛上九天。身謫蓬萊金籍外，',40,'御定全唐詩/json/707.json','["詩中日月酒中仙，平地雄飛上九天。身謫蓬萊金籍外，", "十字遺碑三尺墓，只應吟客吊秋煙。"]'),
('yuding-8','鸚鵡','殷文圭','唐','御定全唐诗','yuding','','[]','丹觜如簧翠羽輕，隨人呼物旋知名。金籠夜黯山西夢，',40,'御定全唐詩/json/707.json','["丹觜如簧翠羽輕，隨人呼物旋知名。金籠夜黯山西夢，", "應緣是我邯鄲客，相顧咬咬別有情。"]'),
('yuding-9','邊將別','殷文圭','唐','御定全唐诗','yuding','','[]','地角天涯倍苦辛，十年鉛槧未酬身。朱門泣別同鮫客，',40,'御定全唐詩/json/707.json','["地角天涯倍苦辛，十年鉛槧未酬身。朱門泣別同鮫客，", "行行獨止干戈域，毳帳望誰為主人。"]'),
('yuding-10','江南秋日','殷文圭','唐','御定全唐诗','yuding','','[]','水國由來稱道情，野人經此頓神清。一篷秋雨睡初起，',40,'御定全唐詩/json/707.json','["水國由來稱道情，野人經此頓神清。一篷秋雨睡初起，", "冰綃寫上江南景，寄與金鑾馬長卿。"]'),
('yuding-11','題友人庭竹','殷文圭','唐','御定全唐诗','yuding','','[]','叢篁蕭瑟拂清陰，貴地栽成碧玉林。盡待花開添鳳食，',40,'御定全唐詩/json/707.json','["叢篁蕭瑟拂清陰，貴地栽成碧玉林。盡待花開添鳳食，", "何事子猷偏寄賞，此君心似古人心。"]'),
('yuding-12','覽陸龜蒙舊集','殷文圭','唐','御定全唐诗','yuding','','[]','先生文價沸三吳，白雪千編酒一壺。吟去星辰筆下動，',40,'御定全唐詩/json/707.json','["先生文價沸三吳，白雪千編酒一壺。吟去星辰筆下動，", "身後獨遺封禪草，何人尋得佐鴻圖。"]'),
('yuding-13','玉仙道中','殷文圭','唐','御定全唐诗','yuding','','[]','蓴鱸方美別吳江，筆陣詩魔兩未降。山勢北蟠龍偃蹇，',40,'御定全唐詩/json/707.json','["蓴鱸方美別吳江，筆陣詩魔兩未降。山勢北蟠龍偃蹇，", "信馬冷吟迷路處，隔溪煙雨吠村厖。"]'),
('yuding-14','趙侍郎看紅白牡丹，因寄楊狀頭贊圖','殷文圭','唐','御定全唐诗','yuding','','[]','遲開都為讓群芳，貴地栽成對玉堂。紅豔嫋煙疑欲語，',40,'御定全唐詩/json/707.json','["遲開都為讓群芳，貴地栽成對玉堂。紅豔嫋煙疑欲語，", "雅稱花中為首冠，年年長占斷春光。"]'),
('yuding-15','題胡州太學丘光庭博士幽居','殷文圭','唐','御定全唐诗','yuding','','[]','舜軌堯文混九垓，明堂宏構集良材。江邊雲臥如龍穩，',40,'御定全唐詩/json/707.json','["舜軌堯文混九垓，明堂宏構集良材。江邊雲臥如龍穩，", "草玄門似山中靜，不是公卿到不開。"]'),
('yuding-16','初秋留別越中幕客','殷文圭','唐','御定全唐诗','yuding','','[]','魂夢飄零落葉洲，北轅南柁幾時休。月中青桂漸看老，',40,'御定全唐詩/json/707.json','["魂夢飄零落葉洲，北轅南柁幾時休。月中青桂漸看老，", "吳花越柳饒君醉，直待功成始舉頭。"]'),
('yuding-17','送道者朝見後歸山','殷文圭','唐','御定全唐诗','yuding','','[]','暫隨蒲帛謁金鑾，蕭灑風儀傲漢官。天馬難將朱索絆，',40,'御定全唐詩/json/707.json','["暫隨蒲帛謁金鑾，蕭灑風儀傲漢官。天馬難將朱索絆，", "神鼎已幹龍虎伏，一條真氣出雲端。"]'),
('yuding-18','贈戰將','殷文圭','唐','御定全唐诗','yuding','','[]','綠沈槍利雪峰尖，犀甲軍裝稱紫髯。威懾萬人長凜凜，',40,'御定全唐詩/json/707.json','["綠沈槍利雪峰尖，犀甲軍裝稱紫髯。威懾萬人長凜凜，", "不為已為儒弟子，好依門下學韜鈐。"]'),
('yuding-19','九華賀雨吟','殷文圭','唐','御定全唐诗','yuding','','[]','陶公焦思念生靈，變旱為豐合杳冥。雷劈老松疑虎怒，',40,'御定全唐詩/json/707.json','["陶公焦思念生靈，變旱為豐合杳冥。雷劈老松疑虎怒，", "吟賀西成饒旅興，散絲飛灑滿長亭。"]'),
('yuding-20','贈池州張太守','殷文圭','唐','御定全唐诗','yuding','','[]','神珠無纇玉無瑕，七葉簪貂漢相家。陣面奔星破犀象，',40,'御定全唐詩/json/707.json','["神珠無纇玉無瑕，七葉簪貂漢相家。陣面奔星破犀象，", "只怕池人留不住，別遷征鎮擁高牙。"]'),
('yuding-21','中秋自宛陵寄池陽太守','殷文圭','唐','御定全唐诗','yuding','','[]','出山三見月如眉，蝶夢終宵繞戟枝。旅客思歸鴻去日，',40,'御定全唐詩/json/707.json','["出山三見月如眉，蝶夢終宵繞戟枝。旅客思歸鴻去日，", "按部況聞秋稼熟，馬前迎拜羨並兒。"]'),
('yuding-22','次韻九華杜先輩重陽寄投宛陵丞相','殷文圭','唐','御定全唐诗','yuding','','[]','日下飛聲徹不毛，酒醒時得廣離騷。先生鬢為吟詩白，',40,'御定全唐詩/json/707.json','["日下飛聲徹不毛，酒醒時得廣離騷。先生鬢為吟詩白，", "強酬小謝重陽句，沙恨無金盡日淘。"]'),
('yuding-23','寄賀杜荀鶴及第','殷文圭','唐','御定全唐诗','yuding','','[]','一戰平疇五字勞，晝歸鄉去錦為袍。大鵬出海翎猶濕，',40,'御定全唐詩/json/707.json','["一戰平疇五字勞，晝歸鄉去錦為袍。大鵬出海翎猶濕，", "由來稽古符公道，平地丹梯甲乙高。"]'),
('yuding-24','春草碧色','殷文圭','唐','御定全唐诗','yuding','','[]','細草含愁碧，芊綿南浦濱。萋萋如恨別，苒苒共傷春。',72,'御定全唐詩/json/707.json','["細草含愁碧，芊綿南浦濱。萋萋如恨別，苒苒共傷春。", "疏雨煙華潤，斜陽細彩勻。花粘繁鬥錦，人藉軟勝茵。", "淺映宮池水，輕遮輦路塵。杜回如可結，誓作報恩身。"]'),
('yuding-25','和友人送衡尚書赴池陽副車','殷文圭','唐','御定全唐诗','yuding','','[]','淮王上將例分憂，玉帳參承半列侯。次第選材如創廈，',88,'御定全唐詩/json/707.json','["淮王上將例分憂，玉帳參承半列侯。次第選材如創廈，", "躞蹀行牽金鋄重，嬋娟立唱翠娥愁。築頭勳業諧三陣，", "赤鱗旆卷鷗汀晚，青雀船橫雁陣秋。十字細波澄鏡面，", "況是昭明食魚郡，不妨閑擲釣璜鉤。"]'),
('yuding-26','貽李南平','殷文圭','唐','御定全唐诗','yuding','','[]','紫殿西頭月欲斜，曾草臨淮上相麻。',32,'御定全唐詩/json/707.json','["紫殿西頭月欲斜，曾草臨淮上相麻。", "潤筆已曾經奏謝，更飛章句問張華。"]'),
('yuding-27','句','殷文圭','唐','御定全唐诗','yuding','','[]','龍舒太守人中傑，風韻堂中心似月。',43,'御定全唐詩/json/707.json','["龍舒太守人中傑，風韻堂中心似月。", "眾口聲光誇漢將，築頭勳業佐淮王。（《賀池陽太守正命》，"]'),
('yuding-0','釣台','徐夤','唐','御定全唐诗','yuding','','[]','金門誰奉詔，碧岸獨垂鉤。舊友只樵叟，新交惟野鷗。',48,'御定全唐詩/json/708.json','["金門誰奉詔，碧岸獨垂鉤。舊友只樵叟，新交惟野鷗。", "嘉名懸日月，深谷化陵丘。便可招巢父，長川好飲牛。"]'),
('yuding-1','旅次寓題','徐夤','唐','御定全唐诗','yuding','','[]','胡為名利役，來往老關河。白髮隨梳少，青山入夢多。',48,'御定全唐詩/json/708.json','["胡為名利役，來往老關河。白髮隨梳少，青山入夢多。", "途窮憐抱疾，世亂恥登科。卻起漁舟念，春風釣綠波。"]'),
('yuding-2','贈嚴司直','徐夤','唐','御定全唐诗','yuding','','[]','承家居闕下，避世出關東。有酒劉伶醉，無兒伯道窮。',48,'御定全唐詩/json/708.json','["承家居闕下，避世出關東。有酒劉伶醉，無兒伯道窮。", "新詩吟閣賞，舊業釣台空。雨雪還相訪，心懷與我同。"]'),
('yuding-3','贈東方道士','徐夤','唐','御定全唐诗','yuding','','[]','葫蘆窗畔掛，是物在其間。雪色老人鬢，桃花童子顏。',48,'御定全唐詩/json/708.json','["葫蘆窗畔掛，是物在其間。雪色老人鬢，桃花童子顏。", "祭星秋蔔日，采藥曉登山。舊放長生鹿，時銜瑞草還。"]'),
('yuding-4','題僧壁','徐夤','唐','御定全唐诗','yuding','','[]','香廚流瀑布，獨院鎖孤峰。紺發青螺長，文茵紫豹重。',48,'御定全唐詩/json/708.json','["香廚流瀑布，獨院鎖孤峰。紺發青螺長，文茵紫豹重。", "卵枯皆化燕，蜜老卻成蜂。明月留人宿，秋聲夜著松。"]'),
('yuding-5','和人經隋唐間戰處','徐夤','唐','御定全唐诗','yuding','','[]','孤軍前度戰，一敗一成功。卷旆早歸國，臥屍猶臂弓。',48,'御定全唐詩/json/708.json','["孤軍前度戰，一敗一成功。卷旆早歸國，臥屍猶臂弓。", "草間腥半在，沙上血殘紅。傷魄何為者，五湖垂釣翁。"]'),
('yuding-6','追和常建歎王昭君','徐夤','唐','御定全唐诗','yuding','','[]','紅顏如朔雪，日爍忽成空。淚盡黃雲雨，塵消白草風。',48,'御定全唐詩/json/708.json','["紅顏如朔雪，日爍忽成空。淚盡黃雲雨，塵消白草風。", "君心爭不悔，恨思竟何窮。願化南飛燕，年年入漢宮。"]'),
('yuding-7','贈董先生','徐夤','唐','御定全唐诗','yuding','','[]','壽歲過於百，時閑到上京。餐松雙鬢嫩，絕粒四支輕。',48,'御定全唐詩/json/708.json','["壽歲過於百，時閑到上京。餐松雙鬢嫩，絕粒四支輕。", "雨雪思中嶽，雲霞夢赤城。來年期壽籙，何處待先生。"]'),
('yuding-8','河流','徐夤','唐','御定全唐诗','yuding','','[]','洪流盤砥柱，淮濟不同波。莫訝清時少，都緣曲處多。',48,'御定全唐詩/json/708.json','["洪流盤砥柱，淮濟不同波。莫訝清時少，都緣曲處多。", "遠能通玉塞，高複接銀河。大禹成門嶮，為龍始得過。"]'),
('yuding-9','題南寺','徐夤','唐','御定全唐诗','yuding','','[]','久別猿啼寺，流年劫逝波。舊僧歸塔盡，古瓦長松多。',48,'御定全唐詩/json/708.json','["久別猿啼寺，流年劫逝波。舊僧歸塔盡，古瓦長松多。", "壁蘚昏題記，窗螢散薜蘿。平生英壯節，何故旋消磨。"]'),
('yuding-10','北山秋晚','徐夤','唐','御定全唐诗','yuding','','[]','十載衣裘盡，臨寒隱薜蘿。心閑緣事少，身老愛山多。',48,'御定全唐詩/json/708.json','["十載衣裘盡，臨寒隱薜蘿。心閑緣事少，身老愛山多。", "玉露催收菊，金風促剪禾。燕秦正戎馬，林下好婆娑。"]'),
('yuding-11','昔游','徐夤','唐','御定全唐诗','yuding','','[]','昔游紅杏苑，今隱刺桐村。歲計懸僧債，科名負國恩。',48,'御定全唐詩/json/708.json','["昔游紅杏苑，今隱刺桐村。歲計懸僧債，科名負國恩。", "不書胝漸穩，頻鑷鬢無根。惟有經邦事，年年志尚存。"]'),
('yuding-12','酒鬍子','徐夤','唐','御定全唐诗','yuding','','[]','紅筵絲竹合，用爾作歡娛。直指寧偏黨，無私絕覬覦。',48,'御定全唐詩/json/708.json','["紅筵絲竹合，用爾作歡娛。直指寧偏黨，無私絕覬覦。", "當歌誰擐袖，應節漸輕軀。恰與真相似，氈裘滿頷須。"]'),
('yuding-13','吊崔補闕','徐夤','唐','御定全唐诗','yuding','','[]','近來吾道少，慟哭博陵君。直節岩前竹，孤魂嶺上雲。',48,'御定全唐詩/json/708.json','["近來吾道少，慟哭博陵君。直節岩前竹，孤魂嶺上雲。", "縉紳傳確論，丞相取遺文。廢卻中興策，何由免用軍。"]'),
('yuding-14','吊赤水李先生','徐夤','唐','御定全唐诗','yuding','','[]','三年悲過隙，一室類銷冰。妻病入仙觀，子窮隨嶽僧。',48,'御定全唐詩/json/708.json','["三年悲過隙，一室類銷冰。妻病入仙觀，子窮隨嶽僧。", "荒丘寒有雨，古屋夜無燈。往日清猷著，金門幾欲征。"]'),
('yuding-15','香鴨','徐夤','唐','御定全唐诗','yuding','','[]','不假陶熔妙，誰教羽翼全。五金池畔質，百和口中煙。',48,'御定全唐詩/json/708.json','["不假陶熔妙，誰教羽翼全。五金池畔質，百和口中煙。", "觜鈍魚難啄，心空火自燃。禦爐如有闕，須進聖君前。"]'),
('yuding-16','雞','徐夤','唐','御定全唐诗','yuding','','[]','名參十二屬，花入羽毛深。守信催朝日，能鳴送曉陰。',48,'御定全唐詩/json/708.json','["名參十二屬，花入羽毛深。守信催朝日，能鳴送曉陰。", "峨冠裝瑞璧，利爪削黃金。徒有稻粱感，何由報德音。"]'),
('yuding-17','白鴿','徐夤','唐','御定全唐诗','yuding','','[]','舉翼淩空碧，依人到大邦。粉翎棲畫閣，雪影拂瓊窗。',48,'御定全唐詩/json/708.json','["舉翼淩空碧，依人到大邦。粉翎棲畫閣，雪影拂瓊窗。", "振鷺堪為侶，鳴鳩好作雙。狎鷗歸未得，睹爾憶晴江。"]'),
('yuding-18','龜','徐夤','唐','御定全唐诗','yuding','','[]','行止竟何從，深溪與古峰。青荷巢瑞質，綠水返靈蹤。',48,'御定全唐詩/json/708.json','["行止竟何從，深溪與古峰。青荷巢瑞質，綠水返靈蹤。", "鑽骨神明應，酬恩感激重。仙翁求一卦，何日脫龍鍾。"]'),
('yuding-19','銀結條冠子','徐夤','唐','御定全唐诗','yuding','','[]','日下征良匠，宮中贈阿嬌。瑞蓮開二孕，瓊縷織千條。',48,'御定全唐詩/json/708.json','["日下征良匠，宮中贈阿嬌。瑞蓮開二孕，瓊縷織千條。", "蟬翼輕輕結，花紋細細挑。舞時紅袖舉，纖影透龍綃。"]'),
('yuding-20','蜀葵','徐夤','唐','御定全唐诗','yuding','','[]','劍門南面樹，移向會仙亭。錦水饒花豔，岷山帶葉青。',48,'御定全唐詩/json/708.json','["劍門南面樹，移向會仙亭。錦水饒花豔，岷山帶葉青。", "文君慚婉娩，神女讓娉婷。爛熳紅兼紫，飄香入繡扃。"]'),
('yuding-21','華清宮','徐夤','唐','御定全唐诗','yuding','','[]','十二瓊樓鎖翠微，暮霞遺卻六銖衣。桐枯丹穴鳳何去，',40,'御定全唐詩/json/708.json','["十二瓊樓鎖翠微，暮霞遺卻六銖衣。桐枯丹穴鳳何去，", "君王魂斷驪山路，且向蓬瀛伴貴妃。"]'),
('yuding-22','再幸華清宮','徐夤','唐','御定全唐诗','yuding','','[]','腸斷將軍改葬歸，錦囊香在憶當時。年來卻恨相思樹，',40,'御定全唐詩/json/708.json','["腸斷將軍改葬歸，錦囊香在憶當時。年來卻恨相思樹，", "霓裳舊曲飛霜殿，夢破魂驚絕後期。"]'),
('yuding-23','喜雨上主人尚書','徐夤','唐','御定全唐诗','yuding','','[]','天皇攘袂敕神龍，雨我公田兆歲豐。幾日淋漓侵暮角，',40,'御定全唐詩/json/708.json','["天皇攘袂敕神龍，雨我公田兆歲豐。幾日淋漓侵暮角，", "門下十年耕稼者，坐來偏憶翠微峰。"]'),
('yuding-24','回文詩二首','徐夤','唐','御定全唐诗','yuding','','[]','飛書一幅錦文回，恨寫深情寄雁來。機上月殘香閣掩，',80,'御定全唐詩/json/708.json','["飛書一幅錦文回，恨寫深情寄雁來。機上月殘香閣掩，", "歸日幾人行問卜，徽音想望倚高臺。", "輕帆數點千峰碧，水接雲山四望遙。晴日海霞紅靄靄，", "明月釣舟漁浦遠，傾山雪浪暗隨潮。"]'),
('yuding-25','不把漁竿','徐夤','唐','御定全唐诗','yuding','','[]','不把漁竿不灌園，策筇吟繞綠蕪村。得爭野老眠雲樂，',40,'御定全唐詩/json/708.json','["不把漁竿不灌園，策筇吟繞綠蕪村。得爭野老眠雲樂，", "何人買我安貧趣，百萬黃金未可論。"]'),
('yuding-26','古往今來','徐夤','唐','御定全唐诗','yuding','','[]','古往今來恨莫窮，不如沈醉臥春風。雀兒無角長穿屋，',40,'御定全唐詩/json/708.json','["古往今來恨莫窮，不如沈醉臥春風。雀兒無角長穿屋，", "閑思郭令長安宅，草沒匡牆舊事空。"]'),
('yuding-27','十裏煙籠','徐夤','唐','御定全唐诗','yuding','','[]','十裏煙籠一徑分，故人迢遞久離群。白雲明月皆由我，',40,'御定全唐詩/json/708.json','["十裏煙籠一徑分，故人迢遞久離群。白雲明月皆由我，", "北邙坡上青松下，儘是鏘金佩玉墳。"]'),
('yuding-28','偶書','徐夤','唐','御定全唐诗','yuding','','[]','巧者多為拙者資，良籌第一在乘時。市門逐利終身飽，',40,'御定全唐詩/json/708.json','["巧者多為拙者資，良籌第一在乘時。市門逐利終身飽，", "高皇冷笑重瞳客，蓋世拔山何所為。"]'),
('yuding-29','潤屋','徐夤','唐','御定全唐诗','yuding','','[]','潤屋豐家莫妄求，眼看多是與身讎。百禽羅得皆黃口，',40,'御定全唐詩/json/708.json','["潤屋豐家莫妄求，眼看多是與身讎。百禽羅得皆黃口，", "朱門粉署何由到，空寄新詩謝列侯。"]'),
('yuding-30','退居','徐夤','唐','御定全唐诗','yuding','','[]','鶴性松心合在山，五侯門館怯趨攀。三年臥病不能免，',40,'御定全唐詩/json/708.json','["鶴性松心合在山，五侯門館怯趨攀。三年臥病不能免，", "笑他範蠡貪婪甚，相罷金多始退閑。"]'),
('yuding-31','閉門','徐夤','唐','御定全唐诗','yuding','','[]','閉卻閑門臥小窗。更何人與療膏肓。一生有酒唯知醉，',40,'御定全唐詩/json/708.json','["閉卻閑門臥小窗。更何人與療膏肓。一生有酒唯知醉，", "漳濱伏枕文園渴，盜蹠縱橫似虎狼。"]'),
('yuding-32','開窗','徐夤','唐','御定全唐诗','yuding','','[]','閉戶開窗寢又興，三更時節也如冰。長閑便是忘機者，',40,'御定全唐詩/json/708.json','["閉戶開窗寢又興，三更時節也如冰。長閑便是忘機者，", "薔薇花盡熏風起，綠葉空隨滿架藤。"]'),
('yuding-33','燈花','徐夤','唐','御定全唐诗','yuding','','[]','點蠟燒銀卻勝栽，九華紅豔吐玫瑰。獨含冬夜寒光拆，',40,'御定全唐詩/json/708.json','["點蠟燒銀卻勝栽，九華紅豔吐玫瑰。獨含冬夜寒光拆，", "貪膏附熱多相誤，為報飛蛾罷拂來。"]'),
('yuding-34','東歸出城留別知己','徐夤','唐','御定全唐诗','yuding','','[]','韋蒙屈指許非才，三載長安共酒杯。欲別未攀楊柳贈，',40,'御定全唐詩/json/708.json','["韋蒙屈指許非才，三載長安共酒杯。欲別未攀楊柳贈，", "他日因書問衰颯，東溪須訪子陵台。"]'),
('yuding-35','詠懷','徐夤','唐','御定全唐诗','yuding','','[]','愁花變出白髭須，半世辛勤一事無。道在或期君夢想，',40,'御定全唐詩/json/708.json','["愁花變出白髭須，半世辛勤一事無。道在或期君夢想，", "借取秦宮臺上鏡，為時開照漢妖狐。"]'),
('yuding-36','郊村獨游','徐夤','唐','御定全唐诗','yuding','','[]','歲閏堪憐曆候遲，出門惟與野雲期。驚魚擲上綠荷芰，',40,'御定全唐詩/json/708.json','["歲閏堪憐曆候遲，出門惟與野雲期。驚魚擲上綠荷芰，", "市頭相者休相戲，蹙膝先生半自知。"]'),
('yuding-37','經故翰林楊左丞池亭','徐夤','唐','御定全唐诗','yuding','','[]','八角紅亭蔭綠池，一朝青草蓋遺基。薔薇藤老開花淺，',40,'御定全唐詩/json/708.json','["八角紅亭蔭綠池，一朝青草蓋遺基。薔薇藤老開花淺，", "平生德義人間誦，身後何勞更立碑。"]'),
('yuding-38','經故廣平員外舊宅','徐夤','唐','御定全唐诗','yuding','','[]','門巷蕭條引涕洟，遺孤三歲著麻衣。綠楊樹老垂絲短，',40,'御定全唐詩/json/708.json','["門巷蕭條引涕洟，遺孤三歲著麻衣。綠楊樹老垂絲短，", "平生欲獻匡君策，抱病猶言未息機。"]'),
('yuding-39','潘丞相舊宅','徐夤','唐','御定全唐诗','yuding','','[]','綠樹垂枝蔭四鄰，春風還似舊時春。年年燕是雕梁主，',40,'御定全唐詩/json/708.json','["綠樹垂枝蔭四鄰，春風還似舊時春。年年燕是雕梁主，", "秋槐影薄蟬聲盡，休謂龍門待化鱗。"]'),
('yuding-40','門外閒田數畝長有泉源因築直堤分為兩沼','徐夤','唐','御定全唐诗','yuding','','[]','左右澄漪小檻前，直堤高築古平川。十分春水雙簷影，',40,'御定全唐詩/json/708.json','["左右澄漪小檻前，直堤高築古平川。十分春水雙簷影，", "坐來暗起江湖思，速問溪翁買釣船。"]'),
('yuding-41','北園','徐夤','唐','御定全唐诗','yuding','','[]','北園幹葉旋空枝，蘭蕙還將眾草衰。籠鳥上天猶有待，',40,'御定全唐詩/json/708.json','["北園幹葉旋空枝，蘭蕙還將眾草衰。籠鳥上天猶有待，", "生事罷求名與利，一窗書策是年支。"]'),
('yuding-42','溪上要一隻白簟扇蓋頭垂釣去年就節推…遂成拙句','徐夤','唐','御定全唐诗','yuding','','[]','難求珍箑過炎天，遠就金貂乞月圓。直在引風欹角枕，',40,'御定全唐詩/json/708.json','["難求珍箑過炎天，遠就金貂乞月圓。直在引風欹角枕，", "莫道如今時較晚，也應留得到明年。"]'),
('yuding-43','招隱','徐夤','唐','御定全唐诗','yuding','','[]','齒發那能敵歲華，早知休去避塵沙。鬼神只闞高明裏，',40,'御定全唐詩/json/708.json','["齒發那能敵歲華，早知休去避塵沙。鬼神只闞高明裏，", "贈君吉語堪銘座，看取朝開暮落花。"]'),
('yuding-44','憶山中友人','徐夤','唐','御定全唐诗','yuding','','[]','憶得當年接善鄰，苦將閒事強夫君。鬥開碧沼分明月，',40,'御定全唐詩/json/708.json','["憶得當年接善鄰，苦將閒事強夫君。鬥開碧沼分明月，", "金門幾欲言西上，惆悵關河正用軍。"]'),
('yuding-45','溪隱','徐夤','唐','御定全唐诗','yuding','','[]','將名將利已無緣，深隱清溪擬學仙。絕卻腥膻勝服藥，',40,'御定全唐詩/json/708.json','["將名將利已無緣，深隱清溪擬學仙。絕卻腥膻勝服藥，", "鸞鶴久從籠檻閉，春風卻放紙為鳶。"]'),
('yuding-46','酒醒','徐夤','唐','御定全唐诗','yuding','','[]','酒醒欲得適閒情，騎馬那勝策杖行。天暖天寒三月暮，',40,'御定全唐詩/json/708.json','["酒醒欲得適閒情，騎馬那勝策杖行。天暖天寒三月暮，", "望斷長安故交遠，來書未說九河清。"]'),
('yuding-47','夢斷','徐夤','唐','御定全唐诗','yuding','','[]','夢斷紗窗半夜雷，別君花落又花開。漁陽路遠書難寄，',40,'御定全唐詩/json/708.json','["夢斷紗窗半夜雷，別君花落又花開。漁陽路遠書難寄，", "人生若得長相對，螢火生煙草化灰。"]'),
('yuding-48','人事','徐夤','唐','御定全唐诗','yuding','','[]','人事飄如一炷煙，且須求佛與求仙。豐年甲子春無雨，',40,'御定全唐詩/json/708.json','["人事飄如一炷煙，且須求佛與求仙。豐年甲子春無雨，", "平生生計何為者，三徑蒼苔十畝田。"]'),
('yuding-49','休說','徐夤','唐','御定全唐诗','yuding','','[]','休說人間有陸沈，一樽閑待月明斟。時來不怕滄溟闊，',40,'御定全唐詩/json/708.json','["休說人間有陸沈，一樽閑待月明斟。時來不怕滄溟闊，", "梓桐賦罷相如隱，誰為君前永夜吟。"]'),
('yuding-50','嘉運','徐夤','唐','御定全唐诗','yuding','','[]','嘉運良時兩阻修，釣竿蓑笠樂林丘。家無寸帛渾閒事，',40,'御定全唐詩/json/708.json','["嘉運良時兩阻修，釣竿蓑笠樂林丘。家無寸帛渾閒事，", "晨炊一箸紅銀粒，憶著長安索米秋。"]'),
('yuding-51','綠鬢','徐夤','唐','御定全唐诗','yuding','','[]','綠鬢先生自出林，孟光同樂野雲深。躬耕為食古人操，',40,'御定全唐詩/json/708.json','["綠鬢先生自出林，孟光同樂野雲深。躬耕為食古人操，", "君看黃閣南遷客，一過瀧州絕好音。"]'),
('yuding-52','驕侈','徐夤','唐','御定全唐诗','yuding','','[]','驕侈阽危儉素牢，鏡中形影豈能逃。石家恃富身還滅，',40,'御定全唐詩/json/708.json','["驕侈阽危儉素牢，鏡中形影豈能逃。石家恃富身還滅，", "古今人事惟堪醉，好脫霜裘換綠醪。"]'),
('yuding-53','龍蟄二首','徐夤','唐','御定全唐诗','yuding','','[]','龍蟄蛇蟠卻待伸，和光何惜且同塵。伍員豈是吹簫者，',80,'御定全唐詩/json/708.json','["龍蟄蛇蟠卻待伸，和光何惜且同塵。伍員豈是吹簫者，", "穰侯休忌關東客，張祿先生竟相秦。", "休說雄才間代生，到頭難與運相爭。時通有詔征枚乘，", "中林且作煙霞侶，塵滿關河未可行。"]'),
('yuding-54','逐臭蒼蠅','徐夤','唐','御定全唐诗','yuding','','[]','逐臭蒼蠅豈有為，清蟬吟露最高奇。多藏苟得何名富，',40,'御定全唐詩/json/708.json','["逐臭蒼蠅豈有為，清蟬吟露最高奇。多藏苟得何名富，", "首陽山翠千年在，好奠冰壺吊伯夷。"]'),
('yuding-55','牡丹花二首','徐夤','唐','御定全唐诗','yuding','','[]','看遍花無勝此花，剪雲披雪蘸丹砂。開當青律二三月，',80,'御定全唐詩/json/708.json','["看遍花無勝此花，剪雲披雪蘸丹砂。開當青律二三月，", "不隨寒令同時放，倍種雙松與辟邪。", "萬萬花中第一流，淺霞輕染嫩銀甌。能狂綺陌千金子，", "詩書滿架塵埃撲，盡日無人略舉頭。"]'),
('yuding-56','尚書座上賦牡丹花得輕字韻其花自越中移植','徐夤','唐','御定全唐诗','yuding','','[]','流蘇凝作瑞華精，仙閣開時麗日晴。霜月冷銷銀燭焰，',40,'御定全唐詩/json/708.json','["流蘇凝作瑞華精，仙閣開時麗日晴。霜月冷銷銀燭焰，", "早晚有人天上去，寄他將贈董雙成。"]'),
('yuding-57','依韻和尚書再贈牡丹花','徐夤','唐','御定全唐诗','yuding','','[]','爛銀基地薄紅妝，羞殺千花百卉芳。紫陌昔曾遊寺看，',40,'御定全唐詩/json/708.json','["爛銀基地薄紅妝，羞殺千花百卉芳。紫陌昔曾遊寺看，", "多著黃金何處買，輕橈挑過鏡湖光。"]'),
('yuding-58','郡庭惜牡丹','徐夤','唐','御定全唐诗','yuding','','[]','腸斷東風落牡丹，為祥為瑞久留難。青春不駐堪垂淚，',40,'御定全唐詩/json/708.json','["腸斷東風落牡丹，為祥為瑞久留難。青春不駐堪垂淚，", "明年萬葉千枝長，倍發芳菲借客看。"]'),
('yuding-59','追和白舍人詠白牡丹','徐夤','唐','御定全唐诗','yuding','','[]','蓓蕾抽開素練囊，瓊葩熏出白龍香。裁分楚女朝雲片，',40,'御定全唐詩/json/708.json','["蓓蕾抽開素練囊，瓊葩熏出白龍香。裁分楚女朝雲片，", "檻邊幾笑東籬菊，冷折金風待降霜。"]'),
('yuding-60','憶牡丹','徐夤','唐','御定全唐诗','yuding','','[]','綠樹多和雪霰栽，長安一別十年來。王侯買得價偏重，',40,'御定全唐詩/json/708.json','["綠樹多和雪霰栽，長安一別十年來。王侯買得價偏重，", "滄洲春暮空腸斷，畫看猶將勸酒杯。"]'),
('yuding-61','惜牡丹','徐夤','唐','御定全唐诗','yuding','','[]','今日狂風揭錦筵，預愁吹落夕陽天。閑看紅豔只須醉，',40,'御定全唐詩/json/708.json','["今日狂風揭錦筵，預愁吹落夕陽天。閑看紅豔只須醉，", "良時雖作鶯花主，白馬王孫恰少年。"]'),
('yuding-62','覽柳渾汀洲采白蘋之什，因成一章','徐夤','唐','御定全唐诗','yuding','','[]','采盡汀蘋恨別離，鴛鴦鸂鶒總雙飛。月明南浦夢初斷，',40,'御定全唐詩/json/708.json','["采盡汀蘋恨別離，鴛鴦鸂鶒總雙飛。月明南浦夢初斷，", "年來泣淚知多少，重疊成痕在繡衣。"]'),
('yuding-63','司直巡官無諸移到玫瑰花','徐夤','唐','御定全唐诗','yuding','','[]','芳菲移自越王台，最似薔薇好並栽。穠豔盡憐勝彩繪，',40,'御定全唐詩/json/708.json','["芳菲移自越王台，最似薔薇好並栽。穠豔盡憐勝彩繪，", "為報朱衣早邀客，莫教零落委蒼苔。"]'),
('yuding-64','梅花','徐夤','唐','御定全唐诗','yuding','','[]','瓊瑤初綻嶺頭葩，蕊粉新妝姹女家。舉世更誰憐潔白，',40,'御定全唐詩/json/708.json','["瓊瑤初綻嶺頭葩，蕊粉新妝姹女家。舉世更誰憐潔白，", "結實和羹知有日，肯隨羌笛落天涯。"]'),
('yuding-65','荔枝二首','徐夤','唐','御定全唐诗','yuding','','[]','朱彈星丸粲日光，綠瓊枝散小香囊。龍綃殼綻紅紋粟，',80,'御定全唐詩/json/708.json','["朱彈星丸粲日光，綠瓊枝散小香囊。龍綃殼綻紅紋粟，", "蠻山蹋曉和煙摘，拜捧金盤奉越王。", "日日熏風卷瘴煙，南園珍果荔枝先。靈鴉啄破瓊津滴，", "何人刺出猩猩血，深染羅紋遍殼鮮。"]'),
('yuding-66','菊花','徐夤','唐','御定全唐诗','yuding','','[]','桓景登高事可尋，黃花開處綠畦深。消災辟惡君須采，',40,'御定全唐詩/json/708.json','["桓景登高事可尋，黃花開處綠畦深。消災辟惡君須采，", "陶公豈是居貧者，剩有東籬萬朵金。"]'),
('yuding-67','畫松','徐夤','唐','御定全唐诗','yuding','','[]','澗底陰森驗筆精，筆閑開展覺神清。曾當月照還無影，',40,'御定全唐詩/json/708.json','["澗底陰森驗筆精，筆閑開展覺神清。曾當月照還無影，", "天臺道士頻來見，說似株株倚赤城。"]'),
('yuding-68','草木','徐夤','唐','御定全唐诗','yuding','','[]','草木無情亦可嗟，重開明鏡照無涯。菊英空折羅含宅，',40,'御定全唐詩/json/708.json','["草木無情亦可嗟，重開明鏡照無涯。菊英空折羅含宅，", "仙翁乞取金盤露，洗卻蒼蒼兩鬢華。"]'),
('yuding-69','松','徐夤','唐','御定全唐诗','yuding','','[]','澗底青松不染塵，未逢良匠競誰分。龍盤勁節岩前見，',40,'御定全唐詩/json/708.json','["澗底青松不染塵，未逢良匠競誰分。龍盤勁節岩前見，", "皇王自有增封日，修竹徒勞號此君。"]'),
('yuding-70','竹','徐夤','唐','御定全唐诗','yuding','','[]','翠染琅玕粉漸開，東南移得會稽栽。遊絲掛處漁竿去，',40,'御定全唐詩/json/708.json','["翠染琅玕粉漸開，東南移得會稽栽。遊絲掛處漁竿去，", "王猷舊宅無人到，抱卻清陰蓋綠苔。"]'),
('yuding-71','尚書打球，小驄步驟最奇，因有所贈','徐夤','唐','御定全唐诗','yuding','','[]','善價千金未可論，燕王新寄小龍孫。逐將白日馳青漢，',40,'御定全唐詩/json/708.json','["善價千金未可論，燕王新寄小龍孫。逐將白日馳青漢，", "桃花雪點多雖貴，全假當場一顧恩。"]'),
('yuding-72','尚書惠蠟麵茶','徐夤','唐','御定全唐诗','yuding','','[]','武夷春暖月初圓，採摘新芽獻地仙。飛鵲印成香蠟片，',40,'御定全唐詩/json/708.json','["武夷春暖月初圓，採摘新芽獻地仙。飛鵲印成香蠟片，", "分贈恩深知最異，晚鐺宜煮北山泉。"]'),
('yuding-73','勸酒','徐夤','唐','御定全唐诗','yuding','','[]','休向尊前訴羽觥，百壺清酌與君傾。身同綠樹年年老，',40,'御定全唐詩/json/708.json','["休向尊前訴羽觥，百壺清酌與君傾。身同綠樹年年老，", "醉鄉路與乾坤隔，豈信人間有利名。"]'),
('yuding-74','斷酒','徐夤','唐','御定全唐诗','yuding','','[]','因論沈湎覺前非，便碎金罍與羽卮。采茗早馳三蜀使，',40,'御定全唐詩/json/708.json','["因論沈湎覺前非，便碎金罍與羽卮。采茗早馳三蜀使，", "此事十年前已說，匡廬山下老僧知。"]'),
('yuding-75','憶舊山','徐夤','唐','御定全唐诗','yuding','','[]','澗竹岩雲有舊期，二年頻長鬢邊絲。游魚不愛金杯水，',40,'御定全唐詩/json/708.json','["澗竹岩雲有舊期，二年頻長鬢邊絲。游魚不愛金杯水，", "龍爭虎攫皆閒事，數疊山光在夢思。"]'),
('yuding-0','西華','徐夤','唐','御定全唐诗','yuding','','[]','五千仞有餘神秀，一一排雲上泬。疊嶂出關分二陝，',40,'御定全唐詩/json/709.json','["五千仞有餘神秀，一一排雲上泬。疊嶂出關分二陝，", "拜祝金天乞陰德，為民求主降神堯。"]'),
('yuding-1','嵐似屏風','徐夤','唐','御定全唐诗','yuding','','[]','嵐似屏風草似茵，草邊時膾錦花鱗。山中宰相陶弘景，',40,'御定全唐詩/json/709.json','["嵐似屏風草似茵，草邊時膾錦花鱗。山中宰相陶弘景，", "君看東洛平泉宅，只有年年百卉春。"]'),
('yuding-2','憶潼關','徐夤','唐','御定全唐诗','yuding','','[]','洞壑雙扉入到初，似從深阱睹高墟。天開白日臨軍國，',40,'御定全唐詩/json/709.json','["洞壑雙扉入到初，似從深阱睹高墟。天開白日臨軍國，", "須知皇漢能扃鐍，延得年過四百餘。"]'),
('yuding-3','憶潼關早行','徐夤','唐','御定全唐诗','yuding','','[]','行客起看仙掌月，落星斜照濁河泥。故山遠處高飛雁，',40,'御定全唐詩/json/709.json','["行客起看仙掌月，落星斜照濁河泥。故山遠處高飛雁，", "芻蕘十軸僮三尺，豈謂青雲便有梯。"]'),
('yuding-4','鴻門','徐夤','唐','御定全唐诗','yuding','','[]','耨月耕煙水國春，薄徒應笑作農人。皇王尚法三推禮，',40,'御定全唐詩/json/709.json','["耨月耕煙水國春，薄徒應笑作農人。皇王尚法三推禮，", "猶勝墮力求飧者，五鬥低腰走世塵。"]'),
('yuding-5','憶長安行','徐夤','唐','御定全唐诗','yuding','','[]','舊曆關中憶廢興，僭奢須戒儉須憑。火光只是燒秦塚，',40,'御定全唐詩/json/709.json','["舊曆關中憶廢興，僭奢須戒儉須憑。火光只是燒秦塚，", "不如坐釣清溪月，心共寒潭一片澄。"]'),
('yuding-6','憶長安上省年','徐夤','唐','御定全唐诗','yuding','','[]','忽憶關中逐計車，曆坊騎馬信空虛。三秋病起見新雁，',40,'御定全唐詩/json/709.json','["忽憶關中逐計車，曆坊騎馬信空虛。三秋病起見新雁，", "如今說著猶堪泣，兩宿都堂過歲除。"]'),
('yuding-7','長安述懷','徐夤','唐','御定全唐诗','yuding','','[]','黃河冰合尚來遊，知命知時肯躁求。詞賦有名堪自負，',40,'御定全唐詩/json/709.json','["黃河冰合尚來遊，知命知時肯躁求。詞賦有名堪自負，", "十載公卿早言屈，何須課夏更冥搜。"]'),
('yuding-8','長安即事三首','徐夤','唐','御定全唐诗','yuding','','[]','拋擲清溪舊釣鉤，長安寒暑再環周。便隨鶯羽三春化，',120,'御定全唐詩/json/709.json','["拋擲清溪舊釣鉤，長安寒暑再環周。便隨鶯羽三春化，", "明時則待金門詔，肯羨班超萬戶侯。", "無酒窮愁結自舒，飲河求滿不求餘。身登霄漢平時第，", "明時用即匡君去，不用何妨卻釣魚。", "拖紫腰金不要論，便堪歸隱白雲村。更無名籍強金榜，", "高眠亦是前賢事，爭報春闈莫大恩。"]'),
('yuding-9','東京次新安道中','徐夤','唐','御定全唐诗','yuding','','[]','賊去兵來歲月長，野蒿空滿壞牆匡。旋從古轍成深谷，',40,'御定全唐詩/json/709.json','["賊去兵來歲月長，野蒿空滿壞牆匡。旋從古轍成深谷，", "殊時異世為儒者，不見文皇與武皇。"]'),
('yuding-10','山陰故事','徐夤','唐','御定全唐诗','yuding','','[]','坦腹夫君不可逢，千年猶在播英風。紅鵝化鶴青天遠，',40,'御定全唐詩/json/709.json','["坦腹夫君不可逢，千年猶在播英風。紅鵝化鶴青天遠，", "吹笙緱嶺登山後，東注清流豈有窮。"]'),
('yuding-11','溫陵即事','徐夤','唐','御定全唐诗','yuding','','[]','早年師友教為文，賣卻魚舟網典墳。國有安危期日諫，',40,'御定全唐詩/json/709.json','["早年師友教為文，賣卻魚舟網典墳。國有安危期日諫，", "爭得千鐘季孫粟，滄洲歸與故人分。"]'),
('yuding-12','溫陵殘臘書懷寄崔尚書','徐夤','唐','御定全唐诗','yuding','','[]','濟川無楫擬何為，三傑還從漢祖推。心學庭槐空發火，',40,'御定全唐詩/json/709.json','["濟川無楫擬何為，三傑還從漢祖推。心學庭槐空發火，", "江上年年接君子，一杯春酒一枰棋。"]'),
('yuding-13','義通裏寓居即事','徐夤','唐','御定全唐诗','yuding','','[]','家住寒梅翠嶺東，長安時節詠途窮。牡丹窠小春餘雨，',40,'御定全唐詩/json/709.json','["家住寒梅翠嶺東，長安時節詠途窮。牡丹窠小春餘雨，", "長卿甚有淩雲作，誰與清吟繞帝宮。"]'),
('yuding-14','上陽宮詞','徐夤','唐','御定全唐诗','yuding','','[]','點點苔錢上玉墀，日斜空望六龍西。妝台塵暗青鸞掩，',40,'御定全唐詩/json/709.json','["點點苔錢上玉墀，日斜空望六龍西。妝台塵暗青鸞掩，", "銀蟾借與金波路，得入重輪伴羿妻。"]'),
('yuding-15','西寨寓居','徐夤','唐','御定全唐诗','yuding','','[]','閑讀南華對酒杯，醉攜筇竹畫蒼苔。豪門有利人爭去，',80,'御定全唐詩/json/709.json','["閑讀南華對酒杯，醉攜筇竹畫蒼苔。豪門有利人爭去，", "嚴陵萬古清風在，好棹東溪詠釣台。", "功智爭馳淡薄空，猶懷忠信擬何從。鴟鳶啄腐疑雛鳳，", "崇侯入輔嚴陵退，堪憶啼猿萬仞峰。"]'),
('yuding-16','題福州天王閣','徐夤','唐','御定全唐诗','yuding','','[]','絕境宜棲獨角仙，金張到此亦忘還。三門裏面千層閣，',40,'御定全唐詩/json/709.json','["絕境宜棲獨角仙，金張到此亦忘還。三門裏面千層閣，", "有時海上看明月，輾出冰輪疊浪間。"]'),
('yuding-17','憶薦福寺南院','徐夤','唐','御定全唐诗','yuding','','[]','憶昔長安落第春，佛宮南院獨遊頻。燈前不動惟金像，',40,'御定全唐詩/json/709.json','["憶昔長安落第春，佛宮南院獨遊頻。燈前不動惟金像，", "啼猿溪上將歸去，合問升平詣秉鈞。"]'),
('yuding-18','塔院小屋，四壁皆是卿相題名，因成四韻','徐夤','唐','御定全唐诗','yuding','','[]','雁塔攙空映九衢，每看華宇每踟躕。題名儘是台衡跡，',40,'御定全唐詩/json/709.json','["雁塔攙空映九衢，每看華宇每踟躕。題名儘是台衡跡，", "誰知遠客思歸夢，夜夜無船自過湖。"]'),
('yuding-19','題名琉璃院','徐夤','唐','御定全唐诗','yuding','','[]','一條溪繞翠岩隈，行腳僧言勝五台。農罷樹陰黃犢臥，',40,'御定全唐詩/json/709.json','["一條溪繞翠岩隈，行腳僧言勝五台。農罷樹陰黃犢臥，", "三卷貝多金粟語，可能長誦免輪回。"]'),
('yuding-20','寺中偶題','徐夤','唐','御定全唐诗','yuding','','[]','聽話金仙眉相毫，每來皆得解塵勞。鶴棲雲路看方貴，',40,'御定全唐詩/json/709.json','["聽話金仙眉相毫，每來皆得解塵勞。鶴棲雲路看方貴，", "銀蟾未出金烏在，更上層樓眺海濤。"]'),
('yuding-21','山寺寓居','徐夤','唐','御定全唐诗','yuding','','[]','高臥東林最上方，水聲山翠剔愁腸。白雲送雨籠僧閣，',40,'御定全唐詩/json/709.json','["高臥東林最上方，水聲山翠剔愁腸。白雲送雨籠僧閣，", "披緇學佛應無分，鶴氅談空亦不妨。"]'),
('yuding-22','寄僧寓題','徐夤','唐','御定全唐诗','yuding','','[]','佛頂抄經憶惠休，眾人皆謂我悠悠。浮生真個醉中夢，',40,'御定全唐詩/json/709.json','["佛頂抄經憶惠休，眾人皆謂我悠悠。浮生真個醉中夢，", "安眠靜笑思何報，日夜焚修祝郡侯。"]'),
('yuding-23','遊靈隱天竺二寺','徐夤','唐','御定全唐诗','yuding','','[]','丹井冷泉虛易到，兩山真界實難名。石和雲霧蓮華氣，',40,'御定全唐詩/json/709.json','["丹井冷泉虛易到，兩山真界實難名。石和雲霧蓮華氣，", "更憐童子呼猿去，颯颯蕭蕭下樹行。"]'),
('yuding-24','醉題邑宰南塘屋壁','徐夤','唐','御定全唐诗','yuding','','[]','萬古清淮照遠天，黃河濁浪不相關。縣留東道三千客，',40,'御定全唐詩/json/709.json','["萬古清淮照遠天，黃河濁浪不相關。縣留東道三千客，", "閩王美錦求賢制，未許陶公解印還。"]'),
('yuding-25','題泗洲塔','徐夤','唐','御定全唐诗','yuding','','[]','十年前事已悠哉，旋被鐘聲早暮催。明月似師生又沒，',40,'御定全唐詩/json/709.json','["十年前事已悠哉，旋被鐘聲早暮催。明月似師生又沒，", "惟有南邊山色在，重重依舊上高臺。"]'),
('yuding-26','東歸題屋壁','徐夤','唐','御定全唐诗','yuding','','[]','塵埃歸去五湖東，還是衡門一畝宮。舊業旋從征賦失，',40,'御定全唐詩/json/709.json','["塵埃歸去五湖東，還是衡門一畝宮。舊業旋從征賦失，", "見說武王天上夢，無情曾與傅岩通。"]'),
('yuding-27','寓題','徐夤','唐','御定全唐诗','yuding','','[]','酒壺棋局似閒人，竹笏藍衫老此身。托客買書重得卷，',40,'御定全唐詩/json/709.json','["酒壺棋局似閒人，竹笏藍衫老此身。托客買書重得卷，", "見說天池波浪闊，也應涓滴濺窮鱗。"]'),
('yuding-28','偶題','徐夤','唐','御定全唐诗','yuding','','[]','閑補亡書見廢興，偶然前古也填膺。秦宮猶自拜張祿，',40,'御定全唐詩/json/709.json','["閑補亡書見廢興，偶然前古也填膺。秦宮猶自拜張祿，", "燕台財力知多少，誰築黃金到九層。"]'),
('yuding-29','寓題述懷','徐夤','唐','御定全唐诗','yuding','','[]','大道真風早晚還，妖訛成俗汙乾坤。宣尼既沒蘇張起，',40,'御定全唐詩/json/709.json','["大道真風早晚還，妖訛成俗汙乾坤。宣尼既沒蘇張起，", "堯廷忘卻征元凱，天闕重關十二門。"]'),
('yuding-30','將入城靈口道中作','徐夤','唐','御定全唐诗','yuding','','[]','路上長安惟咫尺，灞陵西望接秦源。依稀日下分天闕，',40,'御定全唐詩/json/709.json','["路上長安惟咫尺，灞陵西望接秦源。依稀日下分天闕，", "高風九萬程途近，與報滄洲欲化鯤。"]'),
('yuding-31','新屋','徐夤','唐','御定全唐诗','yuding','','[]','耳順何為土木勤，叔孫牆屋有前聞。縱然一世如紅葉，',40,'御定全唐詩/json/709.json','["耳順何為土木勤，叔孫牆屋有前聞。縱然一世如紅葉，", "清甜數尺沙泉井，平與鄰家晝夜分。"]'),
('yuding-32','新葺茆堂','徐夤','唐','御定全唐诗','yuding','','[]','剪竹誅茆就水濱，靜中還得保天真。只聞神鬼害盈滿，',80,'御定全唐詩/json/709.json','["剪竹誅茆就水濱，靜中還得保天真。只聞神鬼害盈滿，", "階前一片泓澄水，借與汀禽活紫鱗。", "耨水耕山息故林，壯圖嘉話負前心。素絲鬢上分愁色，", "同年二十八君子，游楚游秦斷好音。"]'),
('yuding-33','茆亭','徐夤','唐','御定全唐诗','yuding','','[]','鴛瓦虹梁計已疏，織茅編竹稱貧居。剪平恰似山僧笠，',40,'御定全唐詩/json/709.json','["鴛瓦虹梁計已疏，織茅編竹稱貧居。剪平恰似山僧笠，", "重門公子應相笑，四壁風霜老讀書。"]'),
('yuding-34','客廳','徐夤','唐','御定全唐诗','yuding','','[]','移卻松筠致客堂，淨泥環堵貯荷香。衡茅只要免風雨，',40,'御定全唐詩/json/709.json','["移卻松筠致客堂，淨泥環堵貯荷香。衡茅只要免風雨，", "燕台漢閣王侯事，青史千年播耿光。"]'),
('yuding-35','詠寫真','徐夤','唐','御定全唐诗','yuding','','[]','寫得衰容似十全，閑開僧舍靜時懸。瘦于南國從軍日，',40,'御定全唐詩/json/709.json','["寫得衰容似十全，閑開僧舍靜時懸。瘦于南國從軍日，", "借將前輩真儀比，未愧金鑾李謫仙。"]'),
('yuding-36','放榜日','徐夤','唐','御定全唐诗','yuding','','[]','喧喧車馬欲朝天，人探東堂榜已懸。萬里便隨金鸑鷟，',40,'御定全唐詩/json/709.json','["喧喧車馬欲朝天，人探東堂榜已懸。萬里便隨金鸑鷟，", "十二街前樓閣上，捲簾誰不看神仙。"]'),
('yuding-37','曲江宴日呈諸同年','徐夤','唐','御定全唐诗','yuding','','[]','鷦鷯驚與鳳凰同，忽向中興遇至公。金榜連名升碧落，',40,'御定全唐詩/json/709.json','["鷦鷯驚與鳳凰同，忽向中興遇至公。金榜連名升碧落，", "好是慈恩題瞭望，白雲飛盡塔連空。"]'),
('yuding-38','渤海賓貢高元固先輩閩中相訪雲本國人…屏障因而有贈','徐夤','唐','御定全唐诗','yuding','','[]','折桂何年下月中，閩山來問我雕蟲。肯銷金翠書屏上，',40,'御定全唐詩/json/709.json','["折桂何年下月中，閩山來問我雕蟲。肯銷金翠書屏上，", "嗟嗟大國金門士，幾個人能振素風。"]'),
('yuding-39','偶吟','徐夤','唐','御定全唐诗','yuding','','[]','千卷長書萬首詩，朝蒸藜藿暮烹葵。清時名立難皆我，',40,'御定全唐詩/json/709.json','["千卷長書萬首詩，朝蒸藜藿暮烹葵。清時名立難皆我，", "尋常抖擻懷中策，可便降他兩鬢絲。"]'),
('yuding-40','贈表弟黃校書輅','徐夤','唐','御定全唐诗','yuding','','[]','產破身窮為學儒，我家諸表愛詩書。嚴陵雖說臨溪隱，',40,'御定全唐詩/json/709.json','["產破身窮為學儒，我家諸表愛詩書。嚴陵雖說臨溪隱，", "閑來共話無生理，今古悠悠事總虛。"]'),
('yuding-41','輦下贈屯田何員外','徐夤','唐','御定全唐诗','yuding','','[]','封章頻得帝咨嗟，報國唯將直破邪。身到西山書幾達，',40,'御定全唐詩/json/709.json','["封章頻得帝咨嗟，報國唯將直破邪。身到西山書幾達，", "內翰好才兼好古，秋來應數到君家。"]'),
('yuding-42','贈月君','徐夤','唐','御定全唐诗','yuding','','[]','出水蓮花比性靈，三生塵夢一時醒。神傳尊勝陀羅咒，',40,'御定全唐詩/json/709.json','["出水蓮花比性靈，三生塵夢一時醒。神傳尊勝陀羅咒，", "鳴梭軋軋纖纖手，窗戶流光織女星。"]'),
('yuding-43','贈垂光同年','徐夤','唐','御定全唐诗','yuding','','[]','丹桂攀來十七春，如今始見茜袍新。須知紅杏園中客，',40,'御定全唐詩/json/709.json','["丹桂攀來十七春，如今始見茜袍新。須知紅杏園中客，", "他時黃閣朝元處，莫忘同年射策人。"]'),
('yuding-44','贈楊著','徐夤','唐','御定全唐诗','yuding','','[]','藻麗熒煌冠士林，白華榮養有曾參。十年去裏荊門改，',40,'御定全唐詩/json/709.json','["藻麗熒煌冠士林，白華榮養有曾參。十年去裏荊門改，", "釣魚臺上頻相訪，共說長安淚滿襟。"]'),
('yuding-45','贈黃校書先輩璞閒居','徐夤','唐','御定全唐诗','yuding','','[]','馭得驪龍第四珠，退依僧寺卜貧居。青山入眼不幹祿，',40,'御定全唐詩/json/709.json','["馭得驪龍第四珠，退依僧寺卜貧居。青山入眼不幹祿，", "月明掃石吟詩坐，諱卻全無儋石儲。"]'),
('yuding-46','尚書榮拜恩命夤疾中輒課惡詩二首以申攀贊','徐夤','唐','御定全唐诗','yuding','','[]','明公家鑿鳳凰池，弱冠封侯四海推。富貴有期天授早，',80,'御定全唐詩/json/709.json','["明公家鑿鳳凰池，弱冠封侯四海推。富貴有期天授早，", "昨日詔書猶漏缺，未言商也最能詩。", "東郊迎入紫泥封，此日天仙下九重。三五月明臨闞澤，", "借問乘軺何處客，相庭雄幕卷芙蓉。"]'),
('yuding-47','府主僕射王摶生日','徐夤','唐','御定全唐诗','yuding','','[]','熊羆先兆慶垂休，天地氤氳瑞氣浮。李樹影籠周柱史，',40,'御定全唐詩/json/709.json','["熊羆先兆慶垂休，天地氤氳瑞氣浮。李樹影籠周柱史，", "勳業定應歸鼎鼐，生靈豈獨化東甌。"]'),
('yuding-48','獻內翰楊侍郎','徐夤','唐','御定全唐诗','yuding','','[]','窗開青瑣見瑤台，冷拂星辰逼上臺。丹鳳詔成中使取，',40,'御定全唐詩/json/709.json','["窗開青瑣見瑤台，冷拂星辰逼上臺。丹鳳詔成中使取，", "莫擬吟雲避榮貴，廟堂玉鉉待鹽梅。"]'),
('yuding-49','送劉常侍','徐夤','唐','御定全唐诗','yuding','','[]','懷君何計更留連，忍送文星上碧天。杜預注通三十卷，',40,'御定全唐詩/json/709.json','["懷君何計更留連，忍送文星上碧天。杜預注通三十卷，", "他日有書隨雁足，東溪無令訪漁船。"]'),
('yuding-50','送盧拾遺歸華山','徐夤','唐','御定全唐诗','yuding','','[]','紫殿諫多防佞口，清秋假滿別明君。惟憂急詔歸青瑣，',40,'御定全唐詩/json/709.json','["紫殿諫多防佞口，清秋假滿別明君。惟憂急詔歸青瑣，", "門前舊客期相薦，猶望飛書及主文。"]'),
('yuding-51','春末送陳先輩之清源','徐夤','唐','御定全唐诗','yuding','','[]','貧中惟是長年華，每羨君行自歎嗟。歸日捧持明月寶，',40,'御定全唐詩/json/709.json','["貧中惟是長年華，每羨君行自歎嗟。歸日捧持明月寶，", "千乘侯王若相問，飛書與報白雲家。"]'),
('yuding-52','上盧三拾遺以言見黜','徐夤','唐','御定全唐诗','yuding','','[]','骨鯁如君道尚存，近來人事不須論。疾危必厭神明藥，',40,'御定全唐詩/json/709.json','["骨鯁如君道尚存，近來人事不須論。疾危必厭神明藥，", "因思周廟當時誡，金口三緘示後昆。"]'),
('yuding-53','送王校書往清源','徐夤','唐','御定全唐诗','yuding','','[]','南國賢侯待德風，長途仍借九花驄。清歌早貫驪龍頷，',40,'御定全唐詩/json/709.json','["南國賢侯待德風，長途仍借九花驄。清歌早貫驪龍頷，", "吟詩臺上如相問，與說蟠溪直釣翁。"]'),
('yuding-54','嶽州端午日送人游郴連','徐夤','唐','御定全唐诗','yuding','','[]','五月巴陵值積陰，送君千里客於郴。北風吹雨黃梅落，',40,'御定全唐詩/json/709.json','["五月巴陵值積陰，送君千里客於郴。北風吹雨黃梅落，", "九嶷雲闊蒼梧暗，與說重華舊德音。"]'),
('yuding-55','賀清源太保王延彬','徐夤','唐','御定全唐诗','yuding','','[]','蕊珠宮裏謫神仙，八載溫陵萬戶閑。心地闊於雲夢澤，',80,'御定全唐詩/json/709.json','["蕊珠宮裏謫神仙，八載溫陵萬戶閑。心地闊於雲夢澤，", "應笑清溪舊門吏，年年扶病掩柴關。", "武榮江畔蔭祥雲，寵拜天人慶郡人。五色鶴綾花上敕，", "更待春風飛吉語，紫泥分付與陶鈞。"]'),
('yuding-56','病中春日即事寄主人尚書二首','徐夤','唐','御定全唐诗','yuding','','[]','身比秋荷覺漸枯，致君經國墮前圖。層冰照日猶能暖，',80,'御定全唐詩/json/709.json','["身比秋荷覺漸枯，致君經國墮前圖。層冰照日猶能暖，", "庾樓恩化通神聖，何計能教擲得盧。", "風拍衰肌久未蠲，破窗頻見月團圓。更無舊日同人問，", "玄穹若假年齡在，願捧銅盤為國賢。"]'),
('yuding-57','寄華山司空侍郎二首','徐夤','唐','御定全唐诗','yuding','','[]','金闕爭權競獻功，獨逃征詔臥三峰。雞群未必容於鶴，',80,'御定全唐詩/json/709.json','["金闕爭權競獻功，獨逃征詔臥三峰。雞群未必容於鶴，", "風霜落滿千林木，不近青青澗底松。", "非雲非鶴不從容，誰敢輕量傲世蹤。紫殿幾征王佐業，", "前古負材多為國，滿懷經濟欲何從。"]'),
('yuding-58','寄盧端公同年仁炯，時遷都洛陽，新立幼主','徐夤','唐','御定全唐诗','yuding','','[]','上陽宮闕翠華歸，百辟傷心序漢儀。昆嶽有炎瓊玉碎，',40,'御定全唐詩/json/709.json','["上陽宮闕翠華歸，百辟傷心序漢儀。昆嶽有炎瓊玉碎，", "惆悵宸居遠於日，長籲空摘鬢邊絲。"]'),
('yuding-59','寄天臺陳希畋','徐夤','唐','御定全唐诗','yuding','','[]','陰山冰凍嘗迎夏，蟄戶雲雷只待春。呂望豈嫌垂釣老，',40,'御定全唐詩/json/709.json','["陰山冰凍嘗迎夏，蟄戶雲雷只待春。呂望豈嫌垂釣老，", "拍手相思惟大笑，我曹寧比等閒人。"]'),
('yuding-60','寄兩浙羅書記','徐夤','唐','御定全唐诗','yuding','','[]','進即湮沈退卻升，錢塘風月過金陵。鴻才入貢無人換，',40,'御定全唐詩/json/709.json','["進即湮沈退卻升，錢塘風月過金陵。鴻才入貢無人換，", "憐君道在名長在，不到慈恩最上層。"]'),
('yuding-61','邑宰相訪，翼日有寄','徐夤','唐','御定全唐诗','yuding','','[]','淵明深念郤詵貧，踏破莓苔看甑塵。碧沼共攀紅菡萏，',40,'御定全唐詩/json/709.json','["淵明深念郤詵貧，踏破莓苔看甑塵。碧沼共攀紅菡萏，", "夜半夢醒追複想，欲長攀接有何因。"]'),
('yuding-62','白酒兩瓶送崔侍禦','徐夤','唐','御定全唐诗','yuding','','[]','雪化霜融好潑醅，滿壺冰凍向春開。求從白石洞中得，',40,'御定全唐詩/json/709.json','["雪化霜融好潑醅，滿壺冰凍向春開。求從白石洞中得，", "湖邊送與崔夫子，誰見嵇山盡日頹。"]'),
('yuding-63','依韻酬常循州','徐夤','唐','御定全唐诗','yuding','','[]','早年花縣拜潘郎，尋忝飛鳴出桂堂。日走登天長似箭，',40,'御定全唐詩/json/709.json','["早年花縣拜潘郎，尋忝飛鳴出桂堂。日走登天長似箭，", "公論一麾將塞詔，且隨征令過瀟湘。"]'),
('yuding-64','謝主人惠綠酒白魚','徐夤','唐','御定全唐诗','yuding','','[]','早起雀聲送喜頻，白魚芳酒寄來珍。馨香乍揭春風甕，',40,'御定全唐詩/json/709.json','["早起雀聲送喜頻，白魚芳酒寄來珍。馨香乍揭春風甕，", "不曾垂釣兼親醞，堪愧金台醉飽身。"]'),
('yuding-0','蜀','徐夤','唐','御定全唐诗','yuding','','[]','雖倚關張敵萬夫，豈勝恩信作良圖。能均漢祚三分業，',40,'御定全唐詩/json/710.json','["雖倚關張敵萬夫，豈勝恩信作良圖。能均漢祚三分業，", "君王幸是中山后，建國如何號蜀都。"]'),
('yuding-1','魏','徐夤','唐','御定全唐诗','yuding','','[]','伐罪書勳令不常，爭教為帝與為王。十年小怨誅桓邵，',40,'御定全唐詩/json/710.json','["伐罪書勳令不常，爭教為帝與為王。十年小怨誅桓邵，", "奸雄事過分明見，英識空懷許子將。"]'),
('yuding-2','吳','徐夤','唐','御定全唐诗','yuding','','[]','一主參差六十年，父兄猶慶授孫權。不迎曹操真長策，',40,'御定全唐詩/json/710.json','["一主參差六十年，父兄猶慶授孫權。不迎曹操真長策，", "秦嬴謾作東游計，紫氣黃旗豈偶然。"]'),
('yuding-3','兩晉','徐夤','唐','御定全唐诗','yuding','','[]','三世深謀啟帝基，可憐孀婦與孤兒。罪歸成濟皇天恨，',40,'御定全唐詩/json/710.json','["三世深謀啟帝基，可憐孀婦與孤兒。罪歸成濟皇天恨，", "誰知高鼻能知數，競向中原簸戰旗。"]'),
('yuding-4','宋二首','徐夤','唐','御定全唐诗','yuding','','[]','天爵休將儋石論，一身恭儉萬邦尊。賭將金帶驚寰海，',80,'御定全唐詩/json/710.json','["天爵休將儋石論，一身恭儉萬邦尊。賭將金帶驚寰海，", "草中求活非吾事，豈啻橫身向廟門。", "百萬人甘一擲輸，玄穹惟與道相符。豈知紫殿新天子，", "三年未得分明夢，卻為蘭陵起霸圖。"]'),
('yuding-5','陳','徐夤','唐','御定全唐诗','yuding','','[]','三惑昏昏中紫宸，萬機拋卻醉臨春。書中不禮隋文帝，',40,'御定全唐詩/json/710.json','["三惑昏昏中紫宸，萬機拋卻醉臨春。書中不禮隋文帝，", "兵戈半渡前江水，狎客猶聞爭酒巡。"]'),
('yuding-6','讀史','徐夤','唐','御定全唐诗','yuding','','[]','亞父淒涼別楚營，天留三傑翼龍爭。高才無主不能用，',40,'御定全唐詩/json/710.json','["亞父淒涼別楚營，天留三傑翼龍爭。高才無主不能用，", "須知飲啄繇天命，休問黃河早晚清。"]'),
('yuding-7','漢宮新寵','徐夤','唐','御定全唐诗','yuding','','[]','位在嬪妃最上頭，笑他長信女悲秋。日中月滿可能久，',40,'御定全唐詩/json/710.json','["位在嬪妃最上頭，笑他長信女悲秋。日中月滿可能久，", "妾家兄弟知多少，恰要同時拜列侯。"]'),
('yuding-8','開元即事','徐夤','唐','御定全唐诗','yuding','','[]','曲江真宰國中訛，尋奏漁陽忽荷戈。堂上有兵天不用，',40,'御定全唐詩/json/710.json','["曲江真宰國中訛，尋奏漁陽忽荷戈。堂上有兵天不用，", "未必蛾眉能破國，千秋休恨馬嵬坡。"]'),
('yuding-9','李翰林','徐夤','唐','御定全唐诗','yuding','','[]','謫下三清列八仙，獲調羹鼎侍龍顏。吟開鎖闥窺天近，',40,'御定全唐詩/json/710.json','["謫下三清列八仙，獲調羹鼎侍龍顏。吟開鎖闥窺天近，", "遺編往簡應飛去，散入祥雲瑞日間。"]'),
('yuding-10','聞長安庚子歲事','徐夤','唐','御定全唐诗','yuding','','[]','羽檄交馳觸冕旒，函關飛入鐵兜鍪。皇王去國未為恨，',40,'御定全唐詩/json/710.json','["羽檄交馳觸冕旒，函關飛入鐵兜鍪。皇王去國未為恨，", "唐堯縱禪乾坤位，不是重華莫謾求。"]'),
('yuding-11','公子行','徐夤','唐','御定全唐诗','yuding','','[]','十五轅門學控弦，六街騎馬去如煙。金多倍著牡丹價，',40,'御定全唐詩/json/710.json','["十五轅門學控弦，六街騎馬去如煙。金多倍著牡丹價，", "相如謾說淩雲賦，四壁何曾有一錢。"]'),
('yuding-12','依韻贈嚴司直','徐夤','唐','御定全唐诗','yuding','','[]','曾轉雙蓬到玉京，宣尼恩奏樂卿名。歌殘白石扣牛角，',40,'御定全唐詩/json/710.json','["曾轉雙蓬到玉京，宣尼恩奏樂卿名。歌殘白石扣牛角，", "夫君才大官何小，堪恨人間事不平。"]'),
('yuding-13','傷前翰林楊左丞','徐夤','唐','御定全唐诗','yuding','','[]','飛上鼇頭侍玉皇，三台遺耀換餘光。人間搦管窮蒼頡，',40,'御定全唐詩/json/710.json','["飛上鼇頭侍玉皇，三台遺耀換餘光。人間搦管窮蒼頡，", "皇天未啟升平運，不使伊皋相禹湯。"]'),
('yuding-14','日月無情','徐夤','唐','御定全唐诗','yuding','','[]','日月無情也有情，朝升夕沒照均平。雖催前代英雄死，',40,'御定全唐詩/json/710.json','["日月無情也有情，朝升夕沒照均平。雖催前代英雄死，", "憑誰築斷東溟路，龍影蟬光免運行。"]'),
('yuding-15','新月','徐夤','唐','御定全唐诗','yuding','','[]','雲際嬋娟出又藏，美人腸斷拜金方。姮娥一隻眉先掃，',40,'御定全唐詩/json/710.json','["雲際嬋娟出又藏，美人腸斷拜金方。姮娥一隻眉先掃，", "更期十五圓明夜，與破陰霾照八荒。"]'),
('yuding-16','和尚書詠煙','徐夤','唐','御定全唐诗','yuding','','[]','無根無蒂結還融，曾觸嵐光徹底空。不散幾知離畢雨，',40,'御定全唐詩/json/710.json','["無根無蒂結還融，曾觸嵐光徹底空。不散幾知離畢雨，", "瓊什捧來思舊隱，撲窗穿戶曉溟蒙。"]'),
('yuding-17','宮鶯','徐夤','唐','御定全唐诗','yuding','','[]','領得春光在帝家，早從深谷出煙霞。閑棲仙禁日邊柳，',40,'御定全唐詩/json/710.json','["領得春光在帝家，早從深谷出煙霞。閑棲仙禁日邊柳，", "可憐鸚鵡矜言語，長閉雕籠歲月賒。"]'),
('yuding-18','鬢髮','徐夤','唐','御定全唐诗','yuding','','[]','鬢添華髮數莖新，羅雀門前絕故人。減食為緣疏五味，',40,'御定全唐詩/json/710.json','["鬢添華髮數莖新，羅雀門前絕故人。減食為緣疏五味，", "天地有爐長鑄物，濁泥遺塊待陶鈞。"]'),
('yuding-19','春入鯉湖','徐夤','唐','御定全唐诗','yuding','','[]','到來峭壁白雲齊，載酒春遊渡九溪。鐵嶂有樓霾欲墮，',40,'御定全唐詩/json/710.json','["到來峭壁白雲齊，載酒春遊渡九溪。鐵嶂有樓霾欲墮，", "回首浮生真幻夢，何如斯地傍幽棲。"]'),
('yuding-20','雙鷺','徐夤','唐','御定全唐诗','yuding','','[]','雙鷺雕籠昨夜開，月明飛出立庭隈。但教綠水池塘在，',40,'御定全唐詩/json/710.json','["雙鷺雕籠昨夜開，月明飛出立庭隈。但教綠水池塘在，", "何人為我追尋得，重勸溪翁酒一杯。"]'),
('yuding-21','鷓鴣','徐夤','唐','御定全唐诗','yuding','','[]','繡僕梅兼羽翼全，楚雞非瑞莫爭先。啼歸明月落邊樹，',40,'御定全唐詩/json/710.json','["繡僕梅兼羽翼全，楚雞非瑞莫爭先。啼歸明月落邊樹，", "荔枝初熟無人際，啄破紅苞墜野田。"]'),
('yuding-22','鷹','徐夤','唐','御定全唐诗','yuding','','[]','害物傷生性豈馴，且宜籠罩待知人。惟擒燕雀啖腥血，',40,'御定全唐詩/json/710.json','["害物傷生性豈馴，且宜籠罩待知人。惟擒燕雀啖腥血，", "豪門不讀詩書者，走馬平原放玩頻。"]'),
('yuding-23','蝴蝶二首','徐夤','唐','御定全唐诗','yuding','','[]','縹緲青蟲脫殼微，不堪煙重雨霏霏。一枝穠豔留教住，',80,'御定全唐詩/json/710.json','["縹緲青蟲脫殼微，不堪煙重雨霏霏。一枝穠豔留教住，", "無情豈解關魂夢，莫信莊周說是非。", "拂綠穿紅麗日長，一生心事住春光。最嫌神女來行雨，", "鳴蟬性分殊迂闊，空解三秋噪夕陽。"]'),
('yuding-24','郡侯坐上觀琉璃瓶中游魚','徐夤','唐','御定全唐诗','yuding','','[]','寶器一泓銀漢水，錦鱗才動即先知。似涵明月波寧隔，',40,'御定全唐詩/json/710.json','["寶器一泓銀漢水，錦鱗才動即先知。似涵明月波寧隔，", "文翁未得沈香餌，擬置金盤召左慈。"]'),
('yuding-25','剪刀','徐夤','唐','御定全唐诗','yuding','','[]','寶持多用繡為囊，雙日交加兩鬢霜。金匣掠平花翡翠，',40,'御定全唐詩/json/710.json','["寶持多用繡為囊，雙日交加兩鬢霜。金匣掠平花翡翠，", "欲制縕袍先把看，質非紈綺愧銛鋩。"]'),
('yuding-26','紙被','徐夤','唐','御定全唐诗','yuding','','[]','文采鴛鴦罷合歡，細柔輕綴好魚箋。一床明月蓋歸夢，',40,'御定全唐詩/json/710.json','["文采鴛鴦罷合歡，細柔輕綴好魚箋。一床明月蓋歸夢，", "赤眉豪客見皆笑，卻問儒生直幾錢。"]'),
('yuding-27','紙帳','徐夤','唐','御定全唐诗','yuding','','[]','幾笑文園四壁空，避寒深入剡藤中。誤懸謝守澄江練，',40,'御定全唐詩/json/710.json','["幾笑文園四壁空，避寒深入剡藤中。誤懸謝守澄江練，", "針羅截錦饒君侈，爭及蒙茸暖避風。"]'),
('yuding-28','貢餘秘色茶盞','徐夤','唐','御定全唐诗','yuding','','[]','捩翠融青瑞色新，陶成先得貢吾君。功剜明月染春水，',40,'御定全唐詩/json/710.json','["捩翠融青瑞色新，陶成先得貢吾君。功剜明月染春水，", "中山竹葉醅初發，多病那堪中十分。"]'),
('yuding-29','筍鞭','徐夤','唐','御定全唐诗','yuding','','[]','筇竹岩邊剔翠苔，錦江波冷洗瓊瑰。累累節轉蒼龍骨，',40,'御定全唐詩/json/710.json','["筇竹岩邊剔翠苔，錦江波冷洗瓊瑰。累累節轉蒼龍骨，", "甯同晉帝環營日，拋賺中途後騎來。"]'),
('yuding-30','詠簾','徐夤','唐','御定全唐诗','yuding','','[]','素節輕盈珠影勻，何人巧思間成文。閑垂別殿風應度，',40,'御定全唐詩/json/710.json','["素節輕盈珠影勻，何人巧思間成文。閑垂別殿風應度，", "無情幾恨黃昏月，才到如鉤便墮雲。"]'),
('yuding-31','詠燈','徐夤','唐','御定全唐诗','yuding','','[]','分影由來恨不同，綠窗孤館兩何窮。熒煌短焰長疑暗，',40,'御定全唐詩/json/710.json','["分影由來恨不同，綠窗孤館兩何窮。熒煌短焰長疑暗，", "莫言明滅無多事，曾比人生一世中。"]'),
('yuding-32','詠扇','徐夤','唐','御定全唐诗','yuding','','[]','為發涼飆滿玉堂，每親襟袖便難忘。霜濃雪暗知何在，',40,'御定全唐詩/json/710.json','["為發涼飆滿玉堂，每親襟袖便難忘。霜濃雪暗知何在，", "漢宮如有秋風起，誰信班姬淚數行。"]'),
('yuding-33','詠筆二首','徐夤','唐','御定全唐诗','yuding','','[]','秦代將軍欲建功，截龍搜兔助英雄。用多誰念毛皆拔，',80,'御定全唐詩/json/710.json','["秦代將軍欲建功，截龍搜兔助英雄。用多誰念毛皆拔，", "班超握管不成事，投擲翻從萬里戎。", "君子三歸擅一名，秋毫雖細握非輕。軍書羽檄教誰錄，", "毛幹時有何人潤，盡把燒焚恨始平。"]'),
('yuding-34','詠錢','徐夤','唐','御定全唐诗','yuding','','[]','多蓄多藏豈足論，有誰還議濟王孫。能於禍處翻為福，',40,'御定全唐詩/json/710.json','["多蓄多藏豈足論，有誰還議濟王孫。能於禍處翻為福，", "朝爭暮競歸何處，盡入權門與幸門。"]'),
('yuding-35','尚書筵中詠紅手帕','徐夤','唐','御定全唐诗','yuding','','[]','鶴綾三尺曉霞濃，送與東家二八容。羅帶繡裙輕好系，',40,'御定全唐詩/json/710.json','["鶴綾三尺曉霞濃，送與東家二八容。羅帶繡裙輕好系，", "無事把將纏皓腕，為君池上折芙蓉。"]'),
('yuding-36','尚書新造花箋','徐夤','唐','御定全唐诗','yuding','','[]','濃染紅桃二月花，只宜神筆縱龍蛇。淺澄秋水看雲母，',40,'御定全唐詩/json/710.json','["濃染紅桃二月花，只宜神筆縱龍蛇。淺澄秋水看雲母，", "使君即入金鑾殿，夜直無非草白麻。"]'),
('yuding-37','釣車','徐夤','唐','御定全唐诗','yuding','','[]','荻灣漁客巧妝成，硾鑄銀星一點輕。拋過碧江鸂鶒岸，',40,'御定全唐詩/json/710.json','["荻灣漁客巧妝成，硾鑄銀星一點輕。拋過碧江鸂鶒岸，", "把向嚴灘尋轍跡，漁台基在輾難傾。"]'),
('yuding-38','柳','徐夤','唐','御定全唐诗','yuding','','[]','漠漠金條引線微，年年先翠報春歸。解籠飛靄延芳景，',40,'御定全唐詩/json/710.json','["漠漠金條引線微，年年先翠報春歸。解籠飛靄延芳景，", "五株名顯陶家後，見說辭榮種者稀。"]'),
('yuding-39','愁','徐夤','唐','御定全唐诗','yuding','','[]','夜長偏覺漏聲遲，往往隨歌慘翠眉。黃葉落催砧杵日，',40,'御定全唐詩/json/710.json','["夜長偏覺漏聲遲，往往隨歌慘翠眉。黃葉落催砧杵日，", "四皓入山招不得，無家歸客最堪欺。"]'),
('yuding-40','草','徐夤','唐','御定全唐诗','yuding','','[]','廢苑荒階伴綠苔，恩疏長信恨難開。姑蘇麋鹿食思食，',40,'御定全唐詩/json/710.json','["廢苑荒階伴綠苔，恩疏長信恨難開。姑蘇麋鹿食思食，", "燕昭沒後多卿士，千載流芳郭隗台。"]'),
('yuding-41','螢','徐夤','唐','御定全唐诗','yuding','','[]','月墜西樓夜影空，透簾穿幕達房櫳。流光堪在珠璣列，',40,'御定全唐詩/json/710.json','["月墜西樓夜影空，透簾穿幕達房櫳。流光堪在珠璣列，", "欲知應候何時節，六月初迎大暑風。"]'),
('yuding-42','水','徐夤','唐','御定全唐诗','yuding','','[]','火性何如水性柔，西來東出幾時休。莫言通海能通漢，',40,'御定全唐詩/json/710.json','["火性何如水性柔，西來東出幾時休。莫言通海能通漢，", "洪波激湍歸何處，二月桃花滿眼流。"]'),
('yuding-43','苔','徐夤','唐','御定全唐诗','yuding','','[]','印留麋鹿野禽蹤，岩壁漁磯幾處逢。金穀曉凝花影重，',40,'御定全唐詩/json/710.json','["印留麋鹿野禽蹤，岩壁漁磯幾處逢。金穀曉凝花影重，", "歸去掃除階砌下，蘚痕殘綠一重重。"]'),
('yuding-44','曉','徐夤','唐','御定全唐诗','yuding','','[]','水盡銅龍滴漸微，景陽鐘動夢魂飛。潼關雞唱促歸騎，',40,'御定全唐詩/json/710.json','["水盡銅龍滴漸微，景陽鐘動夢魂飛。潼關雞唱促歸騎，", "羲和晴聳扶桑轡，借與寰瀛看早暉。"]'),
('yuding-45','別','徐夤','唐','御定全唐诗','yuding','','[]','酒盡歌終問後期，泛萍浮梗不勝悲。東門匹馬夜歸處，',40,'御定全唐詩/json/710.json','["酒盡歌終問後期，泛萍浮梗不勝悲。東門匹馬夜歸處，", "可憐范陸分襟後，空折梅花寄所思。"]'),
('yuding-46','夜','徐夤','唐','御定全唐诗','yuding','','[]','日墜虞淵燭影開，沉沉煙霧壓浮埃。剡川雪滿子猷去，',40,'御定全唐詩/json/710.json','["日墜虞淵燭影開，沉沉煙霧壓浮埃。剡川雪滿子猷去，", "愁人莫道何時旦，自有鐘鳴漏滴催。"]'),
('yuding-47','雨','徐夤','唐','御定全唐诗','yuding','','[]','引電隨龍密又輕，酒杯閑噀得嘉名。千山草木如雲暗，',40,'御定全唐詩/json/710.json','["引電隨龍密又輕，酒杯閑噀得嘉名。千山草木如雲暗，", "陰妖冷孽成何怪，敢蔽高天日月明。"]'),
('yuding-48','萍','徐夤','唐','御定全唐诗','yuding','','[]','為實隨流瑞色新，泛風縈草護遊鱗。密行碧水澄涵月，',40,'御定全唐詩/json/710.json','["為實隨流瑞色新，泛風縈草護遊鱗。密行碧水澄涵月，", "平湖春渚知何限，撥破閑投獨繭綸。"]'),
('yuding-49','恨','徐夤','唐','御定全唐诗','yuding','','[]','事與時違不自由，如燒如刺寸心頭。烏江項籍忍歸去，',40,'御定全唐詩/json/710.json','["事與時違不自由，如燒如刺寸心頭。烏江項籍忍歸去，", "須知入骨難銷處，莫比人間取次愁。"]'),
('yuding-50','鴻','徐夤','唐','御定全唐诗','yuding','','[]','行如兄弟影連空，春去秋來燕不同。紫塞別當秋露白，',40,'御定全唐詩/json/710.json','["行如兄弟影連空，春去秋來燕不同。紫塞別當秋露白，", "況解銜蘆避弓箭，一聲歸唳楚天風。"]'),
('yuding-51','鶴','徐夤','唐','御定全唐诗','yuding','','[]','閬苑瑤台歲月長，一歸華表好增傷。新聲乍警初零露，',40,'御定全唐詩/json/710.json','["閬苑瑤台歲月長，一歸華表好增傷。新聲乍警初零露，", "三山頂上無人處，瓊樹堪巢不死鄉。"]'),
('yuding-52','鵲','徐夤','唐','御定全唐诗','yuding','','[]','神化難源瑞即開，雕陵毛羽出塵埃。香閨報喜行人至，',40,'御定全唐詩/json/710.json','["神化難源瑞即開，雕陵毛羽出塵埃。香閨報喜行人至，", "瓊枝翠葉庭前植，從待翩翩去又來。"]'),
('yuding-53','霜','徐夤','唐','御定全唐诗','yuding','','[]','應節誰窮造化端，菊黃豺祭問應難。紅窗透出鴛衾冷，',40,'御定全唐詩/json/710.json','["應節誰窮造化端，菊黃豺祭問應難。紅窗透出鴛衾冷，", "世間無比催搖落，松竹何人肯更看。"]'),
('yuding-54','風','徐夤','唐','御定全唐诗','yuding','','[]','城上寒來思莫窮，土囊萍末兩難同。飄成遠浪江湖際，',40,'御定全唐詩/json/710.json','["城上寒來思莫窮，土囊萍末兩難同。飄成遠浪江湖際，", "春能和煦秋搖落，生殺還同造化功。"]'),
('yuding-55','帆','徐夤','唐','御定全唐诗','yuding','','[]','豈勞孤棹送行舟，輕過天涯勢未休。斷岸曉看殘月掛，',40,'御定全唐詩/json/710.json','["豈勞孤棹送行舟，輕過天涯勢未休。斷岸曉看殘月掛，", "幸遇濟川恩不淺，北溟東海更何愁。"]'),
('yuding-56','夢','徐夤','唐','御定全唐诗','yuding','','[]','月落燈前閉北堂，神魂交入杳冥鄉。文通毫管醒來異，',40,'御定全唐詩/json/710.json','["月落燈前閉北堂，神魂交入杳冥鄉。文通毫管醒來異，", "生松十八年方應，通塞人間豈合忙。"]'),
('yuding-57','東','徐夤','唐','御定全唐诗','yuding','','[]','紫氣天元出故關，大明先照九垓間。鼇山海上秦娥去，',40,'御定全唐詩/json/710.json','["紫氣天元出故關，大明先照九垓間。鼇山海上秦娥去，", "蟠桃樹在煙濤水，解凍風高未得攀。"]'),
('yuding-58','西','徐夤','唐','御定全唐诗','yuding','','[]','密雲郊外已回秋，日下崦嵫景懶收。秦帝城高堅似鐵，',40,'御定全唐詩/json/710.json','["密雲郊外已回秋，日下崦嵫景懶收。秦帝城高堅似鐵，", "見說山傍偏出將，犬戎降盡複何愁。"]'),
('yuding-59','南','徐夤','唐','御定全唐诗','yuding','','[]','罩罩嘉魚憶此方，送君前浦恨難量。火山遠照蒼梧郡，',40,'御定全唐詩/json/710.json','["罩罩嘉魚憶此方，送君前浦恨難量。火山遠照蒼梧郡，", "鐘儀冠帶歸心阻，蝴蝶飛園萬草芳。"]'),
('yuding-60','北','徐夤','唐','御定全唐诗','yuding','','[]','雪滿湖天日影微，李君降虜失良時。窮溟駕浪鶤鵬化，',40,'御定全唐詩/json/710.json','["雪滿湖天日影微，李君降虜失良時。窮溟駕浪鶤鵬化，", "可憐燕穀花間晚，鄒律如何為一吹。"]'),
('yuding-61','雲','徐夤','唐','御定全唐诗','yuding','','[]','漠漠沉沉向夕暉，蒼梧巫峽兩相依。天心白日休空蔽，',40,'御定全唐詩/json/710.json','["漠漠沉沉向夕暉，蒼梧巫峽兩相依。天心白日休空蔽，", "為霖須救蒼生旱，莫向西郊作雨稀。"]'),
('yuding-62','燕','徐夤','唐','御定全唐诗','yuding','','[]','從待銜泥濺客衣，百禽靈性比他稀。何嫌何恨秋須去，',40,'御定全唐詩/json/710.json','["從待銜泥濺客衣，百禽靈性比他稀。何嫌何恨秋須去，", "吳王宮女嬌相襲，合整雙毛預奮飛。"]'),
('yuding-63','蟬','徐夤','唐','御定全唐诗','yuding','','[]','寒鳴寧與眾蟲同，翼鬢緌冠豈道窮。殼蛻已從今日化，',40,'御定全唐詩/json/710.json','["寒鳴寧與眾蟲同，翼鬢緌冠豈道窮。殼蛻已從今日化，", "從此最能驚賦客，計居何處轉飛蓬。"]'),
('yuding-64','露','徐夤','唐','御定全唐诗','yuding','','[]','鶴鳴先警雁來天，洗竹沾花處處鮮。散彩幾當蟬飲際，',40,'御定全唐詩/json/710.json','["鶴鳴先警雁來天，洗竹沾花處處鮮。散彩幾當蟬飲際，", "怵惕與霜同降日，蘋蘩思薦獨淒然。"]'),
('yuding-65','霞','徐夤','唐','御定全唐诗','yuding','','[]','天際何人濯錦歸，偏宜殘照與晨暉。流為洞府千年酒，',40,'御定全唐詩/json/710.json','["天際何人濯錦歸，偏宜殘照與晨暉。流為洞府千年酒，", "勞生願學長生術，餐盡紅桃上漢飛。"]'),
('yuding-66','蒲','徐夤','唐','御定全唐诗','yuding','','[]','濯秀盤根在碧流，紫茵含露向晴抽。編為細履隨君步，',40,'御定全唐詩/json/710.json','["濯秀盤根在碧流，紫茵含露向晴抽。編為細履隨君步，", "鴛鴦鸂鶒多情甚，日日雙雙繞傍遊。"]'),
('yuding-67','泉','徐夤','唐','御定全唐诗','yuding','','[]','非鑿非疏出洞門，源深流嶮合還分。高成瀑布漱逋客，',40,'御定全唐詩/json/710.json','["非鑿非疏出洞門，源深流嶮合還分。高成瀑布漱逋客，", "舊齋一帶連松竹，明月窗前枕上聞。"]'),
('yuding-68','煙','徐夤','唐','御定全唐诗','yuding','','[]','燎野焚林見所從，惹空橫水展形容。能滋甘雨隨車潤，',40,'御定全唐詩/json/710.json','["燎野焚林見所從，惹空橫水展形容。能滋甘雨隨車潤，", "有時片片風吹去，海碧山清過幾重。"]'),
('yuding-69','閑','徐夤','唐','御定全唐诗','yuding','','[]','不管人間是與非，白雲流水自相依。一瓢掛樹傲時代，',40,'御定全唐詩/json/710.json','["不管人間是與非，白雲流水自相依。一瓢掛樹傲時代，", "客星辭得漢光武，卻坐東江舊蘚磯。"]'),
('yuding-70','忙','徐夤','唐','御定全唐诗','yuding','','[]','雙競龍舟疾似風，一星球子兩明同。平吳破蜀三除裏，',40,'御定全唐詩/json/710.json','["雙競龍舟疾似風，一星球子兩明同。平吳破蜀三除裏，", "兵還失路旌旗亂，驚起紅塵似轉蓬。"]'),
('yuding-71','淚','徐夤','唐','御定全唐诗','yuding','','[]','發事牽情不自由，偶然惆悵即難收。已聞抱玉沾衣濕，',40,'御定全唐詩/json/710.json','["發事牽情不自由，偶然惆悵即難收。已聞抱玉沾衣濕，", "世間何處偏留得，萬點分明湘水頭。"]'),
('yuding-72','月','徐夤','唐','御定全唐诗','yuding','','[]','碧落誰分造化權，結霜凝雪作嬋娟。寒蟬若不開三穴，',40,'御定全唐詩/json/710.json','["碧落誰分造化權，結霜凝雪作嬋娟。寒蟬若不開三穴，", "郤詵樹老堯蓂換，惆悵今年似去年。"]'),
('yuding-0','依禦史溫飛卿華清宮二十二韻','徐夤','唐','御定全唐诗','yuding','','[]','地靈蒸水暖，天氣待宸遊。岳拱蓮花秀，峰高玉蕊秋。',264,'御定全唐詩/json/711.json','["地靈蒸水暖，天氣待宸遊。岳拱蓮花秀，峰高玉蕊秋。", "朝元雕翠閣，乞巧繡瓊樓。碧海供驪嶺，黃金絡馬頭。", "五王更入帳，七貴迭封侯。夕雨鳴鴛瓦，朝陽曄柘裘。", "伊皋爭負鼎，舜禹讓垂旒。墮珥閑應拾，遺釵醉不收。", "飛煙籠劍戟，殘月照旌斿。履朔求衣早，臨陽解佩羞。", "宮詞裁錦段，御筆落銀鉤。帝裏新豐縣，長安舊雍州。", "雪衣傳貝葉，蟬鬢插山榴。對景瞻瑤兔，升天駕彩虯。", "丹書陳北虜，玄甲擐犀牛。聖誥多屯否，生靈少怨尤。", "穹旻當有輔，帷幄豈無籌。鳳態傷紅豔，鸞輿緩紫騮。", "樹名端正在，人欲夢魂休。讖語山旁鬼，塵銷隴畔丘。", "重來芳草恨，往事落花愁。五十年鴻業，東憑渭水流。"]'),
('yuding-1','尚書命題瓦硯','徐夤','唐','御定全唐诗','yuding','','[]','遠向端溪得，皆因郢匠成。鑿山青靄斷，琢石紫花輕。',120,'御定全唐詩/json/711.json','["遠向端溪得，皆因郢匠成。鑿山青靄斷，琢石紫花輕。", "散墨松香起，濡毫藻句清。入台知價重，著匣恐塵生。", "守黑還全器，臨池早著名。春闈攜就處，軍幕載將行。", "不獨雄文陣，兼能助筆耕。莫嫌涓滴潤，深染古今情。", "洗處無瑕玷，添時識滿盈。蘭亭如見用，敲戛有金聲。"]'),
('yuding-2','東風解凍省試','徐夤','唐','御定全唐诗','yuding','','[]','暖氣飄蘋末，凍痕銷水中。扇冰初覺泮，吹海旋成空。',72,'御定全唐詩/json/711.json','["暖氣飄蘋末，凍痕銷水中。扇冰初覺泮，吹海旋成空。", "入律三春照，朝宗萬里通。岸分天影闊，色照日光融。", "波起輕搖綠，鱗遊乍躍紅。殷勤排弱羽，飛翥趁和風。"]'),
('yuding-3','和僕射二十四丈牡丹八韻','徐夤','唐','御定全唐诗','yuding','','[]','帝王城裏看，無故亦無新。忍摘都緣借，移栽未有因。',96,'御定全唐詩/json/711.json','["帝王城裏看，無故亦無新。忍摘都緣借，移栽未有因。", "光陰嫌太促，開落一何頻。羞殺登牆女，饒將解佩人。", "蕊堪靈鳳啄，香許白龍親。素練籠霞曉，紅妝帶臉春。", "莫辭終夕醉，易老少年身。買取歸天上，寧教逐世塵。"]'),
('yuding-4','釣絲竹','徐夤','唐','御定全唐诗','yuding','','[]','藋藋拂清流，堪維舴艋舟。野蟲懸作餌，溪月曲為鉤。',72,'御定全唐詩/json/711.json','["藋藋拂清流，堪維舴艋舟。野蟲懸作餌，溪月曲為鉤。", "雨潤搖階長，風吹繞指柔。若將諸樹比，還使綠楊羞。", "蠶婦非堯女，漁人是子猷。湖邊舊栽處，長映讀書樓。"]'),
('yuding-5','尚書會仙亭詠薔薇夤坐中聯四韻晚歸補緝所聯因成一篇','徐夤','唐','御定全唐诗','yuding','','[]','結綠根株翡翠莖，句芒中夜刺猩猩。景陽妝赴嚴鐘出，',88,'御定全唐詩/json/711.json','["結綠根株翡翠莖，句芒中夜刺猩猩。景陽妝赴嚴鐘出，", "風吹嫩帶香苞展，露灑啼思淚點輕。阿母蕊宮期索去，", "鬥日只憂燒密葉，映階疑欲讓雙旌。含煙散纈佳人惜，", "海棠若要分流品，秋菊春蘭兩恰平。"]'),
('yuding-6','和尚書詠泉山瀑布十二韻','徐夤','唐','御定全唐诗','yuding','','[]','名齊火浣溢山椒，誰把驚虹掛一條。天外倚來秋水刃，',96,'御定全唐詩/json/711.json','["名齊火浣溢山椒，誰把驚虹掛一條。天外倚來秋水刃，", "噴石似煙輕漠漠，濺崖如雨冷瀟瀟。水中蠶緒纏蒼壁，", "千尋練寫長年在，六出花開夏日消。急恐劃分青嶂骨，", "林際猿猱偏得飯，岸邊烏鵲擬為橋。赤城未到詩先寄，"]'),
('yuding-7','自詠十韻','徐夤','唐','御定全唐诗','yuding','','[]','只合滄洲釣與耕，忽依螢燭愧功成。未游宦路叨卑宦，',88,'御定全唐詩/json/711.json','["只合滄洲釣與耕，忽依螢燭愧功成。未游宦路叨卑宦，", "錢財儘是侯王惠，骨肉偕承裏巷榮。拙賦偏聞鐫印賣，", "寒益輕裯饒美寢，出乘車馬免徒行。粗支菽粟防饑歉，", "如今便死還甘分，莫更嫌他白髮生。"]'),
('yuding-8','鏡中覽懷','徐夤','唐','御定全唐诗','yuding','','[]','晨起梳頭忽自悲，鏡中親見數莖絲。',32,'御定全唐詩/json/711.json','["晨起梳頭忽自悲，鏡中親見數莖絲。", "從今休說龍泉劍，世上恩讎報已遲。"]'),
('yuding-9','楚國史','徐夤','唐','御定全唐诗','yuding','','[]','六國商於恨最多，良弓休綰劍休磨。',32,'御定全唐詩/json/711.json','["六國商於恨最多，良弓休綰劍休磨。", "君王不剪如簧舌，再得張儀欲奈何。"]'),
('yuding-10','張儀','徐夤','唐','御定全唐诗','yuding','','[]','荊楚南來又北歸，分明舌在不應違。',32,'御定全唐詩/json/711.json','["荊楚南來又北歸，分明舌在不應違。", "懷王本是無心者，籠得蒼蠅卻放飛。"]'),
('yuding-11','薔薇','徐夤','唐','御定全唐诗','yuding','','[]','朝露灑時如濯錦，晚風飄處似遺鈿。',32,'御定全唐詩/json/711.json','["朝露灑時如濯錦，晚風飄處似遺鈿。", "重門剩著黃金鎖，莫被飛瓊摘上天。"]'),
('yuding-12','大夫松','徐夤','唐','御定全唐诗','yuding','','[]','五樹旌封許歲寒，挽柯攀葉也無端。',32,'御定全唐詩/json/711.json','["五樹旌封許歲寒，挽柯攀葉也無端。", "爭如澗底淩霜節，不受秦皇亂世官。"]'),
('yuding-13','杏園','徐夤','唐','御定全唐诗','yuding','','[]','杏苑簫聲好醉鄉，春風嘉宴更無雙。',32,'御定全唐詩/json/711.json','["杏苑簫聲好醉鄉，春風嘉宴更無雙。", "憑誰為謔穆天子，莫把瑤池並曲江。"]'),
('yuding-14','蕉葉','徐夤','唐','御定全唐诗','yuding','','[]','綠綺新裁織女機，擺風搖日影離披。',32,'御定全唐詩/json/711.json','["綠綺新裁織女機，擺風搖日影離披。", "只應青帝行春罷，閑倚東牆卓翠旗。"]'),
('yuding-15','路旁草','徐夤','唐','御定全唐诗','yuding','','[]','楚甸秦原萬里平，誰教根向路傍生。',32,'御定全唐詩/json/711.json','["楚甸秦原萬里平，誰教根向路傍生。", "輕蹄繡轂長相蹋，合是榮時不得榮。"]'),
('yuding-16','讀漢紀','徐夤','唐','御定全唐诗','yuding','','[]','布衣空手取中原，勁卒雄師不足論。',32,'御定全唐詩/json/711.json','["布衣空手取中原，勁卒雄師不足論。", "楚國八千秦百萬，豁開胸臆一時吞。"]'),
('yuding-17','李夫人二首','徐夤','唐','御定全唐诗','yuding','','[]','不望金輿到錦帷，人間樂極即須悲。',64,'御定全唐詩/json/711.json','["不望金輿到錦帷，人間樂極即須悲。", "若言要識愁中貌，也似君恩日日衰。", "招得香魂爵少翁，九華燈燭曉還空。", "漢王不及吳王樂，且與西施死處同。"]'),
('yuding-18','明妃','徐夤','唐','御定全唐诗','yuding','','[]','不用牽心恨畫工，帝家無策及邊戎。',32,'御定全唐詩/json/711.json','["不用牽心恨畫工，帝家無策及邊戎。", "香魂若得升明月，夜夜還應照漢宮。"]'),
('yuding-19','馬嵬','徐夤','唐','御定全唐诗','yuding','','[]','二百年來事遠聞，從龍誰解盡如雲。',32,'御定全唐詩/json/711.json','["二百年來事遠聞，從龍誰解盡如雲。", "張均兄弟皆何在，卻是楊妃死報君。"]'),
('yuding-20','依韻贈南安方處士五首','徐夤','唐','御定全唐诗','yuding','','[]','七貴五侯生肯退，利塵名網死當拋。',160,'御定全唐詩/json/711.json','["七貴五侯生肯退，利塵名網死當拋。", "黔婁寂寞嚴陵臥，借問何人與結交。", "休把羸蹄蹋霜雪，書成何處獻君王。", "嵩山好與浮丘約，三十六峰雲外鄉。", "百萬僧中不為僧，比君知道僅誰能。", "無家寄泊南安縣，六月門前也似冰。", "兩鬢當春卻似秋，僻居誇近野僧樓。", "落花明月皆臨水，明月不流花自流。", "晉楚忙忙起戰塵，龔黃門外有高人。", "一畦雲薤三株竹，席上先生未是貧。"]'),
('yuding-21','依韻答黃校書','徐夤','唐','御定全唐诗','yuding','','[]','慈恩雁塔參差榜，杏苑鶯花次第遊。',32,'御定全唐詩/json/711.json','["慈恩雁塔參差榜，杏苑鶯花次第遊。", "白日有愁猶可散，青山高臥況無愁。"]'),
('yuding-22','傷進士謝庭皓','徐夤','唐','御定全唐诗','yuding','','[]','獻書猶未達明君，何事先游岱嶽雲。',32,'御定全唐詩/json/711.json','["獻書猶未達明君，何事先游岱嶽雲。", "惟有春風護冤魄，與生青草蓋孤墳。"]'),
('yuding-23','聞司空侍郎訃音','徐夤','唐','御定全唐诗','yuding','','[]','園綺生雖逢漢室，巢由死不謁堯階。',32,'御定全唐詩/json/711.json','["園綺生雖逢漢室，巢由死不謁堯階。", "夫君歿去何人葬，合取夷齊隱處埋。"]'),
('yuding-24','偶題二首','徐夤','唐','御定全唐诗','yuding','','[]','買骨須求騏驥骨，愛毛宜采鳳凰毛。',64,'御定全唐詩/json/711.json','["買骨須求騏驥骨，愛毛宜采鳳凰毛。", "駑駘燕雀堪何用，仍向人前價例高。", "賦就長安振大名，斬蛇功與樂天爭。", "歸來延壽溪頭坐，終日無人問一聲。"]'),
('yuding-25','猿','徐夤','唐','御定全唐诗','yuding','','[]','宿有喬林飲有溪，生來蹤跡遠塵泥。',32,'御定全唐詩/json/711.json','["宿有喬林飲有溪，生來蹤跡遠塵泥。", "不知心更愁何事，每向深山夜夜啼。"]'),
('yuding-26','追和賈浪仙古鏡','徐夤','唐','御定全唐诗','yuding','','[]','誰開黃帝橋山塚，明月飛光出九泉。',32,'御定全唐詩/json/711.json','["誰開黃帝橋山塚，明月飛光出九泉。", "狼藉蘚痕磨不盡，黑雲殘點汙秋天。"]'),
('yuding-27','蝴蝶三首','徐夤','唐','御定全唐诗','yuding','','[]','不並難飛繭裏蛾，有花芳處定經過。',96,'御定全唐詩/json/711.json','["不並難飛繭裏蛾，有花芳處定經過。", "天風相送輕飄去，卻笑蜘蛛謾織羅。", "苒苒雙雙拂畫欄，佳人偷眼再三看。", "莫欺翼短飛長近，試就花間撲已難。", "栩栩無因系得他，野園荒徑一何多。", "不聞絲竹誰教舞，應仗流鶯為唱歌。"]'),
('yuding-28','新刺襪','徐夤','唐','御定全唐诗','yuding','','[]','素手春溪罷浣紗，巧裁明月半彎斜。',32,'御定全唐詩/json/711.json','["素手春溪罷浣紗，巧裁明月半彎斜。", "齊宮合贈東昏寵，好步黃金菡萏花。"]'),
('yuding-29','寄華山司空侍郎','徐夤','唐','御定全唐诗','yuding','','[]','山掌林中第一人，鶴書時或問眠雲。',32,'御定全唐詩/json/711.json','["山掌林中第一人，鶴書時或問眠雲。", "莫言疏野全無事，明月清風肯放君。"]'),
('yuding-30','初夏戲題','徐夤','唐','御定全唐诗','yuding','','[]','長養熏風拂曉吹，漸開荷芰落薔薇。',32,'御定全唐詩/json/711.json','["長養熏風拂曉吹，漸開荷芰落薔薇。", "青蟲也學莊周夢，化作南園蛺蝶飛。"]'),
('yuding-0','客舍寓懷','錢珝','唐','御定全唐诗','yuding','','[]','灑灑灘聲晚霽時，客亭風袖半披垂。野雲行止誰相待，',40,'御定全唐詩/json/712.json','["灑灑灘聲晚霽時，客亭風袖半披垂。野雲行止誰相待，", "牽情景物潛惆悵，忽似傷春遠別離。"]'),
('yuding-1','送王郎中','錢珝','唐','御定全唐诗','yuding','','[]','惜別遠相送，卻成惆悵多。獨歸回首處，爭那暮山何。',24,'御定全唐詩/json/712.json','["惜別遠相送，卻成惆悵多。獨歸回首處，爭那暮山何。"]'),
('yuding-2','江行無題一百首','錢珝','唐','御定全唐诗','yuding','','[]','傾酒向漣漪，乘流欲去時。寸心同尺璧，投此報馮夷。',576,'御定全唐詩/json/712.json','["傾酒向漣漪，乘流欲去時。寸心同尺璧，投此報馮夷。", "江曲全縈楚，雲飛半自秦。峴山回首望，如別故鄉人。", "浦煙含夜色，冷日轉秋旻。自有沈碑在，清光不照人。", "楚岸雲空合，楚城人不來。只今誰善舞，莫恨廢章台。", "行背青山郭，吟當白露秋。風流無屈宋，空詠古荊州。", "晚來漁父喜，網重欲收遲。恐有長江使，金錢願贖龜。", "去指龍沙路，徒懸象闕心。夜涼無遠夢，不為偶聞砧。", "霧雲疏有葉，雨浪細無花。穩放扁舟去，江天自有涯。", "好日當秋半，層波動旅腸。已行千裏外，誰與共秋光。", "潤色非東裏，官曹更建章。宦遊難自定，來喚棹船郎。", "夜江清未曉，徒惜月光沉。不是因行樂，堪傷老大心。", "翳日多喬木，維舟取束薪。靜聽江叟語，儘是厭兵人。", "箭漏日初短，汀煙草未衰。雨餘雖更綠，不是采蘋時。", "山雨夜來漲，喜魚跳滿江。岸沙平欲盡，垂蓼入船窗。", "渚邊新雁下，舟上獨淒涼。俱是南來客，憐君綴一行。", "雲密連江暗，風斜著物鳴。一杯真戰將，笑爾作愁兵。", "柳拂斜開路，籬邊數戶村。可能還有意，不掩向江門。", "不識相如渴，徒吟子美詩。江清惟獨看，心外更誰知。", "牽路沿江狹，沙崩岸不平。盡知行處險，誰肯載時輕。", "憔悴異靈均，非讒作逐臣。如逢漁父問，未是獨醒人。", "水含秋夜靜，雲帶夕陽高。詩癖非吾病，何妨吮短豪。", "帶舟維古岸，還似阻西陵。箕伯無多怒，回頭詎不能。", "秋雲久無雨，江燕社猶飛。卻笑舟中客，今年未得歸。", "帆翅初張處，雲鵬怒翼同。莫愁千里路，自有到來風。"]'),
('yuding-3','春恨三首','錢珝','唐','御定全唐诗','yuding','','[]','負罪將軍在北朝，秦淮芳草綠迢迢。',96,'御定全唐詩/json/712.json','["負罪將軍在北朝，秦淮芳草綠迢迢。", "高臺愛妾魂銷盡，始得丘遲為一招。", "久戍臨洮報未歸，篋香銷盡別時衣。", "身輕願比蘭階蝶，萬里還尋塞草飛。", "永巷頻聞小苑遊，舊恩如淚亦難收。", "君前願報新顏色，團扇須防白露秋。"]'),
('yuding-4','蜀國偶題','錢珝','唐','御定全唐诗','yuding','','[]','忽憶明皇西幸時，暗傷潛恨竟誰知。',32,'御定全唐詩/json/712.json','["忽憶明皇西幸時，暗傷潛恨竟誰知。", "佩蘭應語宮臣道，莫向金盤進荔枝。"]'),
('yuding-5','未展芭蕉','錢珝','唐','御定全唐诗','yuding','','[]','冷燭無煙綠蠟幹，芳心猶卷怯春寒。',32,'御定全唐詩/json/712.json','["冷燭無煙綠蠟幹，芳心猶卷怯春寒。", "一緘書劄藏何事，會被東風暗拆看。"]'),
('yuding-6','同程九早入中書','錢珝','唐','御定全唐诗','yuding','','[]','漢家賢相重英奇，蟠木何材也見知。不意雲霄能自致，',40,'御定全唐詩/json/712.json','["漢家賢相重英奇，蟠木何材也見知。不意雲霄能自致，", "獨慚皇鑒明如日，未厭春光向玉墀。"]'),
('yuding-0','陳情獻中丞','喻坦之','唐','御定全唐诗','yuding','','[]','孤拙竟何營，徒希折桂名。始終誰肯薦，得失自難明。',144,'御定全唐詩/json/713.json','["孤拙竟何營，徒希折桂名。始終誰肯薦，得失自難明。", "貢乏雄文獻，歸無瘠土耕。滄江長髮夢，紫陌久慚行。", "意縱求知切，才惟懼鑒精。五言非琢玉，十載看遷鶯。", "取進心甘鈍，傷嗟骨每驚。塵襟痕積淚，客鬢白新莖。", "顧盼身堪教，吹噓羽覺生。依門情轉切，荷德力須傾。", "獎善猶憐貢，垂恩必不輕。從茲便提挈，雲路自生榮。"]'),
('yuding-1','長安雪後','喻坦之','唐','御定全唐诗','yuding','','[]','碧落雲收盡，天涯雪霽時。草開當井地，樹折帶巢枝。',96,'御定全唐詩/json/713.json','["碧落雲收盡，天涯雪霽時。草開當井地，樹折帶巢枝。", "野渡滋寒麥，高泉漲禁池。遙分丹闕出，迥對上林宜。", "宿片攀簷取，凝花就砌窺。氣淩禽翅束，凍入馬蹄危。", "北想連沙漠，南思極海涯。冷光兼素彩，向暮朔風吹。"]'),
('yuding-2','送友人游東川','喻坦之','唐','御定全唐诗','yuding','','[]','食盡須分散，將行幾願留。春兼三月閏，人擬半年遊。',48,'御定全唐詩/json/713.json','["食盡須分散，將行幾願留。春兼三月閏，人擬半年遊。", "風俗同吳地，山川擁梓州。思君登棧道，猿嘯始應愁。"]'),
('yuding-3','題樟亭驛樓','喻坦之','唐','御定全唐诗','yuding','','[]','危檻倚山城，風帆檻外行。日生滄海赤，潮落浙江清。',48,'御定全唐詩/json/713.json','["危檻倚山城，風帆檻外行。日生滄海赤，潮落浙江清。", "秋晚遙峰出，沙幹細草平。西陵煙樹色，長見伍員情。"]'),
('yuding-4','大樑送友人東游','喻坦之','唐','御定全唐诗','yuding','','[]','自古東西路，舟車此地分。河聲梁苑夜，草色楚田曛。',48,'御定全唐詩/json/713.json','["自古東西路，舟車此地分。河聲梁苑夜，草色楚田曛。", "雁已多南去，蟬猶在此聞。聖朝無諫獵，何計謁明君。"]'),
('yuding-5','送友人游蜀','喻坦之','唐','御定全唐诗','yuding','','[]','為儒早得名，為客不憂程。春盡離丹闕，花繁到錦城。',48,'御定全唐詩/json/713.json','["為儒早得名，為客不憂程。春盡離丹闕，花繁到錦城。", "雪消巴水漲，日上劍關明。預想回來樹，秋蟬已數聲。"]'),
('yuding-6','留別友人書齋','喻坦之','唐','御定全唐诗','yuding','','[]','相見不相睽，一留日已西。軒涼庭木大，巷僻鳥巢低。',48,'御定全唐詩/json/713.json','["相見不相睽，一留日已西。軒涼庭木大，巷僻鳥巢低。", "背俗修琴譜，思家話藥畦。卜鄰期太華，同上上方梯。"]'),
('yuding-7','題耿處士林亭','喻坦之','唐','御定全唐诗','yuding','','[]','身向閑中老，生涯本豁然。草堂山水下，漁艇鳥花邊。',48,'御定全唐詩/json/713.json','["身向閑中老，生涯本豁然。草堂山水下，漁艇鳥花邊。", "窺井猿兼鹿，啼林鳥雜蟬。何時人事了，依此亦高眠。"]'),
('yuding-8','商于逢友人','喻坦之','唐','御定全唐诗','yuding','','[]','行役何時了，年年骨肉分。春風來漢棹，雪路入商雲。',48,'御定全唐詩/json/713.json','["行役何時了，年年骨肉分。春風來漢棹，雪路入商雲。", "水險溪難定，林寒鳥異群。相逢聊坐石，啼狖語中聞。"]'),
('yuding-9','灞上逢故人','喻坦之','唐','御定全唐诗','yuding','','[]','花落杏園枝，驅車問路岐。人情誰可會，身事自堪疑。',48,'御定全唐詩/json/713.json','["花落杏園枝，驅車問路岐。人情誰可會，身事自堪疑。", "岳雨狂雷送，溪槎漲水吹。家山如此景，幾處不相隨。"]'),
('yuding-10','發浙江','喻坦之','唐','御定全唐诗','yuding','','[]','島嶼遍含煙，煙中濟大川。山城猶轉漏，沙浦已搖船。',48,'御定全唐詩/json/713.json','["島嶼遍含煙，煙中濟大川。山城猶轉漏，沙浦已搖船。", "海曙霞浮日，江遙水合天。此時空闊思，翻想涉窮邊。"]'),
('yuding-11','晚泊盱眙','喻坦之','唐','御定全唐诗','yuding','','[]','廣葦夾深流，蕭蕭到海秋。宿船橫月浦，驚鳥繞霜洲。',48,'御定全唐詩/json/713.json','["廣葦夾深流，蕭蕭到海秋。宿船橫月浦，驚鳥繞霜洲。", "雲濕淮南樹，笳清泗水樓。徒懸鄉國思，羈跡尚東遊。"]'),
('yuding-12','歸江南','喻坦之','唐','御定全唐诗','yuding','','[]','歸日值江春，看花過楚津。草晴蟲網遍，沙曉浪痕新。',48,'御定全唐詩/json/713.json','["歸日值江春，看花過楚津。草晴蟲網遍，沙曉浪痕新。", "蓮葉初浮水，鷗雛已狎人。漁心慚未遂，空厭路岐塵。"]'),
('yuding-13','代北言懷','喻坦之','唐','御定全唐诗','yuding','','[]','困馬榆關北，那堪落景催。路行沙不絕，風與雪兼來。',48,'御定全唐詩/json/713.json','["困馬榆關北，那堪落景催。路行沙不絕，風與雪兼來。", "草得春猶白，鴻侵夏始回。行人莫遠入，戍角有餘哀。"]'),
('yuding-14','春遊曲江','喻坦之','唐','御定全唐诗','yuding','','[]','誤入杏花塵，晴江一看春。菰蒲雖似越，骨肉且非秦。',48,'御定全唐詩/json/713.json','["誤入杏花塵，晴江一看春。菰蒲雖似越，骨肉且非秦。", "曲岸藏翹鷺，垂楊拂躍鱗。徒憐汀草色，未是醉眠人。"]'),
('yuding-15','和范秘書宿省中作','喻坦之','唐','御定全唐诗','yuding','','[]','清省宜寒夜，仙才稱獨吟。鐘來宮轉漏，月過閣移陰。',48,'御定全唐詩/json/713.json','["清省宜寒夜，仙才稱獨吟。鐘來宮轉漏，月過閣移陰。", "鶴避燈前盡，芸高幄外深。想知因此興，暫動憶山心。"]'),
('yuding-16','寄華陰姚少府','喻坦之','唐','御定全唐诗','yuding','','[]','泰華當公署，為官興可知。硯和青靄凍，簾對白雲垂。',48,'御定全唐詩/json/713.json','["泰華當公署，為官興可知。硯和青靄凍，簾對白雲垂。", "峻掌光浮日，危蓮影入池。料于三考內，應惜德音移。"]'),
('yuding-17','晚泊富春寄友人','喻坦之','唐','御定全唐诗','yuding','','[]','江鐘寒夕微，江鳥望巢飛。木落山城出，潮生海棹歸。',48,'御定全唐詩/json/713.json','["江鐘寒夕微，江鳥望巢飛。木落山城出，潮生海棹歸。", "獨吟霜島月，誰寄雪天衣。此別三千里，關西信更稀。"]'),
('yuding-0','梅花','崔道融','唐','御定全唐诗','yuding','','[]','數萼初含雪，孤標畫本難。香中別有韻，清極不知寒。',48,'御定全唐詩/json/714.json','["數萼初含雪，孤標畫本難。香中別有韻，清極不知寒。", "橫笛和愁聽，斜枝倚病看。朔風如解意，容易莫摧殘。"]'),
('yuding-1','銅雀妓二首','崔道融','唐','御定全唐诗','yuding','','[]','嚴妝垂玉箸，妙舞對清風。無複君王顧，春來起漸慵。',48,'御定全唐詩/json/714.json','["嚴妝垂玉箸，妙舞對清風。無複君王顧，春來起漸慵。", "歌咽新翻曲，香銷舊賜衣。陵園春雨暗，不見六龍歸。"]'),
('yuding-2','春閨二首','崔道融','唐','御定全唐诗','yuding','','[]','寒食月明雨，落花香滿泥。佳人持錦字，無雁寄遼西。',48,'御定全唐詩/json/714.json','["寒食月明雨，落花香滿泥。佳人持錦字，無雁寄遼西。", "欲剪宜春字，春寒入剪刀。遼陽在何處，莫望寄征袍。"]'),
('yuding-3','訪僧不遇','崔道融','唐','御定全唐诗','yuding','','[]','尋僧已寂寞，林下鎖山房。松竹雖無語，牽衣借晚涼。',24,'御定全唐詩/json/714.json','["尋僧已寂寞，林下鎖山房。松竹雖無語，牽衣借晚涼。"]'),
('yuding-4','田上','崔道融','唐','御定全唐诗','yuding','','[]','雨足高田白，披蓑半夜耕。人牛力俱盡，東方殊未明。',24,'御定全唐詩/json/714.json','["雨足高田白，披蓑半夜耕。人牛力俱盡，東方殊未明。"]'),
('yuding-5','月夕','崔道融','唐','御定全唐诗','yuding','','[]','月上隨人意，人閑月更清。朱樓高百尺，不見到天明。',24,'御定全唐詩/json/714.json','["月上隨人意，人閑月更清。朱樓高百尺，不見到天明。"]'),
('yuding-6','槿花','崔道融','唐','御定全唐诗','yuding','','[]','槿花不見夕，一日一回新。東風吹桃李，須到明年春。',24,'御定全唐詩/json/714.json','["槿花不見夕，一日一回新。東風吹桃李，須到明年春。"]'),
('yuding-7','西施灘','崔道融','唐','御定全唐诗','yuding','','[]','宰嚭亡吳國，西施陷惡名。浣紗春水急，似有不平聲。',24,'御定全唐詩/json/714.json','["宰嚭亡吳國，西施陷惡名。浣紗春水急，似有不平聲。"]');
